-- Poems batch 379
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a6e8b7c6-a527-4567-95da-3d881ba5c379','宿嶽麓寺','李綱','宋','宋诗','song-poetry','','[]','嶽麓久不到，兵戈浩聯綿。',204,'全唐诗/poet.song.90000.json','["嶽麓久不到，兵戈浩聯綿。", "及玆再來遊，蓮宇猶依然。", "隔江望城郭，瓦礫稀人煙。", "十里無草木，髠盡羣山顛。", "老僧舊相識，爲語當時緣。", "胡騎中宵來，烈火光照天。", "殺人知幾何，浮屍蔽長川。", "巨盜繼憑據，姦貪爭弄權。", "誅求到骨髓，荆棘生荒田。", "兹山二三刹，危甚偶得全。", "至今齋厨室，不給粥與饘。", "步上法華堂，試酌白鶴泉。", "泉味儼如昔，松竹自碧鮮。", "端如君子操，不爲治亂愆。", "永夜宿虛堂，慷慨不成眠。", "安得有志士，王道還平平。", "太平復舊觀，山林寄餘年。"]'),
('5ab8ae8c-6031-4cb6-beaa-da7ef594549e','初入潭州二首  其一','李綱','宋','宋诗','song-poetry','','[]','長沙自昔號繁雄，兵火連年一掃空。',64,'全唐诗/poet.song.90000.json','["長沙自昔號繁雄，兵火連年一掃空。", "猶有江湖資險固，恨無方略暢威風。", "旁通川陜關河遠，下視荆襄指掌中。", "聖主中興當自此，無因借箸感堯聦。"]'),
('cd3ca165-d769-4cb7-aff6-d1bc9233b94c','初入潭州二首  其二','李綱','宋','宋诗','song-poetry','','[]','昔年假道過長沙，煙雨濛濛十萬家。',64,'全唐诗/poet.song.90000.json','["昔年假道過長沙，煙雨濛濛十萬家。", "棟宇只今皆瓦礫，生靈多少委泥沙。", "寸心報國渾忘老，四路宣風静不譁。", "秪願吾皇假年月，直從襄漢定中華。"]'),
('71b8e58f-ba89-4d28-9405-c33388240be8','到長沙月餘即上章復丐宫祠以詩陳情寄呂丞相元直','李綱','宋','宋诗','song-poetry','','[]','衰病投閑不記年，誤恩暫到楚江邊。',64,'全唐诗/poet.song.90000.json','["衰病投閑不記年，誤恩暫到楚江邊。", "布宣威德銷羣盜，循撫疲癃理廢田。", "報國固将求尺寸，乞身又欲老林泉。", "歸歟晚節知無悔，賴有元台爲保全。"]'),
('ddcc6a9d-86c6-489e-800a-e21187a043ea','余行次衡陽彈壓曹成七萬餘人出湖南境移師衡山降步諒二萬衆既入長沙次日即遣師降王進三千人於湘鄉縣七星寨復破王俊三千餘人於邵州其餘羣盜以次討定凡五萬餘選擇精銳得萬二千人分隸諸将境內遂安流移歸業上章復丐宫祠未報間聞有旨廢宣撫司及以言者罷去有感二首  其一','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','起廢無因許退藏，報恩欲效短中長。',64,'全唐诗/poet.song.90000.json','["起廢無因許退藏，報恩欲效短中長。", "固知吉甫無張仲，猶冀文侯知樂羊。", "破賊功名嗟寂寞，吞燕志氣已淒涼。", "春鴻秋鷰空來往，昭氏成虧可兩忘。"]'),
('98585fb8-1d5f-4291-9034-78db0dd3ebca','余行次衡陽彈壓曹成七萬餘人出湖南境移師衡山降步諒二萬衆既入長沙次日即遣師降王進三千人於湘鄉縣七星寨復破王俊三千餘人於邵州其餘羣盜以次討定凡五萬餘選擇精銳得萬二千人分隸諸将境內遂安流移歸業上章復丐宫祠未報間聞有旨廢宣撫司及以言者罷去有感二首  其二','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','大将呼來若小兒，片言罷去復何疑。',64,'全唐诗/poet.song.90000.json','["大将呼來若小兒，片言罷去復何疑。", "才如頗牧猶遭譖，功似韓彭未免危。", "往事幾番萋菲織，孤忠惟賴聖明知。", "歸歟久得山林趣，丹荔青蕉正是時。"]'),
('40e390b8-8b12-4026-831a-72c72386d9e2','長沙有長江重湖之險而無戰艦水軍余得唐嗣曹王臯遺制創造戰艦數十艘上下三層挾以車輪鼓蹈而前駚於陣馬募水軍三千人日夕教習以二月十八日臨清湘門按閲旌旗戈甲一新觀者如堵成五絕句以誌之  其一','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','車船新製得前規，鼓蹈雙輪勢似飛。',32,'全唐诗/poet.song.90000.json','["車船新製得前規，鼓蹈雙輪勢似飛。", "創物從來因智者，世間何事不由機。"]'),
('f8814720-4172-459b-8cfb-08a172e5ba5d','長沙有長江重湖之險而無戰艦水軍余得唐嗣曹王臯遺制創造戰艦數十艘上下三層挾以車輪鼓蹈而前駚於陣馬募水軍三千人日夕教習以二月十八日臨清湘門按閲旌旗戈甲一新觀者如堵成五絕句以誌之  其二','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','戰艦初成閲水軍，旌旗戈甲照湘濱。',32,'全唐诗/poet.song.90000.json','["戰艦初成閲水軍，旌旗戈甲照湘濱。", "渾人未識舟師制，歎息工夫若鬼神。"]'),
('20dd7c41-89f2-44ee-874f-e99af97ed679','長沙有長江重湖之險而無戰艦水軍余得唐嗣曹王臯遺制創造戰艦數十艘上下三層挾以車輪鼓蹈而前駚於陣馬募水軍三千人日夕教習以二月十八日臨清湘門按閲旌旗戈甲一新觀者如堵成五絕句以誌之  其三','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江巨浸雖天設，控制隄防本在人。',32,'全唐诗/poet.song.90000.json','["長江巨浸雖天設，控制隄防本在人。", "暇日不爲堅守計，臨危何以扼通津。"]'),
('710b2653-c49f-49b8-8364-95a3d8d90493','長沙有長江重湖之險而無戰艦水軍余得唐嗣曹王臯遺制創造戰艦數十艘上下三層挾以車輪鼓蹈而前駚於陣馬募水軍三千人日夕教習以二月十八日臨清湘門按閲旌旗戈甲一新觀者如堵成五絕句以誌之  其四','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','曹瞞百萬瞰江濱，誰遣孫郎會解紛。',32,'全唐诗/poet.song.90000.json','["曹瞞百萬瞰江濱，誰遣孫郎會解紛。", "滿眼旌旜風浪裏，景升方覺是雞豚。"]'),
('5ebd4537-a9b5-48a0-b29e-dee603acf7d0','長沙有長江重湖之險而無戰艦水軍余得唐嗣曹王臯遺制創造戰艦數十艘上下三層挾以車輪鼓蹈而前駚於陣馬募水軍三千人日夕教習以二月十八日臨清湘門按閲旌旗戈甲一新觀者如堵成五絕句以誌之  其五','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','劉裕當年西入關，樓船浮渭取長安。',32,'全唐诗/poet.song.90000.json','["劉裕當年西入關，樓船浮渭取長安。", "不施艫櫂争先進，坐使秦人破膽看。"]'),
('23b2e4b7-1540-4a3e-a52c-a8f9123cc254','初去長沙有感','李綱','宋','宋诗','song-poetry','','[]','恭承嘉惠半年餘，千里宣風愧術疏。',64,'全唐诗/poet.song.90000.json','["恭承嘉惠半年餘，千里宣風愧術疏。", "豈有恩威思将士，漫勞稚耋擁輪輿。", "魚歸江海身方適，鳥出樊籠意已舒。", "多謝吏民相眷戀，使君此去欲懸車。"]'),
('59c25947-3b60-4988-8e55-8948e5449a8a','自長沙至醴陵田皆墾闢有築室而居者','李綱','宋','宋诗','song-poetry','','[]','年來盜賊若冰銷，襁負歸民滿四郊。',64,'全唐诗/poet.song.90000.json','["年來盜賊若冰銷，襁負歸民滿四郊。", "烟雨一犁初破土，江村環堵且誅茅。", "瘡痍不擾生新肉，燕雀無虞返舊巢。", "安集勤斯徒自歎，勿令虎兕更咆哮。"]'),
('4434abb9-2183-43e9-b290-99c0f6cf5c0b','春暮江南道中','李綱','宋','宋诗','song-poetry','','[]','江上風光爛不收，一年春物又将休。',64,'全唐诗/poet.song.90000.json','["江上風光爛不收，一年春物又将休。", "鳴鳩乳燕自相得，飛絮落花如許愁。", "目極關河天杳杳，身歸閩粤興悠悠。", "往來踏遍江南土，已約幽人老一丘。"]'),
('8e7b4d19-e5bb-41ea-a0a4-30cefbd1a338','宿疏山戲成一絕','李綱','宋','宋诗','song-poetry','','[]','疏山緣熟豈無由，暫到人人識故侯。',32,'全唐诗/poet.song.90000.json','["疏山緣熟豈無由，暫到人人識故侯。", "臨别慇勤語禪子，秪來託宿不來遊。"]'),
('d4477cd6-0f3f-4219-9ffa-0e11a3fec545','道武夷沖祐觀壁間讀翁士特郎中留題追懷感愴二首  其一','李綱','宋','宋诗','song-poetry','','[]','昔年曾謁武夷君，先遣瑶山入夢魂。',64,'全唐诗/poet.song.90000.json','["昔年曾謁武夷君，先遣瑶山入夢魂。", "舊事追尋如電激，此身來往任雲奔。", "羣峰縹緲淩空翠，一水縈紆带雨渾。", "願向明時乞骸骨，誅茅深隱洞中門。"]'),
('15983834-2e5a-4970-8bdd-84ef495f0f7f','道武夷沖祐觀壁間讀翁士特郎中留題追懷感愴二首  其二','李綱','宋','宋诗','song-poetry','','[]','昔年曾約武夷孫，仙賞心違莫共論。',64,'全唐诗/poet.song.90000.json','["昔年曾約武夷孫，仙賞心違莫共論。", "地下修文君已遠，世間多難我猶存。", "題詩屋壁事如昨，灑涕烟霞聲爲吞。", "英爽故山應未冺，試憑楚些與招魂。"]'),
('6e4083e6-a1ec-4d0f-ad59-e52f7f8c749b','自水口泛舟如長樂','李綱','宋','宋诗','song-poetry','','[]','行盡青山泛碧溪，湖平波穏畫船移。',64,'全唐诗/poet.song.90000.json','["行盡青山泛碧溪，湖平波穏畫船移。", "春鴻秋燕豈人力，明月清風長我隨。", "萬事糾紛何日了，一生襟抱有誰知。", "落帆已到釣臺側，恰似南柯夢覺時。"]'),
('c6e83c4a-cdf9-4212-b15e-d35c1ed082be','自天寧遷居城東報國寺','李綱','宋','宋诗','song-poetry','','[]','多病維摩祗一牀，徙居又復借僧房。',64,'全唐诗/poet.song.90000.json','["多病維摩祗一牀，徙居又復借僧房。", "荷花欲吐乍舒藥，荔子未丹先有香。", "皓月解尋朱户入，南風偏傍北窗凉。", "吾年半百行休矣，萬事悠悠皆可忘。"]'),
('a9338a36-ba48-4b12-bf4c-21ae94576d2f','颶風二絕句  其一','李綱','宋','宋诗','song-poetry','','[]','自從嶺海入閩中，乃始今朝識颶風。',32,'全唐诗/poet.song.90000.json','["自從嶺海入閩中，乃始今朝識颶風。", "南極只愁天柱折，蘭臺休更論雌雄。"]'),
('cde82dde-1cb1-4a2e-8cef-8480b136050a','颶風二絕句  其二','李綱','宋','宋诗','song-poetry','','[]','雲氣飄揚萬馬馳，占風先有土人知。',32,'全唐诗/poet.song.90000.json','["雲氣飄揚萬馬馳，占風先有土人知。", "飛沙拔木渾閑事，祗怕山園損荔枝。"]'),
('ddff9d0b-00fd-4f50-9442-4a73997b3986','西軒小池荷花盛開與賓客酌酒其上以荷爲杯引滿徑醉','李綱','宋','宋诗','song-poetry','','[]','池上荷花一夜開，呼賓小酌共徘徊。',64,'全唐诗/poet.song.90000.json','["池上荷花一夜開，呼賓小酌共徘徊。", "試将曲柄黄金杓，注此虚心碧玉杯。", "風露暗隨香氣入，雲山盡向坐隅來。", "頽然徑醉君知否，不醉須爲造物咍。"]'),
('19fbfad4-eb74-447b-a306-2d1df853fd07','初食荔枝四絕句  其一','李綱','宋','宋诗','song-poetry','','[]','烟雨濛濛半暑時，輕紅旋摘自提攜。',32,'全唐诗/poet.song.90000.json','["烟雨濛濛半暑時，輕紅旋摘自提攜。", "不知誰是善知識，斷送歸家食荔枝。"]'),
('6540e379-e415-4d02-bd92-c0b9d9de7b30','初食荔枝四絕句  其二','李綱','宋','宋诗','song-poetry','','[]','平昔傳聞十八娘，豐肌秀骨有餘香。',32,'全唐诗/poet.song.90000.json','["平昔傳聞十八娘，豐肌秀骨有餘香。", "今朝親到芳叢下，應許幽人饜飫嘗。"]'),
('2ad0e5a6-e18c-4a7e-8e4d-84e1e8606e4e','初食荔枝四絕句  其三','李綱','宋','宋诗','song-poetry','','[]','堆盤盛喜珠璣滿，繞齒乍驚冰雪香。',32,'全唐诗/poet.song.90000.json','["堆盤盛喜珠璣滿，繞齒乍驚冰雪香。", "病酒相如正消渇，不妨時擘絳紬囊。"]'),
('4adda44c-ebc4-4970-bb5f-5836707994ee','初食荔枝四絕句  其四','李綱','宋','宋诗','song-poetry','','[]','南海何年貢荔枝，知音千古有楊妃。',32,'全唐诗/poet.song.90000.json','["南海何年貢荔枝，知音千古有楊妃。", "華清賜浴嬌無力，一騎紅塵初到時。"]'),
('953d4a51-76fb-4612-8c55-8a5c14c96428','詠懷十六韻','李綱','宋','宋诗','song-poetry','','[]','衰年萬事懶，此志有誰知。',192,'全唐诗/poet.song.90000.json','["衰年萬事懶，此志有誰知。", "偶爾出何意，泛然歸不遲。", "休爲鵩鳥賦，幸及荔枝時。", "水石日在眼，旌旜非所思。", "攜琴傍松徑，置酒俯蓮池。", "粲粲水花凈，蕭蕭風葉披。", "忘言聊隱几，得趣剩圍棋。", "天地慘将暮，風雲徒爾爲。", "物華去苒苒，草色自離離。", "密勿猿鶴侣，迢遥丘壑姿。", "親朋有情話，圖書皆吾師。", "掃室僅容膝，說詩真解頤。", "多慚鵷鷺羽，且詠鶺鴒詩。", "逸少誓獨苦，孔君休乃宜。", "平生滄海約，歲晚鹿門期。", "喜近清秋節，那爲宋玉悲。"]'),
('25ae1ac6-ad61-4bb2-a5d5-67da1260036d','夜月獨坐二絕句  其一','李綱','宋','宋诗','song-poetry','','[]','冰輪杳杳碾層空，獨坐凄然秋色中。',32,'全唐诗/poet.song.90000.json','["冰輪杳杳碾層空，獨坐凄然秋色中。", "深院無人共清景，静聞金井落梧桐。"]'),
('b4c4d936-3eef-460f-9c36-7b95c148f8a5','夜月獨坐二絕句  其二','李綱','宋','宋诗','song-poetry','','[]','廣寒宫殿碧霄傍，散下霏霏風露香。',32,'全唐诗/poet.song.90000.json','["廣寒宫殿碧霄傍，散下霏霏風露香。", "斟酌姮娥憐我老，故窺書幌照人牀。"]'),
('6e5b4dc7-75c3-4aaa-9bf8-98a9ca83c0d2','仲輔叔易招客同遊黄蘖還以詩軸相示爲賦二詩  其一','李綱','宋','宋诗','song-poetry','','[]','招提古黄蘖，環揖盡青山。',48,'全唐诗/poet.song.90000.json','["招提古黄蘖，環揖盡青山。", "我病未能往，子行真是閑。", "猿聲翠屏外，虹影碧潭間。", "好句聯珠璧，清新詎可攀。"]'),
('7e349260-1874-4a0e-8986-bb7a1bf8f42e','仲輔叔易招客同遊黄蘖還以詩軸相示爲賦二詩  其二','李綱','宋','宋诗','song-poetry','','[]','江外留禪老，佳名借此山。',48,'全唐诗/poet.song.90000.json','["江外留禪老，佳名借此山。", "忘心寧戀著，寓意爲幽閑。", "大士說法處，片雲生坐間。", "他年筋骨健，相約更躋攀。"]'),
('77346bf3-e449-49d3-9828-dbec343832dc','諸季招客遊東山置酒賦詩以病不果往次其韻','李綱','宋','宋诗','song-poetry','','[]','衰病年來百事闌，禪居環繞盡青山。',64,'全唐诗/poet.song.90000.json','["衰病年來百事闌，禪居環繞盡青山。", "登髙選勝從君樂，隱几忘言輸我閑。", "一枕清風銷永日，三杯濁酒發酡顔。", "雀羅可設從來事，東閣常開不是慳。"]'),
('de446500-b9ac-4c94-a323-a9997c2a6ceb','送李似之舍人歸連江舊隱二首  其一','李綱','宋','宋诗','song-poetry','','[]','羨君卜築粤江濱，去作林間適意人。',64,'全唐诗/poet.song.90000.json','["羨君卜築粤江濱，去作林間適意人。", "環揖溪山供勝賞，賸栽桃李占芳春。", "養生有主身長健，與物無心道轉親。", "一曲鑑湖歸賀老，可能分半乞比鄰。"]'),
('f0efdb71-6b35-4e82-9c91-eec3229902ab','送李似之舍人歸連江舊隱二首  其二','李綱','宋','宋诗','song-poetry','','[]','衰病修然寂寞濱，已将小隱約幽人。',64,'全唐诗/poet.song.90000.json','["衰病修然寂寞濱，已将小隱約幽人。", "眠雲嘯月有餘樂，問柳尋花無限春。", "争席樵漁真得計，會心魚鳥自相親。", "醉鄉况有閑田地，應許東臯更卜鄰。"]'),
('ec0f2109-af69-418f-93f5-ed13c1a6f31c','知宗端禮太尉出示曾信斯展鉢之作奉次元韻','李綱','宋','宋诗','song-poetry','','[]','忘情鼎食豈無因，應悟從來夢幻身。',64,'全唐诗/poet.song.90000.json','["忘情鼎食豈無因，應悟從來夢幻身。", "自愧毗耶多病客，阻陪蒲塞浄緣人。", "心源瑩澈了空法，舌本圓通透味塵。", "信厚振振流澤遠，嶷然一角見天麟。"]'),
('ef12fd77-4057-4371-be70-85db52c2e2c3','題唐氏所藏崔白畫雪中山水','李綱','宋','宋诗','song-poetry','','[]','我昔曾爲陽羨遊，正值雪花大如掌。',384,'全唐诗/poet.song.90000.json','["我昔曾爲陽羨遊，正值雪花大如掌。", "開門恍訝天地白，雲湧羣山入書幌。", "銅官遠並玉峰寒，罨畫暗流冰片響。", "千巖萬壑争出奇，應接髙低迷俯仰。", "十年不到浙江西，寤寐勝遊勞夢想。", "大梁崔白豈善幻，斷取山川移異壌。", "當時眼界無盡觀，都在一幅生綃上。", "南方炎熱瘴癘地，使我翛然毛骨爽。", "天光慘淡陰氣凝，片片飛花來蒼莽。", "毫端造化成六出，不比餘工得其髣。", "連峰合沓波濤翻，負雪崔嵬幾千丈。", "谷幽草木枝榦老，巖曲樓臺簷角敞。", "溪頭水落正石出，暮靄沉舟暗魚網。", "山牆野壁茅屋深，風颺青帘如五兩。", "買魚酌酒者誰子，應有幽人坐同饗。", "平生愛雪喜山水，對此乍覺神情怳。", "明窗静看久愈妍，似倩麻姑爲爬痒。", "一時名手真絕藝，妙處工夫誰與賞。", "生前裘馬頗蕭條，身後丹青空倜儻。", "惠崇聲價亦相先，滕薛未知當孰長。", "我家梁谿富溪山，雪裏寒光含萬象。", "每同子猷乘小艇，不數王恭披素氅。", "故山猿鶴會相思，感物興懷增勇往。", "時平事定歸去來，安得飛翰出塵鞅。"]'),
('28a6d727-9715-4206-ae15-93a899c692ce','題崔白畫江天雪景','李綱','宋','宋诗','song-poetry','','[]','朔風飛花落暮灘，瀟然幽致滿江干。',64,'全唐诗/poet.song.90000.json','["朔風飛花落暮灘，瀟然幽致滿江干。", "天邊白鷺輕輕下，風裏黄蘆索索乾。", "水淡沙平鸂鶒侣，雲深烟瞑鶺鴒寒。", "江南歲晚多風景，崔氏齊驅入筆端。"]'),
('4741fa84-baa6-4741-92b4-a4682135b6d8','春曉聞衆禽聲有感','李綱','宋','宋诗','song-poetry','','[]','春山蒼莽天欲明，枕上静聽春禽鳴。',256,'全唐诗/poet.song.90000.json','["春山蒼莽天欲明，枕上静聽春禽鳴。", "雛鶯初囀正調舌，姹婭乍聞三兩聲。", "不如歸去意良切，脫却潑袴何由行。", "愁人最是斷消息，姑惡更覺聲嬌獰。", "布穀催耕雨纔足，鵓鳩喚婦遠将晴。", "其餘不復識名字，雅音幽韻如簧笙。", "天公憐我太寂寞，故遣尤物怡吾情。", "鸞歌鳳舞未可見，候蟲時鳥聊嚶嚶。", "我生半世困漂泊，巧言讒謗飽所經。", "杜門却掃與世絕，欲窒兩牖忘雷霆。", "爾聲雖好太饒舌，逼耳頗似虚弦驚。", "就中提壺可人意，勸我沽酒花間傾。", "心懷百憂只欲睡，更願常醉不用醒。", "落花芳草正可藉，玉山自倒知誰令。", "烏啼鵲噪錯昏晝，燕雀啾唧環簷楹。", "從教一一恣嘲弄，吾方深入無何庭。"]'),
('4cc358c7-b040-4fcc-9cd2-bf0ea6ca828a','初見牡丹與諸季申伯小酌','李綱','宋','宋诗','song-poetry','','[]','牡丹家中州，尤者西邑洛。',144,'全唐诗/poet.song.90000.json','["牡丹家中州，尤者西邑洛。", "姚黄妃魏紫，餘品皆落寞。", "南方瘴癘地，寒暑互參錯。", "浪蘂與浮花，未春先已作。", "安能萃和氣，孕此木芍藥。", "今朝眼忽開，數朵到書閣。", "郁然蘭蕙芬，爛若雲霞爍。", "雖非千葉繁，香色亦不惡。", "花王苗裔遠，氣格尚宏廓。", "羣芳類凡禽，累百慚一鶚。", "把酒共對之，寄意良匪薄。", "無辭倒金樽，坐使花空落。"]'),
('5ad6027c-0108-4b04-83de-106794bf5704','小亭中作荼醾架遂試新花與客對飲','李綱','宋','宋诗','song-poetry','','[]','旋装新架對庭除，多謝春工與點酥。',64,'全唐诗/poet.song.90000.json','["旋装新架對庭除，多謝春工與點酥。", "雲葉扶疏成翠幄，玉花浮動滿龍須。", "招邀蜂蝶來書幌，燕集賓朋共酒壺。", "蔭釀欲教香入骨，醉中芳馥任歌呼。"]'),
('11ada1c2-3596-4696-99b4-79ff2056bec4','與叔易弈不勝賦著色山水詩一首','李綱','宋','宋诗','song-poetry','','[]','将軍思訓久爲土，龍眠道人亦已亡。',160,'全唐诗/poet.song.90000.json','["将軍思訓久爲土，龍眠道人亦已亡。", "誰将丹青寫山水，入我宴坐虚明窗。", "峰巒迴複吐雲氣，林木窈窕籠烟光。", "丹楓半落天雨霜，漁舟招招靜鳴榔。", "野橋巖寺遞隱見，浦花汀草何微茫。", "江邊落日尚返照，山頭正作金色黄。", "縈青繚白有餘態，却笑水墨無文章。", "畫工畫意不畫物，咫尺應須千里長。", "具區約略貫苕霅，赤岸髣髴通瀟湘。", "安得僊翁一葉艇，使我超忽窮江鄉。"]'),
('8892ee46-024c-4e4b-bc46-470464306502','有詔舉賢良方正作詩勉錢申伯使繼世科','李綱','宋','宋诗','song-poetry','','[]','中興天子開賢科，籠絡英俊歸網羅。',160,'全唐诗/poet.song.90000.json','["中興天子開賢科，籠絡英俊歸網羅。", "此科久廢習者少，應詔正恐人未多。", "君家三世五制舉，名與嵩華爭嵯峨。", "玉堂金馬皆故物，髙文大策垂不磨。", "今君落筆妙天下，該洽辯愽如懸河。", "胡不進卷對廷策，清芬遠紹揚其波。", "勒兵小試見家法，坐却勍敵揮雕戈。", "君如有意作大将，我願薦信同蕭何。", "功名晚達未爲老，志氣方壯靡有他。", "勉哉努力爲門户，慎勿自棄成蹉跎。"]'),
('435ebf57-b67c-4284-a056-a16fddae20ef','申伯見和拙句且示七言律詩兩章有未肯承當制科之意次韻報之  其一','李綱','宋','宋诗','song-poetry','','[]','才性如君豈易窺，斷碑摸索已無遺。',64,'全唐诗/poet.song.90000.json','["才性如君豈易窺，斷碑摸索已無遺。", "百家小說都成誦，一藏魔言總記持。", "東里多知工潤色，西施雖病善顰眉。", "制科便與承當取，正是逢場作戲時。"]'),
('5be495c1-0366-4b4d-ad3f-042ba32eaada','申伯見和拙句且示七言律詩兩章有未肯承當制科之意次韻報之  其二','李綱','宋','宋诗','song-poetry','','[]','聖朝制舉萃髙門，文采風流日益新。',64,'全唐诗/poet.song.90000.json','["聖朝制舉萃髙門，文采風流日益新。", "功德在民尤表表，子孫宜爾又詵詵。", "策名當學富彦國，避世休同梅子真。", "響答詩筒逼皇祖，讜言驚世更何人。"]'),
('5e0d9a60-3384-4508-b79a-0248c623627d','申伯和篇舉叔易自代叔詩復推申伯要之二子皆當由此科取重名於世恨吾資妄髙不得偕二子鳴躍其間復次前韻以兼勉之','李綱','宋','宋诗','song-poetry','','[]','古來豪傑收殊科，眇然鸞鳳亦可羅。',160,'全唐诗/poet.song.90000.json','["古來豪傑收殊科，眇然鸞鳳亦可羅。", "漢唐選舉最爲盛，我宋得士良已多。", "危言切論動天壤，陸離劍佩冠巍峨。", "至今凛凛有生氣，豈與草木同銷磨。", "自從罷舉樂軟美，馴致黠虜窺關河。", "翠華兩宫狩沙漠，疊鼓萬里翻鯨波。", "睿明感憤復舊制，欲起士氣寧兵戈。", "多材好學如二子，辭此其奈制舉何。", "青錢萬選當萬中，善射不復言公他。", "勉將忠讜助休運，嗟我老矣真蹉跎。"]'),
('151de912-d2d1-4c8c-a28d-07a26c5a1413','申伯叔易再和詩将有從吾言之意而仲輔作詩梗之以故未果復次前韻既助其決且戒勿與仲輔謀也','李綱','宋','宋诗','song-poetry','','[]','嗟予於世誠左科，屏居門可設雀羅。',160,'全唐诗/poet.song.90000.json','["嗟予於世誠左科，屏居門可設雀羅。", "弟昆相從有良友，静中所得亦復多。", "微言造理極壼奥，髙論蓋世驚嶫峨。", "含章懷美待時發，資質已妙猶鐫磨。", "明廷策士復古制，使我意氣如奔河。", "作詩勸自此途進，往駕巨舸凌長波。", "成功相期一戰霸，大敵禠魄皆投戈。", "篇章酬復未勇往，謙退将若斯文何。", "定從當以一語決，幸勿傍顧而言他。", "要須勿與少游議，政恐此志成蹉跎。"]'),
('f13efd6a-82f7-4671-948e-acf7803f6468','詩三往復而二子之意猶未決吾知之矣復次前韻以闢之','李綱','宋','宋诗','song-poetry','','[]','僊家佛氏各有科，所舉淨土與大羅。',160,'全唐诗/poet.song.90000.json','["僊家佛氏各有科，所舉淨土與大羅。", "癡人妄想到其處，堅守丹鼎翻貝多。", "胸中有此一念故，積慮便作層冰峨。", "超然了達無閡者，應物不磷誰憂磨。", "叔兮愛仙事爐竈，擬驂鸞鶴翔雲河。", "錢子貪佛爲藏轉，欲以一月分千波。", "乃将世故與陳說，坐使談笑尋干戈。", "願君捨遠聊自近，濟世不曰如之何。", "我方衰病臥江海，駭俗頗似哀駘他。", "驊騮見鞭行甚速，期子自策勿蹉跎。"]'),
('2a1b4493-fd78-426d-83b1-4292dbb07923','端禮知宗寵示水石六軸戲作此詩歸之','李綱','宋','宋诗','song-poetry','','[]','閩溪盤屈七百里，贑水湍瀉十八灘。',128,'全唐诗/poet.song.90000.json','["閩溪盤屈七百里，贑水湍瀉十八灘。", "何人作此極變態，使我當暑毛骨寒。", "小山屹立奔猛裏，飛浪洶動巉巖間。", "喧豗似有雷霆響，回薄乍疑霜雪翻。", "枯槎石上盡堅瘦，蒼波噴浸尺度慳。", "畫工不復畫舟檝，意謂絕險無敢干。", "豈知操舟若神者，出沒濤瀨心甚閑。", "崎嶇世路更巇惡，返視此畫平而安。"]'),
('e9908a3c-545b-4fda-a0de-bc68ef9c35f6','千葉碧桃二絕句  其一','李綱','宋','宋诗','song-poetry','','[]','春光欲暮碧桃開，烟露相和染玉腮。',32,'全唐诗/poet.song.90000.json','["春光欲暮碧桃開，烟露相和染玉腮。", "仙苑何人移得種，風光疑自茂陵來。"]'),
('16f0be9c-d273-4a84-8616-2f4d36f9eeef','千葉碧桃二絕句  其二','李綱','宋','宋诗','song-poetry','','[]','每恨桃花抵死紅，年年穠艷笑春風。',32,'全唐诗/poet.song.90000.json','["每恨桃花抵死紅，年年穠艷笑春風。", "誰知零落臙脂後，淺碧微開烟雨中。"]'),
('fb711d92-4d62-4554-98aa-a9a94c65df88','許崧老賦三友篇以遺東林珪禪師余嘗次韻和之未幾余被命宣撫荆廣崧老復以詩來曾未一歲間聞吳元中薨于柳崧老東歸薨于虔余方罷帥事屏居長樂珪禪師自江西見過閲篋中得崧老二詩相與讀之愴然因復追和其韻 次孫字韻古風','李綱','宋','宋诗','song-poetry','','[]','胡塵暗神州，寶玦悲王孫。',240,'全唐诗/poet.song.90000.json','["胡塵暗神州，寶玦悲王孫。", "六龍轉淮海，荆棘生中原。", "時危賴耆俊，引手開霧昏。", "廓清天宇間，復見咸池暾。", "跨海斬長鯨，驅石駕鼉黿。", "悼心失良策，至今聲尚吞。", "二公直以方，象在六二坤。", "英英鸞鵠姿，超然脫籠樊。", "才雄一世表，學貫萬象根。", "皇天不憗遺，三友獨我存。", "去歲適湖湘，戈甲照旗旛。", "龍城得吳書，心契久益敦。", "襄陵寓營道，詩句來清溫。", "回頭失良友，誰能詰其源。", "我老臥江海，病鶴栖荒園。", "娛心嶺白雲，濯足溪流渾。", "幽人幸見過，握手得晤言。", "從來心地法，半偈已覺繁。", "願磨習氣垢，坐覿出世尊。", "喟彼泉下人，何由復軒軒。"]'),
('712e98be-bd80-472d-b72a-cd6c448fc4bb','許崧老賦三友篇以遺東林珪禪師余嘗次韻和之未幾余被命宣撫荆廣崧老復以詩來曾未一歲間聞吳元中薨于柳崧老東歸薨于虔余方罷帥事屏居長樂珪禪師自江西見過閲篋中得崧老二詩相與讀之愴然因復追和其韻 次羣字韻長句','李綱','宋','宋诗','song-poetry','','[]','轉頭良友死生分，獨鶴如何不念羣。',64,'全唐诗/poet.song.90000.json','["轉頭良友死生分，獨鶴如何不念羣。", "慨想平生空灑涕，追吟佳句只看雲。", "隻雞墓隧違徐志，羣盜潢池尚楚氛。", "賴有幽人慰岑寂，此方教體在音聞。"]'),
('4eea4a3b-13c1-4457-b10e-4554e9e0b6be','絕句奉約珪禪師相過同食荔枝  其一','李綱','宋','宋诗','song-poetry','','[]','荔子新來已著花，千林行見爛朝霞。',32,'全唐诗/poet.song.90000.json','["荔子新來已著花，千林行見爛朝霞。", "幽人莫戀雪峰境，拄杖穿雲過我家。"]'),
('71bb3ce5-1c07-48d0-b767-18b73d4db9e7','絕句奉約珪禪師相過同食荔枝  其二','李綱','宋','宋诗','song-poetry','','[]','荔子丹兮滿翠嵐，能将法味發芳甘。',32,'全唐诗/poet.song.90000.json','["荔子丹兮滿翠嵐，能将法味發芳甘。", "舌根幸有圓通在，何惜南來與徧參。"]'),
('6c5db375-cca9-40a1-b2b0-15b4d815bea8','劉仲髙提刑見示喜雨佳作次韻和之奉呈全真安撫資政','李綱','宋','宋诗','song-poetry','','[]','精禱龍淵默感通，寸誠端可格蒼穹。',64,'全唐诗/poet.song.90000.json','["精禱龍淵默感通，寸誠端可格蒼穹。", "驅除旱暵千峰翠，灑濯焦枯百穀豐。", "可喜盍親尊酒渌，成霖未放海雲紅。", "清涼更覺山川勝，閉户空慚學寓公。"]'),
('32669ffb-3698-4a5a-bb5a-b7df573ff0c5','七月六日通夕大雨闔境告足豐年之慶枕上用前韻再賦兩篇呈全真諸公  其一','李綱','宋','宋诗','song-poetry','','[]','絳闕清都一念通，沛然甘澤瀉層穹。',64,'全唐诗/poet.song.90000.json','["絳闕清都一念通，沛然甘澤瀉層穹。", "天心會與人心合，國事尤須歲事豐。", "秋水陡添江上碧，朝陽却照棟間紅。", "精誠自可驅雷雨，安用區區致八公。"]'),
('aa4102ed-16dc-4f03-92fb-12c683396802','七月六日通夕大雨闔境告足豐年之慶枕上用前韻再賦兩篇呈全真諸公  其二','李綱','宋','宋诗','song-poetry','','[]','千里溝塍派脉通，挽回樂歲賴髙穹。',64,'全唐诗/poet.song.90000.json','["千里溝塍派脉通，挽回樂歲賴髙穹。", "風雷借助不勞力，粳稻有期成屢豐。", "枕上醉魂清夢想，枝頭嘉果濕猶紅。", "旅居又喜逢穰熟，地主端疑是鄭公。"]'),
('f55d37ac-e734-4a6f-995b-dbeb375158ea','奉寄李泰發端明','李綱','宋','宋诗','song-poetry','','[]','一别東吳不記年，飽經憂患各林泉。',64,'全唐诗/poet.song.90000.json','["一别東吳不記年，飽經憂患各林泉。", "知公置酒常髙會，顧我杜門惟熟眠。", "無分去爲湯餅客，有緣來作荔枝仙。", "越溪閩嶺無多地，步月看雲只黯然。"]'),
('dfe96f6f-efbc-4e11-ae4a-e088faf8ed5c','汪廷俊見示喜雨和篇次韻答之二首  其一','李綱','宋','宋诗','song-poetry','','[]','一氣潛升處處通，誠心初不間窿穹。',64,'全唐诗/poet.song.90000.json','["一氣潛升處處通，誠心初不間窿穹。", "乍欣草木回枯槁，更喜粢盛備潔豐。", "宿霧遊雲朝尚合，斷霞殘照晚偏紅。", "陽舒陰慘無遐邇，造物從來任至公。"]'),
('6827b88a-ade6-4021-aabc-1cb8044be5c5','汪廷俊見示喜雨和篇次韻答之二首  其二','李綱','宋','宋诗','song-poetry','','[]','憫旱遥将精意通，秋霖霶霈仰旻穹。',64,'全唐诗/poet.song.90000.json','["憫旱遥将精意通，秋霖霶霈仰旻穹。", "山川增煥家家好，黍稷方華物物豐。", "得句自應髭變白，舉觴何惜頰潮紅。", "他時倘會風雲便，肯倒長瓢學衛公。"]'),
('cc805791-0441-40b4-8c39-46737ef7aa0c','題劉仲髙提刑所藏文與可墨竹','李綱','宋','宋诗','song-poetry','','[]','蕭郎畫竹稱逼真，與可所作尤絕倫。',256,'全唐诗/poet.song.90000.json','["蕭郎畫竹稱逼真，與可所作尤絕倫。", "不将丹青借粉飾，直把寶墨傳精神。", "渭川萬箇在胸次，援毫戲掃如烟雲。", "眼前先見欲畫者，兔起鶻落氣益振。", "稚枯偃仰盡變態，筆力斡轉風霆春。", "平生知作幾千幅，得心應手老斵輪。", "當時誰是識畫者，謫仙東坡蓋其人。", "老坡亦善作此畫，意雖已到法未親。", "是中妙處不傳授，但得木石枯鱗皴。", "自從兵火喪亂後，錦囊玉軸隨埃塵。", "公於何處得此本，四枝墨色猶鮮新。", "風梢雨葉間濃淡，紛披屈折節脉勻。", "置之座右滌炎暑，颯颯更覺秋聲聞。", "子猷會見定絕倒，安用日事栽培勤。", "只今與可骨已朽，妙蹟散落此幸存。", "願公祕惜勿輕示，更築小堂名墨君。"]'),
('0469f881-6a21-4324-9c6f-cc1d9379489d','諸公復以喜雨詩來勉强再賦一篇見鄙意','李綱','宋','宋诗','song-poetry','','[]','聖君憂國物情通，良牧精祈動上穹。',64,'全唐诗/poet.song.90000.json','["聖君憂國物情通，良牧精祈動上穹。", "塞比干戈雖未定，江南禾稼自多豐。", "阿香推轂驚雷遠，玉女投壺笑電紅。", "幽贊中興萬靈集，願将人績屬羣公。"]'),
('e602037c-128a-4518-a296-bf864bae67e3','諸季邀德久申伯同遊鼓山靈源洞僕以病不果往賦詩見意','李綱','宋','宋诗','song-poetry','','[]','靈源韞秀異，傑出閩粤間。',240,'全唐诗/poet.song.90000.json','["靈源韞秀異，傑出閩粤間。", "神功謝鐫鑿，妙境森回環。", "曲磴下窈窕，髙巖上孱顔。", "松蘿互蔭翳，正暑生清寒。", "路轉人寂寂，泉飛澗潺潺。", "乘髙望雲海，天末波濤翻。", "偉哉宇宙中，有此氣象寛。", "諸子雅好遊，蠟屐履山樊。", "佳客來自遠，復共一日歡。", "而我抱衰疾，屏居方杜關。", "豈不樂山水，宴坐心不闌。", "神遊八極表，目寓無髦蠻。", "塊視衆嶽小，杯看五湖慳。", "矧兹几案物，安用勞躋攀。", "登臨務得雋，無乃見一斑。", "作詩調諸子，醉語不可刪。", "秋風動林壑，凍雨洗塵寰。", "新涼至萬里，濃翠浮千山。", "白雲出何心，飛鳥倦自還。", "興盡盍遄返，勝遊宜勿殫。"]'),
('25f6f4f9-bc32-413b-90ea-ddb7b64b2edc','讀莊子六絕句  其一','李綱','宋','宋诗','song-poetry','','[]','漆園仙吏已賓霄，浩蕩奇言久寂寥。',32,'全唐诗/poet.song.90000.json','["漆園仙吏已賓霄，浩蕩奇言久寂寥。", "鵬鷃何須迭相笑，斯遊安往不逍遥。"]'),
('4613c59d-19c3-4009-9793-3158f6890d7e','讀莊子六絕句  其二','李綱','宋','宋诗','song-poetry','','[]','世間物論最難齊，有萬初從一氣吹。',32,'全唐诗/poet.song.90000.json','["世間物論最難齊，有萬初從一氣吹。", "若會此心平等法，天淵元自絕髙卑。"]'),
('910f9f00-96b0-42e6-9a1b-bce2f504f2d4','讀莊子六絕句  其三','李綱','宋','宋诗','song-poetry','','[]','養生有主衛生經，神守全時豈廢形。',32,'全唐诗/poet.song.90000.json','["養生有主衛生經，神守全時豈廢形。", "遊刃有餘刀不挫，解牛須是學庖丁。"]'),
('7e7c4356-86f4-46ca-bc0c-382154ee8d3c','讀莊子六絕句  其四','李綱','宋','宋诗','song-poetry','','[]','濠上觀魚適意時，從容魚樂獨心知。',32,'全唐诗/poet.song.90000.json','["濠上觀魚適意時，從容魚樂獨心知。", "何須更問魚非我，能見魚遊復是誰。"]'),
('98ef4f78-953b-40e6-9bce-fa4caae82e84','讀莊子六絕句  其五','李綱','宋','宋诗','song-poetry','','[]','寧作泥塗曳尾龜，難堪芻豢廟中犧。',32,'全唐诗/poet.song.90000.json','["寧作泥塗曳尾龜，難堪芻豢廟中犧。", "從來一臂重天下，肯以此身輕用爲。"]'),
('3ff56629-830d-4802-9ef8-14d306799827','讀莊子六絕句  其六','李綱','宋','宋诗','song-poetry','','[]','詆欺儒墨每云云，芻狗詩書跡已陳。',32,'全唐诗/poet.song.90000.json','["詆欺儒墨每云云，芻狗詩書跡已陳。", "泯絕是非歸道妙，掃除糠粃見天真。"]'),
('ac8ed978-753f-4ec6-ba85-61f18177c66e','送劉仲髙提刑受代赴行朝','李綱','宋','宋诗','song-poetry','','[]','繡衣将命七閩中，攬轡褰幃邁古風。',96,'全唐诗/poet.song.90000.json','["繡衣将命七閩中，攬轡褰幃邁古風。", "懷抱坦然推厚德，平反多處剩陰功。", "却持漢節朝天陛，未許甌民借寇公。", "簪筆行趨青瑣闥，攜家去指水晶宫。", "風吹烟浪蓴鱸熟，日照霜林橘柚紅。", "若到東吳見知舊，爲言多病一衰翁。"]'),
('5b9b4c82-d06e-4081-b782-1c1046d70bda','送鄒德久還大柘舊隱三十韻','李綱','宋','宋诗','song-poetry','','[]','抱病臥雲海，杜關誰與遊。',288,'全唐诗/poet.song.90000.json','["抱病臥雲海，杜關誰與遊。", "鄒子惠過我，命駕無停輈。", "但思一會面，不願萬户侯。", "故人相許心，拔俗今焉儔。", "觸熱涉長道，始識甌閩州。", "叩門泉石邊，僮僕驚髭虬。", "怪我齒髪衰，志氣非昔侔。", "豈知數年來，患難如戈矛。", "收悲且歡欣，身健餘何求。", "情話豁懷抱，髙辭紹軻丘。", "遠尋雲間寺，屢泛江上舟。", "同擘荔枝紅，坐見菊花秋。", "告我欲遄返，歸袖風颼颼。", "投老不禁别，聊兹小淹留。", "置酒古道場，大白相獻酬。", "短日忽西匿，輕雲靄而浮。", "露下松桂枝，月轉西南樓。", "慇勤渭城唱，達旦增離愁。", "念子韞器業，學慱仕未優。", "至寶委路傍，誰能辨琳球。", "世事方多難，英俊宜旁搜。", "何人有髙識，薦此窮馬周。", "丈夫重氣槩，出處非身謀。", "巋然棟梁材，回首須萬牛。"]'),
('216f3150-9aff-46ee-824d-b72cce4251a0','送張柔直赴岳州','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','荆楚通南國，巴陵據上游。',192,'全唐诗/poet.song.90000.json','["荆楚通南國，巴陵據上游。", "江湖作襟带，民物會車舟。", "喪亂經多難，荒凉但一丘。", "髙臨洞庭野，無復岳陽樓。", "帝念蘇疲俗，恩頒起故侯。", "光華剖符竹，輯睦擁貔貅。", "魯肅規模在，陶公政績優。", "遠師前哲訓，力贊中興謀。", "羣盜何難縳，侵疆儻可收。", "往分千里寄，爲解九重憂。", "我已甘衰病，君方茂壮猷。", "三年共幽討，此日動離愁。", "世事經綸急，淵衷寤寐求。", "着鞭先祖逖，悟主繼千秋。", "閫外資奇畫，樽前失勝流。", "瀟湘有回鴈，莫遣信沉浮。"]'),
('843656ef-2733-46c6-b1a6-2ad6c6c6f820','庭中酴醾盛開二甥以詩來戲和其韻','李綱','宋','宋诗','song-poetry','','[]','栽培初不棄葑菲，桃李無言下自蹊。',224,'全唐诗/poet.song.90000.json','["栽培初不棄葑菲，桃李無言下自蹊。", "試營小圃供幽奇，野趣獨與閑相宜。", "邇來落葉子滿枝，新花璨發歸酴醾。", "濛濛烟雨濕冰姿，湯泉乍洗温柔肌。", "玉人胡爲在軒墀，態濃意遠芬蘭芝。", "月華萬里來清輝，照耀光彩通屏帷。", "青雲宛轉蟠素螭，髙架上與飛甍齊。", "客來花下同圍棋，對花不怕輸吟詩。", "帝鄉富貴未可幾，淵明之語真良規。", "一杯相屬慎勿辭，我方餔糟啜其醨。", "醉中不省今何時，胸次洞達元無疵。", "山林正好相娱嬉，朝廷漸有中興期。", "羲和鞭日不肯遲，海水清淺蓬萊池。", "飛花雪落白玉巵，起舞鶴氅風前披。"]'),
('8a874f5c-24f5-4e3b-b28b-9d5bd5acb89c','張甥賦碧桃次其韻','李綱','宋','宋诗','song-poetry','','[]','未許濃華獨占春，故将淺碧鬭清新。',64,'全唐诗/poet.song.90000.json','["未許濃華獨占春，故将淺碧鬭清新。", "冰肌綽約疑姑射，玉質丰容似太真。", "不與天香緣底事，秪應國色已無倫。", "慇勤池上親培植，從此芬芳冠七閩。"]'),
('a7579e6d-6f13-4c02-be01-76cd7a80dae5','送錢申伯如邵武','李綱','宋','宋诗','song-poetry','','[]','錢郎與世苦不諧，胸次徒抱經綸才。',192,'全唐诗/poet.song.90000.json','["錢郎與世苦不諧，胸次徒抱經綸才。", "行年五十猶未試，蟠蟄雖久愆風雷。", "掃除習氣趣空寂，華藏重重恣遊歷。", "世間幻妄此道真，未必亨通勝窮阨。", "我方臥病南海濱，喜君襟抱時相親。", "胡爲乘興有所適，使我悵望歸飛雲。", "兵戈格鬬何時息，田園将蕪歸未得。", "同是天涯流落人，此心炯炯君應識。", "閩山六月丹荔枝，火齊堆盤侑一巵。", "願言及此復過我，歲晚勿負滄海期。", "醉鄉我已成真隱，君亦逃禪學蘇晉。", "樂天不醉即談禪，此外悠悠真須忍。"]'),
('88e7c473-33f7-4187-a3d6-9b9c5651ca03','小圃初成秦楚材直閣有詩因次其韻二首  其一','李綱','宋','宋诗','song-poetry','','[]','僧坊暫寓白雲邊，古木荒溪濕暝烟。',64,'全唐诗/poet.song.90000.json','["僧坊暫寓白雲邊，古木荒溪濕暝烟。", "試葺池臺學愚谷，不妨風物似斜川。", "邀賓深愧裴公野，瀹茗空懷陸子泉。", "塵世悠悠盡虚幻，且将身健鬬尊前。"]'),
('146a32ee-93e9-41b5-8bb7-0fdeb6228619','小圃初成秦楚材直閣有詩因次其韻二首  其二','李綱','宋','宋诗','song-poetry','','[]','屏跡山林得放懷，檻花欄藥手親栽。',64,'全唐诗/poet.song.90000.json','["屏跡山林得放懷，檻花欄藥手親栽。", "會心魚鳥自相近，乘興朋遊時自來。", "半世乾忙嗟白髪，四方多難使心哀。", "巖隈水曲翛然處，老木輪囷愧不才。"]'),
('cf0d1a17-8e5d-4716-a051-7d6ce1b75c19','茅齋成乾元珪老以拄杖旄牛拂見遺成二絕句以報之  其一','李綱','宋','宋诗','song-poetry','','[]','横挑世界鴻毛舉，平打虚空冰片消。',32,'全唐诗/poet.song.90000.json','["横挑世界鴻毛舉，平打虚空冰片消。", "今日拈來居士手，穿雲渡水且逍遥。"]'),
('f7aab97e-c4f3-4352-bad1-1055868ee6b2','茅齋成乾元珪老以拄杖旄牛拂見遺成二絕句以報之  其二','李綱','宋','宋诗','song-poetry','','[]','不取非亷取不貪，玉装麈尾謾毿毿。',32,'全唐诗/poet.song.90000.json','["不取非亷取不貪，玉装麈尾謾毿毿。", "年來居士無言說，立起從教作麽參。"]'),
('529e8c95-e300-47b6-afab-da726f18256d','次韻李似宗見示小圃之作二首  其一','李綱','宋','宋诗','song-poetry','','[]','山林自與性相宜，卜築何須物物奇。',64,'全唐诗/poet.song.90000.json','["山林自與性相宜，卜築何須物物奇。", "旋剪荆榛開小徑，自移松菊趁佳時。", "雲生北嶺難持寄，月出東山有所思。", "歲晚龐翁更多病，攜家真赴鹿門期。"]'),
('240ba879-b7a7-4a11-871c-b701034a67af','次韻李似宗見示小圃之作二首  其二','李綱','宋','宋诗','song-poetry','','[]','竹影桐陰夏日長，水花晚色浄林塘。',64,'全唐诗/poet.song.90000.json','["竹影桐陰夏日長，水花晚色浄林塘。", "招邀風月成三友，邂逅賓朋共一觴。", "閑把琴書聊自樂，靜看蜂蝶爲誰忙。", "年來百念皆灰冷，願學螺川雲水鄉。"]'),
('d56e5828-f929-48a8-9eaf-0ba3954c9cda','十二詠 雙蓮閣','李綱','宋','宋诗','song-poetry','','[]','並蔕芙蓉出綠波，靚粧鸞鑑照雙娥。',32,'全唐诗/poet.song.90000.json','["並蔕芙蓉出綠波，靚粧鸞鑑照雙娥。", "風清月曉微開處，無那幽人獨見何。"]'),
('1403ec7a-1ef8-4037-ba12-958703f5f546','十二詠 夢室','李綱','宋','宋诗','song-poetry','','[]','誰把人間比夢間，本來夢覺兩閒閒。',32,'全唐诗/poet.song.90000.json','["誰把人間比夢間，本來夢覺兩閒閒。", "清風一枕北窗下，遊徧江南多少山。"]'),
('608259ac-c1b3-4c62-b9d7-daaca8307003','十二詠 藥圃','李綱','宋','宋诗','song-poetry','','[]','病翁餌藥欲扶衰，自斸霜根種種移。',32,'全唐诗/poet.song.90000.json','["病翁餌藥欲扶衰，自斸霜根種種移。", "端爲出山成小草，白雲深處飬青芝。"]'),
('950bbc68-b608-43e1-bd9a-f2a65a78bc38','十二詠 橘亭','李綱','宋','宋诗','song-poetry','','[]','雪避繁華葉勝雲，野亭秋後露苞新。',32,'全唐诗/poet.song.90000.json','["雪避繁華葉勝雲，野亭秋後露苞新。", "橘中不减啇山樂，留與昂藏四老人。"]'),
('98a8d01e-698d-4cd2-a4be-0137dfdec8e8','十二詠 竹亭','李綱','宋','宋诗','song-poetry','','[]','檻外新篁玉笋抽，和烟滴露碧先浮。',32,'全唐诗/poet.song.90000.json','["檻外新篁玉笋抽，和烟滴露碧先浮。", "此君一日難相捨，疑我前身是子猷。"]'),
('8fb50fb5-634f-48bd-8703-582f27774c8f','十二詠 荔枝亭','李綱','宋','宋诗','song-poetry','','[]','平生最賞荔枝名，手植芳根傍草亭。',32,'全唐诗/poet.song.90000.json','["平生最賞荔枝名，手植芳根傍草亭。", "嘉木亦知人意重，著花不待一周星。"]'),
('4a8df84b-36e4-4788-b55b-f8627dbe2254','十二詠 桂亭','李綱','宋','宋诗','song-poetry','','[]','團團雙桂拂茅齋，虚幌疏櫺盡日開。',32,'全唐诗/poet.song.90000.json','["團團雙桂拂茅齋，虚幌疏櫺盡日開。", "會待秋髙風露下，清香飄泛月中來。"]'),
('75d9c97d-2ca8-4def-baf1-a262db6b889a','十二詠 蘭室','李綱','宋','宋诗','song-poetry','','[]','盡道幽蘭是國香，沐湯紉佩慕芬芳。',32,'全唐诗/poet.song.90000.json','["盡道幽蘭是國香，沐湯紉佩慕芬芳。", "何如邂逅同心士，一吐胸中氣味長。"]'),
('a18a4c5e-0ace-4478-8b3d-15fc24c06f89','十二詠 花塢','李綱','宋','宋诗','song-poetry','','[]','收拾羣英賴化工，嫣然紅紫自成叢。',32,'全唐诗/poet.song.90000.json','["收拾羣英賴化工，嫣然紅紫自成叢。", "四時不絕芳菲意，誰謂春歸閬苑中。"]'),
('61402375-f023-4001-92e3-cce9d173269b','十二詠 圭沼','李綱','宋','宋诗','song-poetry','','[]','旋鑿幽池象玉圭，蓮開紅素兩相輝。',32,'全唐诗/poet.song.90000.json','["旋鑿幽池象玉圭，蓮開紅素兩相輝。", "年來居士心離垢，天女從教試染衣。"]'),
('5160e4bb-d1cb-4247-a6bc-7e3ade248b3e','十二詠 磬塘','李綱','宋','宋诗','song-poetry','','[]','喬木森森借綠陰，曲塘波影漾疏林。',32,'全唐诗/poet.song.90000.json','["喬木森森借綠陰，曲塘波影漾疏林。", "龜魚不用愁清淺，藻荇菰蒲隱映深。"]'),
('26cc93a0-a783-466e-8545-9c2db23ab27e','十二詠 菖蒲澗','李綱','宋','宋诗','song-poetry','','[]','寸根九節結孤芳，青劍凌波日日長。',32,'全唐诗/poet.song.90000.json','["寸根九節結孤芳，青劍凌波日日長。", "幸有仙方辨真贗，醫師休更進菖陽。"]'),
('9824f270-4a49-4c0c-8e58-b4dbcf07ffb3','吕元直得書天台郭外治園林作退老堂求詩爲賦兩章  其一','李綱','宋','宋诗','song-poetry','','[]','獵得飛熊自渭濱，釣璜賜履定前身。',64,'全唐诗/poet.song.90000.json','["獵得飛熊自渭濱，釣璜賜履定前身。", "功髙浴日千山曉，力拒回天萬國春。", "暫輟巖廊調鼎手，來爲林壑採芝人。", "片帆雲海無多地，歎息何緣廁末賓。"]'),
('3a2696b2-6361-4671-978a-bc3c097ee0d3','吕元直得書天台郭外治園林作退老堂求詩爲賦兩章  其二','李綱','宋','宋诗','song-poetry','','[]','周遭疊嶂俯清流，卜築園林事事幽。',64,'全唐诗/poet.song.90000.json','["周遭疊嶂俯清流，卜築園林事事幽。", "春日鶯花隨衮繡，秋來松菊照林丘。", "謝公終爲蒼生起，裴相聊成綠野謀。", "聖主思賢方仄席，未應長伴赤松遊。"]'),
('d95484fc-7067-4954-a0ec-0292b7a6434a','送張子固大資政赴召命二首  其一','李綱','宋','宋诗','song-poetry','','[]','海邦臨撫忽頻年，愷悌宜民德化宣。',64,'全唐诗/poet.song.90000.json','["海邦臨撫忽頻年，愷悌宜民德化宣。", "久戀闕庭心自往，乍歸帷幄席應前。", "鹽梅好去陪三事，風月還須記九仙。", "聖主從容問幽仄，爲陳衰病老林泉。"]'),
('2c79c4ee-2b51-429d-bcfd-bca762e0d965','送張子固大資政赴召命二首  其二','李綱','宋','宋诗','song-poetry','','[]','屏跡山林養病身，數迂旌旆訪幽人。',64,'全唐诗/poet.song.90000.json','["屏跡山林養病身，數迂旌旆訪幽人。", "追酬雅韻篇章富，共醉芳醪意氣親。", "顧我老爲滄海客，羨公去作紫霄賓。", "經綸蚤動中興業，亦欲歸居浙水濱。"]'),
('411e5e55-7ac8-4e3b-adf4-b6f39ece5f89','送秦楚材還永嘉','李綱','宋','宋诗','song-poetry','','[]','海上從容慰所思，相逢已恨十年遲。',64,'全唐诗/poet.song.90000.json','["海上從容慰所思，相逢已恨十年遲。", "未登臺省陪羣彦，且向江湖把一麾。", "顧我留爲鷗鳥伴，羨君歸赴鶺鴒期。", "樽前聽徹陽關唱，明月依然照别離。"]'),
('a3c5bdfd-19b8-492b-ab56-667c345ba9d8','陳國佐左司寄示天台山圖以絕句兩章報之  其一','李綱','宋','宋诗','song-poetry','','[]','往年曾讀興公賦，頗愛天台擅美名。',32,'全唐诗/poet.song.90000.json','["往年曾讀興公賦，頗愛天台擅美名。", "數幅生綃傳貌得，恍如陸地到蓬瀛。"]'),
('8fee90f5-8984-41d1-87e0-4eb2dfd54ed5','陳國佐左司寄示天台山圖以絕句兩章報之  其二','李綱','宋','宋诗','song-poetry','','[]','應真飛錫游行處，峭壁危峰跨石橋。',32,'全唐诗/poet.song.90000.json','["應真飛錫游行處，峭壁危峰跨石橋。", "便欲遠尋方廣寺，却疑圖上有嘉招。"]'),
('f85d7752-97ac-43b9-a363-3874c44f1572','丹霞本老見示拂子并頌次韻','李綱','宋','宋诗','song-poetry','','[]','鈍根不會世間機，且作東山老住持。',32,'全唐诗/poet.song.90000.json','["鈍根不會世間機，且作東山老住持。", "有箇旄牛閑拂子，用時由我不由伊。"]'),
('d52c3c6f-dc93-438b-9f74-9f1a163e3dfd','贈羅偉政奉議','李綱','宋','宋诗','song-poetry','','[]','契闊踰年若泛萍，一樽還此共江城。',64,'全唐诗/poet.song.90000.json','["契闊踰年若泛萍，一樽還此共江城。", "蘭舟桂楫肯相訪，南浦西山無限情。", "顧我已甘華髪老，羨君猶戲綵衣輕。", "秋堂夜飲他年話，莫忘棋聲雜雨聲。"]'),
('503030e8-7558-4fff-9f65-2cf068d0157d','次韻李西美舍人見寄二首  其一','李綱','宋','宋诗','song-poetry','','[]','虜騎長驅犯帝闉，濫陪國論敢謀身。',64,'全唐诗/poet.song.90000.json','["虜騎長驅犯帝闉，濫陪國論敢謀身。", "十年不得關河信，四海猶飛戰伐塵。", "駕馭英雄歸睿主，扶持宗社賴元臣。", "自慚老病無長策，徒奉藩條牧細民。"]'),
('96fcd9b1-67e7-42ea-be7e-ea8983ef3afd','次韻李西美舍人見寄二首  其二','李綱','宋','宋诗','song-poetry','','[]','幾年離索渴微言，敢意髙車過我門。',64,'全唐诗/poet.song.90000.json','["幾年離索渴微言，敢意髙車過我門。", "暫解軒中徐孺榻，謾開坐上孔融樽。", "羨君感慨猶能飲，顧我衰遲已抱孫。", "杞梓楩楠委崖谷，上章端欲叩天閽。"]'),
('2a6d19ae-4fc3-4142-887b-8fba1c9ef1c7','次韻林茂南參謀觀閲水戰之作','李綱','宋','宋诗','song-poetry','','[]','習戰樓船章水濱，機輪運轉若無人。',64,'全唐诗/poet.song.90000.json','["習戰樓船章水濱，機輪運轉若無人。", "旌麾耀日驚飛鷺，金鼓翻波躍錦鱗。", "四坐縱觀聊舉白，一陽潛動欲回春。", "羽書正報淮淝捷，想見臚傳設九賓。"]'),
('998745f0-059a-4ea5-81c3-13d848d7e751','南昌樓秋望','李綱','宋','宋诗','song-poetry','','[]','兵火凋殘今幾秋，江山依舊繞層樓。',64,'全唐诗/poet.song.90000.json','["兵火凋殘今幾秋，江山依舊繞層樓。", "飛雲卷雨不窮態，明月清風無限愁。", "老子平生興不淺，昔人何在水空流。", "落霞孤鶩齊飛處，望斷楚天天盡頭。"]'),
('51426c55-3e99-4828-890f-56b8a6c54e56','冬至日雪二首  其一','李綱','宋','宋诗','song-poetry','','[]','銀河誰挽落層空，散作瓊蕤六出同。',64,'全唐诗/poet.song.90000.json','["銀河誰挽落層空，散作瓊蕤六出同。", "和氣已隨陽氣至，人心自與帝心通。", "魯臺不用書雲物，楚俗由來騐歲功。", "多幸豐年又相繼，從今臥治聽衰翁。"]'),
('4ecfff06-79b2-4e42-8669-d2c3d404f8b6','冬至日雪二首  其二','李綱','宋','宋诗','song-poetry','','[]','端木飛花片片勻，天風不動玉成塵。',64,'全唐诗/poet.song.90000.json','["端木飛花片片勻，天風不動玉成塵。", "葭灰有意迎新律，梅蘂多情漏早春。", "更覺西山饒爽氣，不妨東閣會嘉賓。", "十年不見渾如夢，休怪兒童笑語頻。"]'),
('6dd46ee7-4f66-47a6-b339-b6db204cdbe1','再和趙正之都運觀水戰三首  其一','李綱','宋','宋诗','song-poetry','','[]','戈船列陣楚江濱，世事何嘗不在人。',64,'全唐诗/poet.song.90000.json','["戈船列陣楚江濱，世事何嘗不在人。", "鷁首衝風開雪浪，甲光向日動金鱗。", "烟霄易覺壺中晚，談笑潛回席上春。", "更辱佳篇與褒飾，主人深有愧西賓。"]'),
('cdefebd8-533d-443e-8fd5-9b2b273835ca','再和趙正之都運觀水戰三首  其二','李綱','宋','宋诗','song-poetry','','[]','使節來從河水濱，天心圖舊慰斯人。',64,'全唐诗/poet.song.90000.json','["使節來從河水濱，天心圖舊慰斯人。", "肅将宸指蠲民瘼，力挽恩波活轍鱗。", "北伐正須猷克壮，中興方與物爲春。", "外臺豈久留英躅，佇見觀光利用賓。"]'),
('003c4c2f-2e00-46bd-a667-d5a05c4bee41','再和趙正之都運觀水戰三首  其三','李綱','宋','宋诗','song-poetry','','[]','抱病深棲雲海濱，誤恩起廢愧陳人。',64,'全唐诗/poet.song.90000.json','["抱病深棲雲海濱，誤恩起廢愧陳人。", "飛騰固乏摶風翮，游泳長思縱壑鱗。", "一局銷磨垂老日，三杯搖蕩滿懷春。", "何當詔許歸田野，會有漁樵作上賓。"]'),
('6af0e915-c382-4177-9ac7-928996776e81','正之復次前韻作四篇見示是日適登城樓以望江山且閲捷報因賦六章以報之  其一','李綱','宋','宋诗','song-poetry','','[]','帝遣宗英使楚濱，漕臺元自得詩人。',64,'全唐诗/poet.song.90000.json','["帝遣宗英使楚濱，漕臺元自得詩人。", "從横錦繡花生舌，飛動龍蛇墨起鱗。", "心拱北宸恩露渥，笑回南浦渌波春。", "不須過作飛芻計，早晚追陪紫府賓。"]'),
('4ec50cc7-c743-4f4f-8e32-a14849dc7cab','正之復次前韻作四篇見示是日適登城樓以望江山且閲捷報因賦六章以報之  其二','李綱','宋','宋诗','song-poetry','','[]','黠虜狂謀犯泗濱，脅從太半是吾人。',64,'全唐诗/poet.song.90000.json','["黠虜狂謀犯泗濱，脅從太半是吾人。", "且将戈戟殱蛇豕，會把衣裳易介鱗。", "河洛至今思帝德，雲龍行見會王春。", "漢官儀物都如舊，混一車書萬國賓。"]'),
('766fb28c-3b0f-44e8-820d-7bb2109c0637','正之復次前韻作四篇見示是日適登城樓以望江山且閲捷報因賦六章以報之  其三','李綱','宋','宋诗','song-poetry','','[]','晉敗苻秦淝水濱，謝公祗用八千人。',64,'全唐诗/poet.song.90000.json','["晉敗苻秦淝水濱，謝公祗用八千人。", "飛騰貔虎生修翼，屠剪鯨鯢膾硬鱗。", "否運既傾終反泰，寒威已振却成春。", "吾皇盛德超千古，接士端如見大賓。"]'),
('d1a65be3-075a-4ed0-add8-4054c4ff664f','正之復次前韻作四篇見示是日適登城樓以望江山且閲捷報因賦六章以報之  其四','李綱','宋','宋诗','song-poetry','','[]','艅艎搖曳大江濱，龜手從來笑越人。',64,'全唐诗/poet.song.90000.json','["艅艎搖曳大江濱，龜手從來笑越人。", "會使風檣如陣馬，何妨鷁首著龍鱗。", "已欣淮北兵戈捷，且醉江南麴米春。", "元直德翁忘爾汝，孰爲東道孰爲賓。"]'),
('b106d58b-e246-4768-b444-d97a5d757321','正之復次前韻作四篇見示是日適登城樓以望江山且閲捷報因賦六章以報之  其五','李綱','宋','宋诗','song-poetry','','[]','城樓縹緲俯漳濱，景物依然念昔人。',64,'全唐诗/poet.song.90000.json','["城樓縹緲俯漳濱，景物依然念昔人。", "雲出西山天欲雪，風來南浦水生鱗。", "四圍氣象朝朝好，一點陽和處處春。", "日暮短蓬輕槳急，雙魚應已付溪賓。"]'),
('660ca7c3-4166-4849-a3c0-426466033d2a','正之復次前韻作四篇見示是日適登城樓以望江山且閲捷報因賦六章以報之  其六','李綱','宋','宋诗','song-poetry','','[]','伊昔端居寂寞濱，每於騷雅愛其人。',64,'全唐诗/poet.song.90000.json','["伊昔端居寂寞濱，每於騷雅愛其人。", "長篇賸得斕斑錦，短句兼收細碎鱗。", "指下粗能知越操，郢中那敢和陽春。", "願藏大手無輕露，寸膽于今已自賓。"]'),
('2fd77384-2e80-44a0-ac1d-85f079d5d7ba','殘臘雪再作二首  其一','李綱','宋','宋诗','song-poetry','','[]','朔風三日散輕埃，珠蘂瓊花一夜開。',64,'全唐诗/poet.song.90000.json','["朔風三日散輕埃，珠蘂瓊花一夜開。", "灝氣遠從雲表下，清聲初自竹間來。", "未論上瑞呈三白，且助元功澤九垓。", "向晚城樓聊寓目，西山千疊玉崔嵬。"]'),
('afcd6e73-33ca-4458-b403-b8d7e11de8fa','殘臘雪再作二首  其二','李綱','宋','宋诗','song-poetry','','[]','縈回作舞下烟霄，滿地光鋩混凸凹。',64,'全唐诗/poet.song.90000.json','["縈回作舞下烟霄，滿地光鋩混凸凹。", "虚幌夜寒疑月彩，疏林曉粲誤梅梢。", "遠懷戴隱終須訪，髙擁袁門未易敲。", "好是碧天雲散後，銀蟾皎潔兩相交。"]'),
('f10e76c2-c8d7-4d0b-b962-56bca1e17c85','再次前韻  其一','李綱','宋','宋诗','song-poetry','','[]','太清真境絕氛埃，十二瑤臺面面開。',64,'全唐诗/poet.song.90000.json','["太清真境絕氛埃，十二瑤臺面面開。", "戰退玉龍鱗甲冷，導迎仙鶴羽儀來。", "祥編已慶占盈尺，和氣行欣浹九垓。", "須信天公工幻戲，晴山依舊翠崔嵬。"]'),
('7d00a3cb-7ab4-4759-8af5-3bae3f43d626','再次前韻  其二','李綱','宋','宋诗','song-poetry','','[]','霏霏玉屑灑層霄，皓色輕盈已覆凹。',64,'全唐诗/poet.song.90000.json','["霏霏玉屑灑層霄，皓色輕盈已覆凹。", "留客徑須開綠蟻，探春何處認青梢。", "階庭充積無庸掃，松竹欹摧尚惜敲。", "深愧主人修具薄，嘉賓徒使獻酬交。"]'),
('0dbd30ab-0ec9-4375-8233-faae2c49795c','趙都漕出示魯直少游所書梅詩次韻','李綱','宋','宋诗','song-poetry','','[]','冰散憑陵羣木槁，只有梅花欺不倒。',128,'全唐诗/poet.song.90000.json','["冰散憑陵羣木槁，只有梅花欺不倒。", "籬邊野外忽嫣然，暗香解作幽人惱。", "化工著意爲尤物，故遣孤芳得春早。", "道人寫照三昧手，不假丹青更妍好。", "詩家也是可憐人，落筆雲烟隨意掃。", "遂令淡墨勝鉛華，紙上一枝長不老。", "庭中幾樹正垂垂，忍看飄零委煙草。", "會須痛飲對繁華，細把根源問蒼昊。"]'),
('358257d9-fd5f-44fa-bcd4-d3f6b4b58e9a','吕元直移鎮臨安入覲行闕余方以衰病請閑有卜居浙東之意願爲根老堂之游作詩寄之','李綱','宋','宋诗','song-poetry','','[]','詔起三湘老獵師，和羮舊手帝深知。',64,'全唐诗/poet.song.90000.json','["詔起三湘老獵師，和羮舊手帝深知。", "戎車北伐資長策，衮繡東歸有去思。", "謾作天台休老計，正當黄閣立賢時。", "主人方爲蒼生急，願借新堂醉一巵。"]'),
('db0949c4-4563-42f7-bbe7-004ef5ad96db','趙正之寵貺和篇褒與過厚適傳新命念暌違之有日預深悵然輒次其韻','李綱','宋','宋诗','song-poetry','','[]','七言八法定誰師，妙處工夫只自知。',64,'全唐诗/poet.song.90000.json','["七言八法定誰師，妙處工夫只自知。", "南浦西山久同賞，清風明月更相思。", "瓌材卓犖承恩日，衰病侵尋念去時。", "垂老相看重言别，莫辭瀲灧十分巵。"]'),
('edb7f0c2-76b1-4703-8333-d38579aff0a1','送趙正之判宗室學之官閩中','李綱','宋','宋诗','song-poetry','','[]','神明之胄慶所鍾，禀毓不與常人同。',352,'全唐诗/poet.song.90000.json','["神明之胄慶所鍾，禀毓不與常人同。", "漢髙子孫盡隆凖，唐室賢輔多華宗。", "本朝功德追前古，振振宗姓敦儒風。", "君家奕世擅英譽，繼持從橐聲光崇。", "向來仗節使關陜，風績不减褰帷公。", "自從國步暫艱危，低眉信命隨飄蓬。", "十年流落困覉旅，一日賜對明光宫。", "御前奉命作大字，揮毫落紙蟠虬龍。", "豈惟筆扛百斛鼎，固已氣吐千丈虹。", "上流重地方用武，貔貅十萬屯元戎。", "輟從禁近付飛輓，木牛流馬慚無功。", "國家敦睦急先務，改授欲使歸磨礲。", "捨煩就簡愜雅志，祗恐漕運難追蹤。", "閩山中夏荔枝熟，火齊磊落堆盤紅。", "憑空跨壑千佛寺，金碧照耀烟霞中。", "登臨多暇飫珍品，豈比朱墨相填叢。", "帝心簡在方仄席，鋒車迅召行登庸。", "嗟予憂志苦多病，齒搖髪脫真衰翁。", "誤恩分閫愧無補，豈有惠澤漸兵農。", "乞身屢矣未蒙可，坐使澤雉愁樊籠。", "送君南浦慘長别，此心已逐歸飛鴻。", "會當柴車返故隱，幅巾杖屨長相從。"]'),
('130f283f-dcfd-4c23-8586-885702609e43','次韻鄭顧道侍郎用師字韻見贈','李綱','宋','宋诗','song-poetry','','[]','昔年班列會京師，邂逅相逢只舊知。',64,'全唐诗/poet.song.90000.json','["昔年班列會京師，邂逅相逢只舊知。", "一紀此身渾似夢，中原回首不堪思。", "乍欣旌旆來臨日，共喜江山適意時。", "感慨不須諭舊事，且将强健對芳巵。"]'),
('635ebdff-c2c8-42c3-b241-10734dfaf4e1','中冬教閲兵將運使徐顯謨貺惠佳什降歎之餘因次其韻以答厚意且簡同會諸公','李綱','宋','宋诗','song-poetry','','[]','伐鼓摐金閲五兵，霜天清曉正崢嶸。',64,'全唐诗/poet.song.90000.json','["伐鼓摐金閲五兵，霜天清曉正崢嶸。", "輕裘自愧叨儒帥，一令安能探舊營。", "獵獵旌麾搖有浪，駪駪徒御肅無聲。", "滿堂賓客皆英俊，莫怪陳蕃倒屣迎。"]'),
('9a42b502-a6a9-48e0-b300-4fb8750ee11c','次韻折仲古安撫端明食荔子感懷書事之作','李綱','宋','宋诗','song-poetry','','[]','臥病閩山强自支，嘗珍似與故人期。',64,'全唐诗/poet.song.90000.json','["臥病閩山强自支，嘗珍似與故人期。", "却嗟老眼傷心日，又見輕紅着子時。", "萬事從來皆默定，一樽聊復賦新詩。", "使君不作楞梨看，他日逢人舉似爲。"]'),
('2693fcd0-e620-46d6-9856-615bdb75877e','遊山拙句奉呈珪老并簡諸公','李綱','宋','宋诗','song-poetry','','[]','嘉客同遊海上宫，髙僧問道得從容。',64,'全唐诗/poet.song.90000.json','["嘉客同遊海上宫，髙僧問道得從容。", "乍驚暑退靈源洞，最愛庭開大頂峰。", "傑閣初成切星斗，飛雲時到繞杉松。", "我來未盡登臨興，更待秋髙灝氣濃。"]'),
('825357ae-ab99-465b-b91e-ce9c2ea729e4','次韻廷俊紀藥圃小集見贈之作','李綱','宋','宋诗','song-poetry','','[]','遠邀車馬出郊東，髙閣登臨四顧雄。',64,'全唐诗/poet.song.90000.json','["遠邀車馬出郊東，髙閣登臨四顧雄。", "雨飽共欣秧稻綠，酒酣尤愛荔枝紅。", "漫同小隱開三徑，頗傚前賢時一中。", "坐上衆賢皆降歎，滿浮大白莫如公。"]'),
('4e4b11f5-b1e8-40cd-948f-752c4985e6f2','冬日來觀鼓山新閣偶成古風三十韻','李綱','宋','宋诗','song-poetry','','[]','尋盟訪鼓山，風物宛如昨。',288,'全唐诗/poet.song.90000.json','["尋盟訪鼓山，風物宛如昨。", "山中有開士，彈指成傑閣。", "應真飛錫來，一一得所託。", "翬飛騫棟甍，絢爛麗丹雘。", "峨峨大頂峰，孤影入簷角。", "乃知象教力，建立必卓犖。", "却爲靈源遊，雲木互參錯。", "巖深松桂香，石古苔蘚剝。", "冬温日清美，景短氣蕭索。", "天然資野逸，安用遮翠幕。", "快哉緬登臨，及此小搖落。", "乘髙望瀛海，南極露垠堮。", "蓬壺在跬步，誰謂仙山邈。", "蒼茫杳靄中，萬象恣磅礴。", "迴頭睇中原，郡國半沙漠。", "犬羊污宫殿，蛇豕穴城郭。", "疇能挽天河，一洗氛祲惡。", "我生多艱虞，久矣衰病作。", "君恩聽言歸，養拙侣猿鶴。", "忽忽歲遒盡，平子殊不樂。", "幸同二三子，杖履徧丘壑。", "躋攀力尚强，談笑心無怍。", "野鹿飽豐甘，冥鴻在寥廓。", "翻思軒冕間，何異遭束縳。"]'),
('2d317323-d964-47d5-9e5f-fcd78cd72557','還自鼓山過鱓溪遊大乘榴花洞瞻禮文殊聖像漫成三首  其一','李綱','宋','宋诗','song-poetry','','[]','一派寒流作小溪，松篁深處有叢祠。',64,'全唐诗/poet.song.90000.json','["一派寒流作小溪，松篁深處有叢祠。", "千年鱓骨專車在，百丈靈湫瀑布垂。", "粳稻豐穰欣歲樂，笳簫清咽報神私。", "更将小雨爲滂潤，正是農夫播麥時。"]'),
('393d03cb-6628-467c-a4bf-f3a0ef64a4e7','還自鼓山過鱓溪遊大乘榴花洞瞻禮文殊聖像漫成三首  其二','李綱','宋','宋诗','song-poetry','','[]','乞得明時多病身，歸來林下養天真。',64,'全唐诗/poet.song.90000.json','["乞得明時多病身，歸來林下養天真。", "芒鞋竹杖未全老，藥竈酒壺隨分春。", "山寺遞傳鐘磬晚，田家收拾稻粱新。", "試窮溪上榴花洞，恐有桃源避世人。"]'),
('c3e35dfb-8fd0-4765-9f58-b1d4d4b7b6b5','還自鼓山過鱓溪遊大乘榴花洞瞻禮文殊聖像漫成三首  其三','李綱','宋','宋诗','song-poetry','','[]','布地金沙片片勻，深沉院宇閟祗園。',64,'全唐诗/poet.song.90000.json','["布地金沙片片勻，深沉院宇閟祗園。", "清涼路半前三語，摩詰城中不二門。", "千種光明瞻瑞相，六根清凈爲還源。", "狻猊坐上法王子，稽首皈依衆所尊。"]'),
('36daa4ee-bcfb-488d-aa64-5b97f6ddf68a','冬至前六日奉陪舅氏燕集于張甥東齋泰孫侍坐舅甥四世同會豈易得也舅氏以詩見貺謹次韻成兩章拜呈并簡季弟二甥同賦  其一','李綱','宋','宋诗','song-poetry','','[]','舅甥髙會共稱觴，四世于今在一堂。',64,'全唐诗/poet.song.90000.json','["舅甥髙會共稱觴，四世于今在一堂。", "眉壽康寧由德厚，慶流深遠本源長。", "但将直道師周孔，豈有嘉猷助禹湯。", "提誨勤勤何以報，願言殊祉集新陽。"]'),
('97d79883-997b-409c-bf5c-6c9e0d1bbfa1','冬至前六日奉陪舅氏燕集于張甥東齋泰孫侍坐舅甥四世同會豈易得也舅氏以詩見貺謹次韻成兩章拜呈并簡季弟二甥同賦  其二','李綱','宋','宋诗','song-poetry','','[]','人間此會信非常，和氣薫然自滿堂。',64,'全唐诗/poet.song.90000.json','["人間此會信非常，和氣薫然自滿堂。", "競酌芳樽同勸壽，正當愛日欲迎長。", "綵衣誦古如流水，華髪銜杯若沃湯。", "乘馬路車何以贈，渭陽元自是王陽。"]'),
('acc03209-d1d3-4e86-a849-36c624a6ddfc','次李泰發韻二首送仲輔提刑弟還浙東  其一','李綱','宋','宋诗','song-poetry','','[]','朝路紛紛厭送迎，乞歸恩予繡衣榮。',64,'全唐诗/poet.song.90000.json','["朝路紛紛厭送迎，乞歸恩予繡衣榮。", "稍知物外烟霞好，便覺塵中富貴輕。", "飛舄已能同葉令，叱羊何必效初平。", "坐忘我欲師前躅，爲過天台訪赤城。"]'),
('453e7989-b1e9-4ce6-a3e5-d88c77debfbb','次李泰發韻二首送仲輔提刑弟還浙東  其二','李綱','宋','宋诗','song-poetry','','[]','謁告來歸若駿奔，友于真可裕礽晜。',64,'全唐诗/poet.song.90000.json','["謁告來歸若駿奔，友于真可裕礽晜。", "共傷庭玉先埋土，悵望鴒原增斷魂。", "白髪自嗟臨藥竈，一瓶端欲寄空門。", "浙東耆舊如相問，爲道衰遲愧主恩。"]'),
('c2d84aa1-e82c-4967-889c-61b03b1d9a7b','楊夫人挽章二首  其一','李綱','宋','宋诗','song-poetry','','[]','來嬪初卜鳳和鳴，誰謂今聞薤露聲。',64,'全唐诗/poet.song.90000.json','["來嬪初卜鳳和鳴，誰謂今聞薤露聲。", "婦道宜傳青史筆，壼儀猶在錦官城。", "承家早慶芝蘭秀，主饋空餘蘋藻誠。", "念舊二卿情意厚，可堪孤坐想平生。"]'),
('3eaa3a63-bae9-4ff3-ba44-af04a954f538','楊夫人挽章二首  其二','李綱','宋','宋诗','song-poetry','','[]','悼亡何事覺神傷，端爲音容不可忘。',64,'全唐诗/poet.song.90000.json','["悼亡何事覺神傷，端爲音容不可忘。", "舉案素聞敦節操，題橋今見共龍光。", "錦囊屢慶宸恩重，丹旐俄嗟蜀道長。", "髣髴靈遊元未遠，無人解致返魂香。"]'),
('01bb4984-07ae-479f-822d-7b34b66af0ab','唐植甫左司挽詞二首  其一','李綱','宋','宋诗','song-poetry','','[]','踐歷髙華久，巍然譽望崇。',48,'全唐诗/poet.song.90000.json','["踐歷髙華久，巍然譽望崇。", "典章諳故熟，翰墨老彌工。", "骾亮傳家法，清忠邁古風。", "温温江玉硯，同閟九原中。"]'),
('9537fd69-8593-435c-a2c4-23759153f46b','唐植甫左司挽詞二首  其二','李綱','宋','宋诗','song-poetry','','[]','夙昔欽賢業，何知共里閭。',48,'全唐诗/poet.song.90000.json','["夙昔欽賢業，何知共里閭。", "忘年遇我厚，謫宦識公初。", "小嶺親髙論，靈齋見異書。", "凄凉真一夢，追想涕漣洳。"]'),
('2b39fb76-7c2a-4684-b8e5-baeff4ed5a63','哭宗留守汝霖','李綱','宋','宋诗','song-poetry','','[]','時危念人傑，濟物須材雄。',288,'全唐诗/poet.song.90000.json','["時危念人傑，濟物須材雄。", "尋常齷齪姿，詎可收奇功。", "英英宗夫子，邈與古人同。", "抱器實磊落，秉心鬱精忠。", "彯纓仕州縣，山立不妄從。", "青松雖未髙，已足凌蒿蓬。", "涉世多齟齬，失官久龍鍾。", "擢居河朔郡，烟塵正昬蒙。", "今上在藩邸，持節使虜中。", "力争不可往，髙牙建元戎。", "王室遂再造，廊廟當疇庸。", "同朝共排媢，一麾江漢東。", "見我論世故，慷慨淚沾胸。", "薦之守留鑰，付以節制隆。", "惠政附疲瘵，威聲懾姦兇。", "金湯治城塹，樓櫓欻以崇。", "出師京洛間，屢挫黠虜鋒。", "邦畿千里寧，誇說百歲翁。", "抗疏請還闕，北伐歸兩宫。", "辭直志鯁亮，天子爲動容。", "姦諛更切齒，恨未能關弓。", "乃同歸鄛人，感憤殞厥躬。", "皇天不憗遺，吾道何其窮。", "驊騮竟委離，冀北羣遂空。"]'),
('4e555250-0c9d-4545-876e-6653565e903d','致享張丈脩撰墓下追惟平生不勝愴然輒成兩章以叙懷感之意  其一','李綱','宋','宋诗','song-poetry','','[]','秋原鬱鬱見佳城，尚想音容涕泗横。',64,'全唐诗/poet.song.90000.json','["秋原鬱鬱見佳城，尚想音容涕泗横。", "痛惜山頽與梁壞，愧無玉潤繼冰清。", "喪賢初值龍蛇歲，憂國空餘金石誠。", "賴有階庭蘭玉在，芬芳端不墜家聲。"]'),
('c0a0bdad-92a9-40ae-a2c2-fbd6612cef50','致享張丈脩撰墓下追惟平生不勝愴然輒成兩章以叙懷感之意  其二','李綱','宋','宋诗','song-poetry','','[]','勇退風流靄士林，對揚丹扆極規箴。',64,'全唐诗/poet.song.90000.json','["勇退風流靄士林，對揚丹扆極規箴。", "髙名雅出漢庭右，遺愛空存南國深。", "身後凄凉報恩子，生前軒豁濟時心。", "九原可作如公少，獨立西風淚滿襟。"]'),
('1077924c-683e-472d-977f-e512de384831','哭吳丞相元中二首  其一','李綱','宋','宋诗','song-poetry','','[]','妙年聲譽靄文塲，壮歲飛騰青瑣郎。',64,'全唐诗/poet.song.90000.json','["妙年聲譽靄文塲，壮歲飛騰青瑣郎。", "獻納承平欲堯舜，扶持危難冀宣光。", "賈生曠達仍傷鵩，平仲精忠亦殞荒。", "自古青蠅能黑白，玉華舊事已凄涼。"]'),
('40cd577a-8fd4-4950-813b-e0b2ffa4ce75','哭吳丞相元中二首  其二','李綱','宋','宋诗','song-poetry','','[]','宣和之季靖康初，同力同心衛帝居。',64,'全唐诗/poet.song.90000.json','["宣和之季靖康初，同力同心衛帝居。", "扶轂共升新日月，謫官難守舊田廬。", "孔光温室不言樹，陸贄忠州戒著書。", "歎息端荘士君子，豈随草木腐丘墟。"]'),
('b17f6c07-9436-4d50-8cfe-7221fd9db6e1','哭許崧老右丞二首  其一','李綱','宋','宋诗','song-poetry','','[]','夫子相知一紀前，定交握手自忘年。',64,'全唐诗/poet.song.90000.json','["夫子相知一紀前，定交握手自忘年。", "長松老鶴骨格古，粹玉精金操守堅。", "出入三朝昭大節，漂流萬里正華顛。", "皇天不愸遺元老，空使蒼生共黯然。"]'),
('5cee1202-a5e0-4094-bedb-3572b8243871','哭許崧老右丞二首  其二','李綱','宋','宋诗','song-poetry','','[]','多聞直諒復疏通，近世交遊少似公。',64,'全唐诗/poet.song.90000.json','["多聞直諒復疏通，近世交遊少似公。", "蓋代才名同賈誼，平生述作類揚雄。", "筆蹤髙古今那有，詩調清新老更工。", "知識年來凋喪盡，不堪衰淚落秋風。"]'),
('36121b71-0851-48b3-b37f-9c6f8585e1de','許子大龍圖挽詞二首  其一','李綱','宋','宋诗','song-poetry','','[]','芬芳登桂籍，烜赫紹家聲。',48,'全唐诗/poet.song.90000.json','["芬芳登桂籍，烜赫紹家聲。", "持槖恩輝渥，分符政術明。", "優優方膴仕，鬱鬱遽佳城。", "庭户多蘭玉，應無可恨情。"]'),
('b6ac1209-766a-4a80-8806-582c670210a3','許子大龍圖挽詞二首  其二','李綱','宋','宋诗','song-poetry','','[]','接武鴛鸞列，交承淮海州。',48,'全唐诗/poet.song.90000.json','["接武鴛鸞列，交承淮海州。", "平生欽德望，避地款風流。", "樽俎開幽抱，江山共勝遊。", "那知生死隔，衰淚浩難收。"]'),
('05ce676a-486b-4a48-b6b4-0f55b7dc1809','張次東中奉挽詞三首  其一','李綱','宋','宋诗','song-poetry','','[]','賈父褰帷日，于公駟馬門。',48,'全唐诗/poet.song.90000.json','["賈父褰帷日，于公駟馬門。", "十年持使節，兩郡擁朱轓。", "無復功名會，空餘氣槩存。", "凄涼九原路，楚些與招魂。"]'),
('e8103591-ce67-459f-b20d-3595f2cb9827','張次東中奉挽詞三首  其二','李綱','宋','宋诗','song-poetry','','[]','寓意樽中渌，陶然得此生。',48,'全唐诗/poet.song.90000.json','["寓意樽中渌，陶然得此生。", "孔融真好客，阮籍自忘形。", "議論千夫屈，風流一坐傾。", "傷心将玉樹，寂寞閟佳城。"]'),
('b5eb072c-8b30-4712-b933-32a0f2c165df','張次東中奉挽詞三首  其三','李綱','宋','宋诗','song-poetry','','[]','南國多奇士，如公豈易求。',48,'全唐诗/poet.song.90000.json','["南國多奇士，如公豈易求。", "才髙雖擅譽，命阨未封侯。", "故宅風烟慘，新阡松桂幽。", "遥傳一掬淚，爲灑暮江頭。"]'),
('f6131bf0-0295-43bf-8372-f35633ff1db0','致奠張柔直知郡龍圖以詩四章哭之書置靈几以代祭文  其一','李綱','宋','宋诗','song-poetry','','[]','一枰兩淺舊相期，歎息君今願已違。',32,'全唐诗/poet.song.90000.json','["一枰兩淺舊相期，歎息君今願已違。", "却把荔枝三奠酒，數行衰淚濕深衣。"]'),
('43160d01-03a0-4a37-b110-494ac2af230c','致奠張柔直知郡龍圖以詩四章哭之書置靈几以代祭文  其二','李綱','宋','宋诗','song-poetry','','[]','隻鷄斗酒祭夫君，尚想平生意氣親。',32,'全唐诗/poet.song.90000.json','["隻鷄斗酒祭夫君，尚想平生意氣親。", "痛惜中原未恢復，如何天乃喪斯人。"]'),
('c7493646-700e-46bd-9fa8-473456af74c0','致奠張柔直知郡龍圖以詩四章哭之書置靈几以代祭文  其三','李綱','宋','宋诗','song-poetry','','[]','去歲如今會豫章，從容談笑共銜觴。',32,'全唐诗/poet.song.90000.json','["去歲如今會豫章，從容談笑共銜觴。", "豈期便作終天訣，尺素開時神內傷。"]'),
('d6ececdb-0a66-478c-8fa3-038b4dd9c4fe','致奠張柔直知郡龍圖以詩四章哭之書置靈几以代祭文  其四','李綱','宋','宋诗','song-poetry','','[]','連夕頻頻夢見君，依然野鶴處雞羣。',32,'全唐诗/poet.song.90000.json','["連夕頻頻夢見君，依然野鶴處雞羣。", "不須遺恨功名淺，世事渾如空際雲。"]'),
('62925194-15c7-4eb5-923f-ee2a7ecdf638','洪崖先生畫贊','李綱','宋','宋诗','song-poetry','','[]','洪崖古先生，傲睨得天逸。',72,'全唐诗/poet.song.90000.json','["洪崖古先生，傲睨得天逸。", "結廬西山下，踏雪時一出。", "長瓢與巨扇，此外了無物。", "借問侍者誰，拙朮藤葛橘。", "何年丹青手，寫此神仙質。", "高風邈如在，超然入吾室。"]'),
('e06a7b6d-8983-4747-9aad-ec62c3a4dc65','雙林善慧大士錄贊','李綱','宋','宋诗','song-poetry','','[]','彌勒棲神兜率天，下生此土猶久遠。',384,'全唐诗/poet.song.90000.json','["彌勒棲神兜率天，下生此土猶久遠。", "化身無數在世間，善慧大士乃其一。", "于中深秘菩薩行，而外示現凡夫相。", "佃獵漁捕悉與同，娶妻生子亦復爾。", "忽然照水知宿因，本來神智皆具足。", "雙林浄土坐道場，說法度脱無量衆。", "爲欲化導群生故，六度四心爲依止。", "田園廬舍諸器用，奴婢妻子亦棄捐。", "而以營修大法會，蓋行布施攝慳貪。", "強夫暴客與魔民，豪奪追逐共誣謗。", "更以軟語安慰之，蓋行忍辱攝瞋恚。", "精進攝諸懈怠者，晝夜行道不休息。", "持戒攝諸毁禁者，敷草而坐食粗糲。", "智惠禪定無有邊，攝諸癡亂亦如是。", "慈悲喜捨救衆生，微妙宏深難測識。", "雖依如是衆法門，亦不於此而常住。", "辨才演說無滯閡，譬如空谷中答響。", "歌頌句偈自成章，縱横顛倒皆通達。", "神通游戲得自在，聊以折伏不信心。", "異香殊相放妙光，一叩宮門餘悉啓。", "住是解脱不思議，正如長者維摩詰。", "應世闡化靡不齊，故於行道常接後。", "化緣已畢示寂滅，迄今何翅五百年。", "雖有文字傳未來，蕪纇不能發實相。"]'),
('ee695e0b-1b48-4208-ad4f-71b2731b253d','瑞芝贊','李綱','宋','宋诗','song-poetry','','[]','太虚磅礴，鍾此和氣。',80,'全唐诗/poet.song.90000.json','["太虚磅礴，鍾此和氣。", "慶門其昌，而産斯瑞。", "厥瑞維何，靈芝煌煌。", "孝誠所致，文字之祥。", "有開必先，其應以類。", "力學顯親，孰孝于是。", "勉修遠業，自奮于時。", "匪我云然，芝實告之。"]'),
('613e7543-4ea7-4b63-a9db-5924dcd647db','梁谿真贊','李綱','宋','宋诗','song-poetry','','[]','是爲梁谿，了無差别。',100,'全唐诗/poet.song.90000.json','["是爲梁谿，了無差别。", "行年之化，三十有八。", "返觀其前，膚腴色悦。", "從是以往，蒼顔華髪。", "本來面目，不生不滅。", "游戲仕塗，天付之拙。", "順天而行，一無敢設。", "獨知其天，寧有他訣。", "萬里清風，一輪明月。", "有來問者，默然無說。"]'),
('d1ea39e5-ab7c-41af-9843-dd417970f521','梁谿四友贊序 歲寒贊','李綱','宋','宋诗','song-poetry','','[]','霜霰既零，草木殄瘁。',80,'全唐诗/poet.song.90000.json','["霜霰既零，草木殄瘁。", "惟兹歲寒，獨立不改。", "寸苗初植，未離蓬艾。", "挺然凌雲，色參天黛。", "虬枝茂葉，舞影垂陰。", "清風徐來，虎嘯龍吟。", "與子爲友，貴相知心。", "何以樂之，寫此素琴。"]'),
('608b0670-7477-432b-87fa-5a7e42ec3e2f','梁谿四友贊序 虛心贊','李綱','宋','宋诗','song-poetry','','[]','君子學道，其心貴虚。',80,'全唐诗/poet.song.90000.json','["君子學道，其心貴虚。", "此君之心，一物本無。", "勁節堅竦，清影扶疏。", "劍拔環侍，十萬丈夫。", "細細其香，猗猗其綠。", "滴露和煙，鏘金戞玉。", "與子爲友，惟日不足。", "何年棲鳯，慰此幽獨。"]'),
('4de0820d-0e46-4304-97b0-06c1913f77f3','梁谿四友贊序 幽芳贊','李綱','宋','宋诗','song-poetry','','[]','天地和氣，萃于幽芳。',80,'全唐诗/poet.song.90000.json','["天地和氣，萃于幽芳。", "言茁其芽，薫然國香。", "綠葉紫莖，素榮縹房。", "紉以爲佩，禦彼不祥。", "採自深林，置于座側。", "不改其度，其香滿室。", "與子爲友，心同德一。", "優哉游哉，聊以永日。"]'),
('e8c1946d-eaf4-491a-a876-0e4d51e59715','梁谿四友贊序 粲華贊','李綱','宋','宋诗','song-poetry','','[]','我有佳友，粲粲其華。',80,'全唐诗/poet.song.90000.json','["我有佳友，粲粲其華。", "金英煒煌，翠葉交加。", "風露灑濯，色香相知。", "宛如美人，象服逶迤。", "可以忘憂，莫如旨酒。", "泛此粲華，益我眉壽。", "淵明一樽，子美三嗅。", "永結清歡，相從白首。"]'),
('95208d99-ed81-4c87-93c1-f5d0fabca033','瑞光巖立化雀贊','李綱','宋','宋诗','song-poetry','','[]','菩薩遊戲于神通，六道四生咸可入。',240,'全唐诗/poet.song.90000.json','["菩薩遊戲于神通，六道四生咸可入。", "爲欲化導諸有情，故於異類而出現。", "諦觀此雀甚微渺，每食一粒棲一枝。", "卑飛不出蓬蒿間，遠舉安知鴻鵠志。", "而能坐脱與立亡，依彼金容及香火。", "屹然而化不震動，如以木石鐫刻成。", "非諸菩薩威神力，孰能現此希奇事。", "我觀三界諸衆生，惟人實具大智慧。", "妄想顛倒造諸業，失身淪入横生中。", "重爲毛羣輕羽族，破碎一切諸蠕動。", "雖云妙覺不銷亡，無那沉迷益玄遠。", "菩薩慈悲哀憫故，化身與彼爲導師。", "緣終寂滅顯示人，使知佛性無有二。", "佛子若有瞻禮者，願言悉發敬信心。", "勇猛精進趣菩薩，皆具如是菩薩行。"]'),
('6fe1273a-0dad-4dd3-ba9a-6be837653c32','繡觀音贊','李綱','宋','宋诗','song-poetry','','[]','觀音妙智力，無刹不現身。',96,'全唐诗/poet.song.90000.json','["觀音妙智力，無刹不現身。", "出自鍼縷間，神通亦如是。", "光華五采備，成此六銖衣。", "雲髻冰雪衣，寶冠瓔珞飾。", "荘嚴行道相，步步妙蓮花。", "慈眼視衆生，睟然見于色。", "願言瞻敬者，迴顧逍遙人。", "繫縛本來無，何往非自在。"]'),
('ddbe998b-baf2-4184-910d-ce3b441341ea','天王院新塑釋迦像金色珠贊','李綱','宋','宋诗','song-poetry','','[]','稽首釋迦文，善逝天人師。',156,'全唐诗/poet.song.90000.json','["稽首釋迦文，善逝天人師。", "緣終示寂滅，無量舍利子。", "悉建窣堵波，天人共瞻禮。", "像法住世間，化導諸有情。", "亦示大神變，攝伏不信者。", "璀璨真金色，清浄妙寶珠。", "即彼土木中，現此希奇事。", "有來瞻禮者，隨取即與之。", "既與出愈多，不可爲量數。", "當觀舍利子，及此金色珠。", "堅固與虚脆，無異無差别。", "佛子具智慧，悉發敬信心。", "勇猛勿復疑，歸依無上道。"]'),
('92861934-dfc5-40c9-a4f7-d44360091ae7','綵塔贊','李綱','宋','宋诗','song-poetry','','[]','釋迦佛說妙蓮華，從地湧出七寶塔。',176,'全唐诗/poet.song.90000.json','["釋迦佛說妙蓮華，從地湧出七寶塔。", "欄楯幡幢及龕室，寶玲瓔珞震妙音。", "四面皆出旃檀香，散天妙華以供養。", "佛以右指開塔戶，出大音聲却關鑰。", "多寶如來示全身，讚歎說法分半座。", "惟二如來共一塔，至今此會尚儼然。", "何人建立窣堵波，種種嚴飾悉具足。", "綵縷縈結尺寸間，高廣五百由旬等。", "當知一念周圓時，勝妙功德已成就。", "若能瞻禮復回觀，人人具此如來體。", "至心持誦法華經，彈指真塔當出現。"]'),
('d7b080dd-a463-4cc8-a648-2f0ec097fbea','富鄭公畫像贊','李綱','宋','宋诗','song-poetry','','[]','天下達德，惟仁智勇。',160,'全唐诗/poet.song.90000.json','["天下達德，惟仁智勇。", "合之成體，散之致用。", "巖巖富公，備此三德。", "直道不回，以相王國。", "其智伊何，見于使虜。", "敷陳利害，以悟其主。", "歡盟至今，莫敢予侮。", "其仁伊何，見于救災。", "饑民如雲，襁負以偕。", "法簡惠周，垂訓将來。", "何以行兹，斷以勇克。", "衆人所懼，公獨不惑。", "奪虜之氣，厲色折之。", "賑民之饑，誠意活之。", "我生後公，今覿厥象。", "丹青載傳，朝夕是仰。"]'),
('019d0f59-8cde-417c-bf30-619194d84ed1','如如軒贊','李綱','宋','宋诗','song-poetry','','[]','華屋千楹，貪夫所娱。',77,'全唐诗/poet.song.90000.json','["華屋千楹，貪夫所娱。", "一念休歇，袤丈有餘。", "是軒廓然，含容太虚。", "森羅萬象，體自如如。", "道人何爲，於焉宴居。", "動静語默，隨時捲舒。", "蓋将即此以善已而，又以示其徒者歟。"]'),
('a6c03e5e-e466-4cc7-895e-f68aaac77360','御書草聖千文贊','李綱','宋','宋诗','song-poetry','','[]','伏羲畫卦，人文以成。',240,'全唐诗/poet.song.90000.json','["伏羲畫卦，人文以成。", "書契之作，以代結繩。", "篆籕而降，秦隸乃興。", "規摹楷法，有真有行。", "衆妙且美，萃于兹草。", "疇克工之，心悟筆到。", "芝靖羲獻，主盟此道。", "自昔英主，鮮不自好。", "惟漢光武，投戈講藝。", "有唐太宗，筆蹟奇秘。", "底綏大業，實資勇智。", "游戲翰墨，乃其餘亊。", "於穆天子，允武允文。", "武定禍亂，文該典墳。", "萬機之餘，縱筆怡神。", "作此草聖，前無古人。", "人亦有言，心正筆正。", "妙哉心畫，本乎湖静。", "銀鈎鐵紐，蟠屈剛勁。", "雲漢昭回，奎璧輝映。", "如鳥行沙，如蟲蝕木。", "鸞鵠停峙，龍蛇起陸。", "飛電繞樞，垂虹飲谷。", "千變萬態，盪耀心目。"]'),
('2b45539e-6786-4676-917d-db0592f7cc30','龍眠居士畫十六大阿羅漢贊  其一','李綱','宋','宋诗','song-poetry','','[]','佛所印可，大阿闍黎。',40,'全唐诗/poet.song.90000.json','["佛所印可，大阿闍黎。", "隱几合爪，泊然無爲。", "懇請何人，投地作禮。", "不起于坐，應供千里。"]'),
('618e8532-ce79-4429-ab2b-36fe3d4570e6','龍眠居士畫十六大阿羅漢贊  其二','李綱','宋','宋诗','song-poetry','','[]','倚杖于肩，屈指近喙。',40,'全唐诗/poet.song.90000.json','["倚杖于肩，屈指近喙。", "廢經不讀，思第一義。", "大獅子吼，真獅子兒。", "轉秘密藏，其誰能知。"]'),
('93c54cf4-d04d-4317-b1a0-b66c9f25bd8f','龍眠居士畫十六大阿羅漢贊  其三','李綱','宋','宋诗','song-poetry','','[]','叉指膝間，目視霄漢。',40,'全唐诗/poet.song.90000.json','["叉指膝間，目視霄漢。", "意象軒舉，邈無畔岸。", "剛大之氣，塞于天淵。", "俯仰無怍，縱心浩然。"]'),
('1bfa6e45-aeea-4e83-9a7d-d636cacb0f96','龍眠居士畫十六大阿羅漢贊  其四','李綱','宋','宋诗','song-poetry','','[]','華林擾虎，手舉數珠。',40,'全唐诗/poet.song.90000.json','["華林擾虎，手舉數珠。", "馴彼鬰屈，亦用兹乎。", "巨顙脩鱗，能怖童子。", "慈眼視之，毒心自弭。"]'),
('8db656e6-1b19-4680-9831-46c7304a0039','龍眠居士畫十六大阿羅漢贊  其五','李綱','宋','宋诗','song-poetry','','[]','藕花滿缻，蓮房自拆。',40,'全唐诗/poet.song.90000.json','["藕花滿缻，蓮房自拆。", "神通妙用，在于舉拂。", "童子何知，跪觀戲龜。", "六用不藏，使之者誰。"]'),
('a516fdbb-dad7-4998-a827-e761414b9d3f','龍眠居士畫十六大阿羅漢贊  其六','李綱','宋','宋诗','song-poetry','','[]','老矣衰疲，背依禪板。',40,'全唐诗/poet.song.90000.json','["老矣衰疲，背依禪板。", "讀經可爲，聊用遮眼。", "植膝垂足，獅子銜花。", "杜其德機，豈有斯耶。"]'),
('158b4d76-ca6b-4d97-97db-61b2300ce867','龍眠居士畫十六大阿羅漢贊  其七','李綱','宋','宋诗','song-poetry','','[]','寶珠騰空，光焰璀璨。',40,'全唐诗/poet.song.90000.json','["寶珠騰空，光焰璀璨。", "諦玩無斁，有見皆幻。", "堂堂風儀，龍象之姿。", "靈杵寶鐸，往将加持。"]'),
('041fc89f-4984-4b5e-bf84-f61566910bc8','龍眠居士畫十六大阿羅漢贊  其八','李綱','宋','宋诗','song-poetry','','[]','本無戒持，何嘗有破。',40,'全唐诗/poet.song.90000.json','["本無戒持，何嘗有破。", "方便爲說，三世因果。", "服飾煒然，王者之妃。", "前跪諦聽，善思念之。"]'),
('aca3ad54-884c-4ca9-88ee-068a777e2bee','龍眠居士畫十六大阿羅漢贊  其九','李綱','宋','宋诗','song-poetry','','[]','龍魚秘怪，各有佛性。',40,'全唐诗/poet.song.90000.json','["龍魚秘怪，各有佛性。", "散花投經，出沒游泳。", "具大悲心，平等施之。", "往因妙力，人天之資。"]'),
('96215945-0492-4597-8ae1-3e7980c00aed','龍眠居士畫十六大阿羅漢贊  其一○','李綱','宋','宋诗','song-poetry','','[]','長松森然，虬枝拂天。',40,'全唐诗/poet.song.90000.json','["長松森然，虬枝拂天。", "支頤據木，仰睇玄猿。", "竹樹之間，方虛禪座。", "我欲攝衣，往補其處。"]'),
('7a11d390-e31f-4c3c-9e02-76e2e0bbd9b7','龍眠居士畫十六大阿羅漢贊  其一一','李綱','宋','宋诗','song-poetry','','[]','宴坐便安，支頤握拳。',40,'全唐诗/poet.song.90000.json','["宴坐便安，支頤握拳。", "一念不波，靈臺湛然。", "婉彼胎禽，就掌取食。", "了無驚猜，馴承恩力。"]'),
('5868fcb6-131d-4e45-bc15-85a4ebc83c1f','龍眠居士畫十六大阿羅漢贊  其一二','李綱','宋','宋诗','song-poetry','','[]','敷座親密，便于笑語。',40,'全唐诗/poet.song.90000.json','["敷座親密，便于笑語。", "懷抱之適，怡然相顧。", "瀝彼缾液，注于掌中。", "普潤四大，一滴之功。"]'),
('bc881e89-ba25-4eb6-898b-bc839eb15cc6','龍眠居士畫十六大阿羅漢贊  其一三','李綱','宋','宋诗','song-poetry','','[]','俯身說法，未能忘言。',40,'全唐诗/poet.song.90000.json','["俯身說法，未能忘言。", "無量妙義，見于指端。", "童子茗供，竹間治具。", "滌煩消渴，惟此之故。"]'),
('51b148d0-f5f6-43a4-a340-2eac67490ce4','龍眠居士畫十六大阿羅漢贊  其一四','李綱','宋','宋诗','song-poetry','','[]','麌麌群鹿，出于巖端。',40,'全唐诗/poet.song.90000.json','["麌麌群鹿，出于巖端。", "植杖倚松，寓目縱觀。", "風度凝然，萬法皆了。", "去髪留髭，豈無所表。"]'),
('55825519-c9db-4902-89a5-77f8d26b930d','龍眠居士畫十六大阿羅漢贊  其一五','李綱','宋','宋诗','song-poetry','','[]','適從何來，遊歷于此。',40,'全唐诗/poet.song.90000.json','["適從何來，遊歷于此。", "大空斕斑，負經以侍。", "有偉衣冠，山川之神。", "旌麾戈甲，其從如雲。"]'),
('3ca06506-6f80-4ea5-8191-46f5677db71a','龍眠居士畫十六大阿羅漢贊  其一六','李綱','宋','宋诗','song-poetry','','[]','巖谷窈窕，林芿扶疏。',40,'全唐诗/poet.song.90000.json','["巖谷窈窕，林芿扶疏。", "瀑布淙射，蛇蟲之居。", "衲帔蒙頭，安然入定。", "孰能出之，其獨也正。"]'),
('7eecd60e-445b-4cc2-bffb-2df4c59bae3a','保寧禪師真贊','李綱','宋','宋诗','song-poetry','','[]','此是保寧風度，具眼衲僧試覷。',56,'全唐诗/poet.song.90000.json','["此是保寧風度，具眼衲僧試覷。", "面孔雖然醜拙，肚裏非常峭措。", "佛祖一口吞盡，問着當下休去。", "却說梁谿覓贊，大小一場露布。"]'),
('64261437-c9e3-4b7a-b820-955af953f1fa','王摩詰畫渡水羅漢贊','李綱','宋','宋诗','song-poetry','','[]','阿羅漢具大神通，飛錫凌空如履實。',160,'全唐诗/poet.song.90000.json','["阿羅漢具大神通，飛錫凌空如履實。", "渺然巨浸與天永，戲躡一杯能徑渡。", "云何溪澗咫尺間，乃有種種難涉相。", "前者己濟氣怡然，後者将涉有難色。", "老病扶攜壯者負，足探策引褰衣裾。", "秘其神力不示人，如畏黄蘖所訶責。", "我觀一切諸有情，咸具神通并妙用。", "空中示現十八變，正眼觀時非吉祥。", "善哉摩詰老畫師，能以毫墨作佛亊。", "稽首十六大聲聞，皆悉回心等正覺。"]'),
('8318a015-7ff1-4f08-9153-98999e7266be','雪峰了禪師真贊','李綱','宋','宋诗','song-poetry','','[]','粹然而深，如玉在山而珠在淵。',92,'全唐诗/poet.song.90000.json','["粹然而深，如玉在山而珠在淵。", "頎然而長，如野鶴之處雞群。", "謂是爲了，四大假合，何者是真。", "謂是非了，五峰秀出，望之儼然。", "道與之貌，丹青所傳，其有不得而傳者耶。", "皓月普分千水影，清光常滿一輪中。"]'),
('45e0d648-46e5-47ee-b5cf-61b28b870aa4','顔魯公畫像贊','李綱','宋','宋诗','song-poetry','','[]','英英魯公，人中之龍。',160,'全唐诗/poet.song.90000.json','["英英魯公，人中之龍。", "爲唐宗臣，見危納忠。", "巨盗起燕，朔部風從。", "獨嬰孤城，以抗其鋒。", "功雖不終，志實可則。", "間關造朝，號爲耆德。", "糾繆繩愆，毅然正色。", "姦邪媚之，擯使去國。", "蹇蹇匪躬，險夷一節。", "迨其耄年，奉使希烈。", "氣沮兇逆，誠貫金鐵。", "身雖可隕，名不可滅。", "巖巖高堂，榜曰忠義。", "非公遺像，其孰當置。", "登斯堂者，宜仰而畏。", "師友其人，無公是愧。"]'),
('b53e171b-0b4e-4161-91af-1d8dfbc03f89','故贈諫議大夫了齋陳公真贊','李綱','宋','宋诗','song-poetry','','[]','如玉之溫，有睟其容。',90,'全唐诗/poet.song.90000.json','["如玉之溫，有睟其容。", "如山之峙，有主其中。", "論事有蓍龜之審，知人如衡鑑之公。", "金百鍊而不耗，水萬折而必東。", "置死生于一拾，會理事而皆融。", "吾不知其誰氏之學，混儒釋而爲宗。", "茲其所以爲了翁者歟。"]'),
('f6822475-a88b-4efd-aa9a-0c841fb5af91','佛日杲禪師真贊','李綱','宋','宋诗','song-poetry','','[]','聞佛日之名而未識其面，見佛日之相而不聞其言。',151,'全唐诗/poet.song.90000.json','["聞佛日之名而未識其面，見佛日之相而不聞其言。", "心契神交，未識面可也。", "目擊道存，不聞言可也。", "如水中月，雖非實見，已有清凉之意。", "如獅子吼，雖未發聲，已有畏仰之心。", "自非真是，恁麽人辦得恁麽事。", "衆所推許，疇克爾耶。", "雖然，孤峰頂上訶佛罵祖，彼佛日也。", "一幅丹青默然無說，此佛日也。", "孰是孰非，必有明眼人能辨之者。", "咄！。"]'),
('a115e564-5754-42f7-9896-cc5e66122e29','淵聖皇帝題十八學士頌','李綱','宋','宋诗','song-poetry','','[]','英英策府，十八學士。',160,'全唐诗/poet.song.90000.json','["英英策府，十八學士。", "森如驥騄，才德兼備。", "太宗御之，六轡耳耳。", "嘶風籋雲，一日千里。", "丹青之妙，寫于縑素。", "千載風流，遇之旦暮。", "於穆淵聖，天縱多能。", "遊戲翰墨，識其姓名。", "人物圖繪，及兹宸藻。", "是爲三絕，萬世之寶。", "沙漠苦寒，翠華未還。", "傷心北顧，喟其涕澘。", "安得傑才，如彼諸子。", "扶翊中微，國勢振起。", "豈無趙卒，爲御以歸。", "老臣衰疾，跂而望之。"]'),
('2ef7238d-2477-4ec7-8ac4-45bcb870230c','秋風辭','李綱','宋','宋诗','song-poetry','','[]','秋風起兮黄葉飛，遠客異土兮未能歸。',74,'全唐诗/poet.song.90000.json','["秋風起兮黄葉飛，遠客異土兮未能歸。", "白露降兮悴衆芳，懷美人兮悵難忘。", "變星霜兮阻山河，風異響兮水增波。", "遡明月兮發浩歌，群陰積兮浮雲多。", "歲聿云暮兮奈愁何。"]'),
('f3bd22fb-f6a1-4ddb-b2ef-3284455adce2','遊王原山','李綱','宋','宋诗','song-poetry','','[]','假道廬陵郡，薄遊青原山。',241,'全唐诗/poet.song.90000.json','["假道廬陵郡，薄遊青原山。", "山空松桂香，殿閣森回環。", "三泉湛寒玉，洗我襟抱煩。", "況與二三子，杖屨同躋攀。", "笑觀顔黄碑，筆勢驚飛騫。", "昔也有高士，妙指窮玄關。", "心花五葉開，法炬千燈傳。", "當時尋思人，一見心不瀾。", "至今三百載，水碧山蒼然。", "嗟我愛山水，所至必縱觀。", "聊於戎馬際，偷此半日閑。", "適野慕裨諶，命駕睎謝安。", "規模寂寞濱，指揮衝談笑閒。", "矧茲湖湘盜，鉤鋤本元元。", "弄兵潢池中，豈足勞戈鋋。", "願宣天子德，往使疲瘵歡。", "龔遂理渤海，營平破先零。", "威靈及襄漢，恢復從荆蠻。", "國恩粗可報，乞身返田園。", "持此問祖師，神交當解顔。"]'),
('6a80fbee-0426-481c-bdb5-01e1401e4656','讀書堂','李綱','宋','宋诗','song-poetry','','[]','靈洞水清僊可訪，南巖木古佛同居。',32,'全唐诗/poet.song.90000.json','["靈洞水清僊可訪，南巖木古佛同居。", "公餘問佛尋僊了，贏得安閑剩讀書。"]'),
('91f3cd37-904e-4639-8bcf-f7b4c1e62a5f','題李伯時三教圖卷  其一','李綱','宋','宋诗','song-poetry','','[]','祖師西來，億劫誰伍。',40,'全唐诗/poet.song.90000.json','["祖師西來，億劫誰伍。", "眷焉摩尼，燭此下土。", "滄海津梁，脫離幽苦，至哉流宗，以振聾瞽。"]'),
('1f4b859d-5b01-4ae0-99df-ee601bff6ab0','題李伯時三教圖卷  其二','李綱','宋','宋诗','song-poetry','','[]','丈人之德，藐焉猶龍。',40,'全唐诗/poet.song.90000.json','["丈人之德，藐焉猶龍。", "吐納新故，嬰兒在中。", "鼎水靜綠，飛丹夜紅。", "大德不德，河上遺蹤。"]'),
('968f0941-3a3a-4455-9449-8795bd5d4d4e','題李伯時三教圖卷  其三','李綱','宋','宋诗','song-poetry','','[]','素王峨峨，萬世所師。',40,'全唐诗/poet.song.90000.json','["素王峨峨，萬世所師。", "太和元氣，逝者如斯。", "吾儕小人，有喙何施。", "稽首頓首，念茲在茲。"]'),
('8aaabb61-e0d6-48e4-8935-1c4359155cdc','句','李綱','宋','宋诗','song-poetry','','[]','假使黑風漂蕩去，不妨乘興訪蓬萊。',16,'全唐诗/poet.song.90000.json','["假使黑風漂蕩去，不妨乘興訪蓬萊。"]'),
('16c8274e-7b72-4b9c-b0f4-a8b53f6984f9','句','錢申伯','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.90000.json','["無正文。"]'),
('e8ff1e2b-c8f4-4ab9-b9bc-a49544a37418','寶劍聯句','錢申伯','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.90000.json','["無正文。"]'),
('6cc26d98-3154-4b23-8b53-be67bb304a39','寶劍聯句','叔正','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.90000.json','["無正文。"]'),
('bb842eef-d51b-45ed-a759-e1150107c654','次韻德升尚書永慶閣後觀梅之作','綦崇禮','宋','宋诗','song-poetry','','[]','託根層石下，閟艶重檐陰。',96,'全唐诗/poet.song.90000.json','["託根層石下，閟艶重檐陰。", "愛日少回照，淑氣潛相尋。", "入牖暗香上，俯欄重蘤深。", "孤絕逈多態，繁穠徒滿林。", "怪君獨吟賞，却酒不爲斟。", "應曾共花約，遂擬合朋簪。", "雪意殊未已，寒英虞見侵。", "聞花正芬馥，相向一披襟。"]'),
('56b7c574-480c-45f9-9e5a-75449ee9afda','次韻國佐侍郎即事','綦崇禮','宋','宋诗','song-poetry','','[]','雪霽春未和，寒雲惨多陰。',96,'全唐诗/poet.song.90000.json','["雪霽春未和，寒雲惨多陰。", "同鄉有期約，學海慵沿尋。", "吾衰今得友，晚交契則深。", "歲寒見松柏，茂悦依同林。", "倚市人所賤，在山泉可斟。", "蟠桃着實遲，勸我簡蒿簪。", "吟窗擁翠娥，分定那得侵。", "愧笑領君意，取酒問胸襟。"]'),
('047d86d5-5461-4269-b540-ee1d78051c17','次韻國佐二詩  其一','綦崇禮','宋','宋诗','song-poetry','','[]','覊旅念鄉縣，衰遲驚歲陰。',96,'全唐诗/poet.song.90000.json','["覊旅念鄉縣，衰遲驚歲陰。", "交朋慰幽獨，詩酒相追尋。", "求盟敵難弭，助順天意深。", "邊書息障候，喜氣到山林。", "聯裾得良會，舉白毋緩斟。", "話舊諠笑語，拚醉欹冠簪。", "梁塵歌響墮，玉頰酒紅侵。", "殷勤捧杯意，不惜污羅襟。"]'),
('9572a7ab-44d9-480d-9b18-d036852fdc82','次韻國佐二詩  其二','綦崇禮','宋','宋诗','song-poetry','','[]','官閑一何幸，安坐閲光陰。',96,'全唐诗/poet.song.90000.json','["官閑一何幸，安坐閲光陰。", "世事來無端，循環那可尋。", "名髙毁易至，官達憂常深。", "豈敢慕華屋，且願依中林。", "主人真好客，置酒每共斟。", "里仁知有托，計决擬投簪。", "樂飲不泰至，歸夜從深侵。", "梅英苦留戀，著人香滿襟。"]'),
('146b0633-e101-4125-8376-7dc8aae3746e','再賦一首趁韻信筆初無定意也','綦崇禮','宋','宋诗','song-poetry','','[]','妍詞少勁氣，直表無曲陰。',96,'全唐诗/poet.song.90000.json','["妍詞少勁氣，直表無曲陰。", "勸百豈救一，枉尺焉取尋。", "世路務爭險，人情難測深。", "漁樵各有侣，英俊自成林。", "藥苦病所利，酒多狂莫斟。", "珠投防按劍，玉折戒磨簪。", "願持松柏操，甘受雪霰侵。", "途窮但回步，何用涕沾襟。"]'),
('ba3f9c0e-5a0c-4f53-9a5f-ecf3942ed294','再次前韻','綦崇禮','宋','宋诗','song-poetry','','[]','笙簧樂富貴，等是老墻陰。',96,'全唐诗/poet.song.90000.json','["笙簧樂富貴，等是老墻陰。", "汲汲不知止，悠悠何處尋。", "所嗟天賦薄，未報國恩深。", "一夢遊帝闕，九年辭禁林。", "官廩尚可飽，村醪時自斟。", "不嫌泥土足，懶拂塵埃簪。", "窮巷春雪霽，寒檐朝日侵。", "意行何所適，還欲訪同襟。"]'),
('fd47e7cb-5d5e-4b3a-9883-c6dcf439fad7','德升尚書出示歲除用韋蘇州韻前後二篇及兩郎屬和粲然盈軸賞歎之餘有感於中亦輙次韻書山居一時事  其一','綦崇禮','宋','宋诗','song-poetry','','[]','寒宵送徂歲，青燈照華髪。',72,'全唐诗/poet.song.90000.json','["寒宵送徂歲，青燈照華髪。", "天時自代謝，人事更治忽。", "聖朝今中興，正朔幾書月。", "未作故鄉歸，又見新花發。", "稚女巧娛予，剪綵粧風物。", "一釂婪尾觴，頺然百憂歇。"]'),
('8c7f4ac0-9150-4f90-ab60-3ea5b2e2fce4','德升尚書出示歲除用韋蘇州韻前後二篇及兩郎屬和粲然盈軸賞歎之餘有感於中亦輙次韻書山居一時事  其二','綦崇禮','宋','宋诗','song-poetry','','[]','兒童喜時節，老大悲齒髪。',72,'全唐诗/poet.song.90000.json','["兒童喜時節，老大悲齒髪。", "流光難把玩，百年如倐忽。", "夜燈猶故歲，晨燎已端月。", "回首名宦途，常虞駭機發。", "今來對青山，安坐見春物。", "得失孰多少，且使寸心歇。"]'),
('d4e4452f-0bed-414c-b9b0-858a0e1fdbc2','奉紀','綦崇禮','宋','宋诗','song-poetry','','[]','八座近黄扉，三公宜黑髮。',72,'全唐诗/poet.song.90000.json','["八座近黄扉，三公宜黑髮。", "用舍豈自謀，機緘何翕忽。", "一麾遽出守，雙溪厭風月。", "江海今就閑，議論猶英發。", "大厦終須材，虚舟聊應物。", "勝覽莫辭頻，君騶寧久歇。"]'),
('17232048-2f04-460d-9f2f-66bf072e3f90','自述','綦崇禮','宋','宋诗','song-poetry','','[]','箕裘紹弓冶，不絕僅如髪。',72,'全唐诗/poet.song.90000.json','["箕裘紹弓冶，不絕僅如髪。", "遇主當艱虞，持身敢怠忽。", "謬隨供奉班，更直淹歲月。", "出領東諸侯，羽書憂調發。", "丘壑從素心，朝廷憐舊物。", "桑榆不自收，我駕將焉歇。"]'),
('3badda9f-29b3-4f96-a356-5fb3afba43c2','和東園黄香梅之作因復勸遊','綦崇禮','宋','宋诗','song-poetry','','[]','寒梅殘幾枝，插花無點髪。',72,'全唐诗/poet.song.90000.json','["寒梅殘幾枝，插花無點髪。", "僧房不得地，飄零人所忽。", "谿風晚來急，尋香堆碎月。", "不料東城春，嬌黄方秀發。", "新詩寓佳賞，留情寧一物。", "芳卉滿春山，籃輿來莫歇。"]'),
('36b8e78f-0365-4e84-8bd1-a261a4116757','和李元叔秋懷  其一','綦崇禮','宋','宋诗','song-poetry','','[]','移居寄城郭，閴如在郊坰。',120,'全唐诗/poet.song.90000.json','["移居寄城郭，閴如在郊坰。", "百卉暮凋翠，兩山常對青。", "兒童漸吳語，氣俗易薰蒸。", "喜聞淮師捷，神武暢威稜。", "叛寇不足滅，四夷其來庭。", "十年亂離厄，永夜鄉關情。", "庶見丘墓邦，敢貪簪紱榮。", "故人致尺素，笑烹雙鯉赬。", "清切哦十詠，飄零乖一觥。", "歲晚良可會，濟世須時英。"]'),
('39b58f99-0fd0-46cc-bc1d-69ce0c90b65f','和李元叔秋懷  其二','綦崇禮','宋','宋诗','song-poetry','','[]','杜門身塊坐，息念心灰死。',120,'全唐诗/poet.song.90000.json','["杜門身塊坐，息念心灰死。", "香火遠祠庭，文書凈窗几。", "治劇力豈任，投閑計良是。", "深慚未報恩，尚費官倉米。", "吾儕晚聞道，錯以名爲市。", "那知標榜著，便有謗尤起。", "如君取已多，蚤合登貴仕。", "况彼青箱業，家聲在人耳。", "草草脱廌冠，重升未應止。", "但願毋近名，嘉言終合指。"]'),
('f9639834-9d85-4d97-a292-a7f1e6a8a92e','送濰州詹倅五首  其一','綦崇禮','宋','宋诗','song-poetry','','[]','矯矯摩天姿，青雲久垂翅。',48,'全唐诗/poet.song.90000.json','["矯矯摩天姿，青雲久垂翅。", "别乘屈王祥，海隅賴康濟。", "峻節回郡政，深仁賑民匱。", "胡不三年留，斯民且安慰。"]'),
('9d26b393-d389-46a2-92ac-fc2c4f5a01c1','送濰州詹倅五首  其二','綦崇禮','宋','宋诗','song-poetry','','[]','天子有使指，借問何官曹。',48,'全唐诗/poet.song.90000.json','["天子有使指，借問何官曹。", "轉粟泝洛津，帆檣連萬艘。", "大臣進所知，得此千人豪。", "扶搖一借便，看上青雲髙。"]'),
('bb5399cb-9eb7-4562-baf3-da9703b1ea42','送濰州詹倅五首  其三','綦崇禮','宋','宋诗','song-poetry','','[]','東風催去旆，南浦傷離情。',48,'全唐诗/poet.song.90000.json','["東風催去旆，南浦傷離情。", "攀轅何紛紛，曉日來傾城。", "中有韋布士，雪涕揮縱横。", "欲識何爲者，爲言門下生。"]'),
('1581594b-18a0-4721-a7b4-c63c2b30ad59','送濰州詹倅五首  其四','綦崇禮','宋','宋诗','song-poetry','','[]','先達收人材，輕重在題目。',48,'全唐诗/poet.song.90000.json','["先達收人材，輕重在題目。", "我出一何幸，青眼深回矚。", "聲名士所貴，推挽亦已足。", "母老憐我貧，家事猶省錄。"]'),
('470e485d-dfdc-4dd0-9761-ee72c3eb37b4','送濰州詹倅五首  其五','綦崇禮','宋','宋诗','song-poetry','','[]','人生樂知己，見遇况國士。',48,'全唐诗/poet.song.90000.json','["人生樂知己，見遇况國士。", "吾身不激昂，孰爲報恩子。", "薦達有往來，登門願誰始。", "寄謝魏王孫，丹心亦如此。"]'),
('9103b9e3-11a2-409f-806c-d3aa866aac90','蒙成大亨分送紫蘇且以前書有戲謔語垂示解嘲輙次元韻','綦崇禮','宋','宋诗','song-poetry','','[]','先生昔爲吏，敏政便劇繁。',288,'全唐诗/poet.song.90000.json','["先生昔爲吏，敏政便劇繁。", "利刅無錯節，大邑如烹鮮。", "民曹與廷尉，衆紛常裕然。", "胡爲棄九卿，歲晚來灌園。", "分陰在所惜，寸地不忍閑。", "草木苟有用，豈憚遠移根。", "從來憂世心，中懷百慮煎。", "栽梅期鼎實，無取寒花妍。", "植竹待威鳯，肯羡冥鴻騫。", "此志未云遂，亦足留風烟。", "山泉釀賢聖，艶曲聼嬋娟。", "引酌梅竹下，醉臥雲峰前。", "何以解其酲，玉笋捧甌圓。", "香泛紫蘇飲，醒心清可憐。", "洗滌麴糵昏，還觀神明全。", "先生得此物，手種當春天。", "耘培供採掇，內熱常得痊。", "云何失滋茂，無乃人力愆。", "因疑課督功，多稼移大田。", "循例猶見分，乞隣問東阡。", "不耐作戲語，解嘲來巨篇。", "珠玉隱光彩，入城驚市廛。", "風霜已落木，洞户宜垂氈。", "何當擁爐夜，一樽同笑言。"]'),
('d05e75c2-f33c-4999-bc94-131e689a262a','次韻成季尚書喜雪','綦崇禮','宋','宋诗','song-poetry','','[]','衰年憂患百侵凌，胸次聊憑詩澡雪。',96,'全唐诗/poet.song.90000.json','["衰年憂患百侵凌，胸次聊憑詩澡雪。", "寄情山水時自娛，不求賞音絃莫絕。", "身顯豈忘莊舄吟，量能盍止周師任。", "閑中之趣難具陳，赤城慵臥七回春。", "終南捷徑猶可疑，海濱老矣誰見稱。", "積雪加寒固應爾，且爲北人湯餅喜。"]'),
('25671f45-522e-4e47-8951-47a620578a5d','用晦顯謨近出長篇德升尚書遂已賡和輙牽鄙思以繼二公之後兼簡行之待制','綦崇禮','宋','宋诗','song-poetry','','[]','赤城自昔佳山水，遊宦何曾論道里。',336,'全唐诗/poet.song.90000.json','["赤城自昔佳山水，遊宦何曾論道里。", "朅來五載著閑身，天假衰年幸如此。", "偶逢人面即成親，信美那知非我里。", "相從晚得世家賢，風流未泯典刑全。", "豫章杞梓雜蘭玉，向來人物常推先。", "一門卿相有三四，功名並列青瑶鎸。", "憔悴祗今餘此老，北闕薦書誰復草。", "忘懷驟喜肝膽傾，學道故宜容鬢好。", "江湖歷走到海濱，可怕鯨波風浩浩。", "平時所寶非瓊瑰，生涯都付瓶與罍。", "客至輙留盡歡適，玉山不覺欹崔嵬。", "醒來默坐參佛祖，餘酲宿障隨驅排。", "衡門我亦棲遲久，却視華途慚俊茂。", "山中麋鹿會同羣，客裏妻奴得相守。", "感君向我意甚真，杯酒招邀惟恐後。", "往還况此足親知，清談雅集每忘疲。", "尚書舊信心如水，京兆猶傳政不私。", "共尋泉石豈無伴，却上雲霄知有基。", "顧我終焉奚所欲，一丘一壑志願足。", "勝遊非遠閑日多，秋節正凉新酒熟。", "東州西縣君何求，請解行包停去躅。"]'),
('63d36655-ad93-4229-a56c-9a20f283efd7','故李察院挽歌辭二首  其一','綦崇禮','宋','宋诗','song-poetry','','[]','學古方從仕，投閑遂屏居。',48,'全唐诗/poet.song.90000.json','["學古方從仕，投閑遂屏居。", "聲華芸省舊，風采柏臺餘。", "黄壤歸何速，青雲志莫舒。", "推財均室盡，遺子有家書。"]'),
('9d64dfa3-e62e-43ac-b7a0-6b9007a21e83','故李察院挽歌辭二首  其二','綦崇禮','宋','宋诗','song-poetry','','[]','有才曾少試，無命可深尤。',48,'全唐诗/poet.song.90000.json','["有才曾少試，無命可深尤。", "憲府初峨豸，滄溟遽狎鷗。", "盛年嗟未老，多病忽先秋。", "勤學平生事，萱堂孰解憂。"]'),
('c9b9f52e-c414-4f02-8819-06effa4ba25a','和人見寄','綦崇禮','宋','宋诗','song-poetry','','[]','江海同爲客，山林不並居。',48,'全唐诗/poet.song.90000.json','["江海同爲客，山林不並居。", "經時占喜鵲，今日剖雙魚。", "擁鼻還成詠，撐腸未廢書。", "孤吟聊自遣，誰復借吹嘘。"]'),
('ab7d7478-1987-4e73-8500-94de5f026757','故丞相高平范公挽歌辭三首  其一','綦崇禮','宋','宋诗','song-poetry','','[]','遇主方英妙，當朝獨老成。',48,'全唐诗/poet.song.90000.json','["遇主方英妙，當朝獨老成。", "小車何耄耋，前席起公卿。", "感會真千載，哀榮止半生。", "傷心埋玉處，愁霧鎖佳城。"]'),
('28617e8e-2f71-4c64-b279-36db0907b890','故丞相高平范公挽歌辭三首  其二','綦崇禮','宋','宋诗','song-poetry','','[]','帷幄言猶在，山林迹已遷。',48,'全唐诗/poet.song.90000.json','["帷幄言猶在，山林迹已遷。", "登庸疑早貴，福艾欠長年。", "渾厚風神粹，恢宏德度全。", "直應天奪速，何物恨鳶肩。"]'),
('fe1657b9-3960-4a8e-b5cb-f04fb7bfcb39','故丞相高平范公挽歌辭三首  其三','綦崇禮','宋','宋诗','song-poetry','','[]','憶昔金鑾直，天顔喜色新。',48,'全唐诗/poet.song.90000.json','["憶昔金鑾直，天顔喜色新。", "草麻慚大手，命相得良臣。", "內賜充懷袖，廷敭聳搢紳。", "秪今餘典册，那復見斯人。"]'),
('38c78941-06a4-4515-ad6b-55574128ae17','故丞相吕成公挽歌詩辭五首  其一','綦崇禮','宋','宋诗','song-poetry','','[]','翊戴興炎祚，權宜倣晉都。',48,'全唐诗/poet.song.90000.json','["翊戴興炎祚，權宜倣晉都。", "關中蕭相國，江左管夷吾。", "感會逢英主，拘攣鄙腐儒。", "人間留不得，去與列星俱。"]'),
('9a44c589-5844-4597-9132-1cefb9e9bbe5','故丞相吕成公挽歌詩辭五首  其二','綦崇禮','宋','宋诗','song-poetry','','[]','憶昨初南渡，人情正自危。',48,'全唐诗/poet.song.90000.json','["憶昨初南渡，人情正自危。", "起平王室亂，笑指楚囚悲。", "投箠來方鋭，乘桴計不疑。", "還師期克敵，遺恨失斯時。"]'),
('38660a0e-adee-41ff-ae0c-2c045d289bcc','故丞相吕成公挽歌詩辭五首  其三','綦崇禮','宋','宋诗','song-poetry','','[]','仗鉞除君側，披荆立本朝。',48,'全唐诗/poet.song.90000.json','["仗鉞除君側，披荆立本朝。", "規模收廟勝，威略動天驕。", "賢業留黄閣，閑情在午橋。", "傷心桃李徑，霜霰日蕭條。"]'),
('3e630d82-06bc-43b7-8132-7d7203ea5ee0','故丞相吕成公挽歌詩辭五首  其四','綦崇禮','宋','宋诗','song-poetry','','[]','名與功髙大，身爲世重輕。',48,'全唐诗/poet.song.90000.json','["名與功髙大，身爲世重輕。", "初傳都督令，已懾敵人情。", "門謝三千客，胸包十萬兵。", "聖王分陜意，歎息失長城。"]'),
('d4502478-3969-4552-a47a-d09dfe4c164f','故丞相吕成公挽歌詩辭五首  其五','綦崇禮','宋','宋诗','song-poetry','','[]','齪齪誠何算，堂堂亦已休。',48,'全唐诗/poet.song.90000.json','["齪齪誠何算，堂堂亦已休。", "嗟聞閉東閣，忍復過西州。", "會送宜千乘，歸藏但一丘。", "往來埋玉恨，清淚漲溪流。"]'),
('41e71f85-0952-4b91-9ee1-207f7cc5f993','扈從書事','綦崇禮','宋','宋诗','song-poetry','','[]','扈從官班近，囏難報效微。',96,'全唐诗/poet.song.90000.json','["扈從官班近，囏難報效微。", "又同陪法駕，復共著征衣。", "舉目江山好，傷心井社非。", "何當戎馬定，却作故鄉歸。", "負郭田園美，迎霜雉兔肥。", "風塵嗟澒洞，夢寐悵依稀。", "聖主興皇祚，羣公翊政機。", "時平當自劾，還採故山薇。"]'),
('82093c4f-4a19-421c-88c9-406253397618','入雁蕩山','綦崇禮','宋','宋诗','song-poetry','','[]','傑峰秀嶺競崔巍，緩引籃舁不用催。',64,'全唐诗/poet.song.90000.json','["傑峰秀嶺競崔巍，緩引籃舁不用催。", "一徑靈虚飛鳥上，四圍春色畫屏開。", "鹿門未有携家便，雁蕩何妨築室來。", "已上封章乞閑散，勿令俗駕却輕迴。"]'),
('cf29a1fc-e3a1-438d-82ec-769b629c829f','德升勸酒爲已懋尚書壽予即席賦長句以代俳諧','綦崇禮','宋','宋诗','song-poetry','','[]','禁掖東西曾並直，鑾坡先後亦聯名。',64,'全唐诗/poet.song.90000.json','["禁掖東西曾並直，鑾坡先後亦聯名。", "那知白髪歸田舍，却見朱轓蒞海城。", "往事回頭真是夢，流年屈指只堪驚。", "一盃相屬公應悉，冷煖難移故舊情。"]'),
('01182f05-1b0c-4cf1-aa23-56a0b0c63b75','國佐侍郎併示佳篇謹復次韻','綦崇禮','宋','宋诗','song-poetry','','[]','漂流歲晚憐羈跡，慷慨平時仰令名。',64,'全唐诗/poet.song.90000.json','["漂流歲晚憐羈跡，慷慨平時仰令名。", "問俗卜隣依里社，登瀛得友自都城。", "諌書昔睹言常用，偉論今傳衆尚驚。", "未足朝眠何所事，良辰詩酒最關情。"]'),
('73035792-9bf7-4a4e-beae-9573da9e97dc','見德升國佐酬贈歎愛不已用復次韻','綦崇禮','宋','宋诗','song-poetry','','[]','常伯二卿俱擅美，憲臺諌省各知名。',64,'全唐诗/poet.song.90000.json','["常伯二卿俱擅美，憲臺諌省各知名。", "英詞宜和南薰曲，雅意難追北斗城。", "元禮風聲誰得御，孟公姓字坐皆驚。", "聯肩接袂予何幸，一笑從容每盡情。"]'),
('2d1d41e3-cb42-45dc-be92-0b8717de4cf7','賦東城梅花示哲上人','綦崇禮','宋','宋诗','song-poetry','','[]','一枝冷落爲誰開，欲遣寒香入酒杯。',64,'全唐诗/poet.song.90000.json','["一枝冷落爲誰開，欲遣寒香入酒杯。", "鐵石心腸猶解賦，芝蘭風味合相陪。", "臘前頗訝疏疏見，春盡何妨得得來。", "十里東城不嫌遠，待看山月照徘徊。"]'),
('401193bb-46d2-45e2-845a-239cf67e1ab5','題子正觀察溪風亭二首  其一','綦崇禮','宋','宋诗','song-poetry','','[]','巧據東西面勢雄，兹亭壯觀一園中。',64,'全唐诗/poet.song.90000.json','["巧據東西面勢雄，兹亭壯觀一園中。", "淙淙鳴竇過流水，拂拂虚簷來遠風。", "好解塵纓濯清泚，聊披醉衽望穹窿。", "泠然便欲乘風去，汗漫相期孰與同。"]'),
('a18cf985-35b8-489a-bd6b-9de74eebbbe3','題子正觀察溪風亭二首  其二','綦崇禮','宋','宋诗','song-poetry','','[]','溪上微波起穀紋，凉颸不斷快餘醺。',64,'全唐诗/poet.song.90000.json','["溪上微波起穀紋，凉颸不斷快餘醺。", "飄飄弄袖疑輕舉，馥馥吹花得細聞。", "但羡園林今地主，焉知弓劍舊將軍。", "功名興盡從吾好，白首安閑少似君。"]'),
('7bb6843d-cf93-46d0-b91b-b74df1bf3bf0','德升尚書賦溪風亭二首以題爲韻顧風字某已先作别賦溪字一首','綦崇禮','宋','宋诗','song-poetry','','[]','泉通暗甃瀉清溪，倒影風亭翼瓦齊。',64,'全唐诗/poet.song.90000.json','["泉通暗甃瀉清溪，倒影風亭翼瓦齊。", "借問披襟聆漱玉，何如擐甲聼征鞞。", "相過底厭時揮麈，獨坐應須日杖藜。", "信美那知非我里，倚欄歸路已都迷。"]'),
('abf2d5b8-419d-4d53-a715-03d63054b7ce','題天台山石橋庵院','綦崇禮','宋','宋诗','song-poetry','','[]','林麓陰森徑屈盤，漸驚危步入重巒。',64,'全唐诗/poet.song.90000.json','["林麓陰森徑屈盤，漸驚危步入重巒。", "地分寶刹臨空翠，天設飛梁跨激湍。", "霧暗雲蒸山氣肅，雪翻雷輥水聲寒。", "我來不作多求想，試出神光變現看。"]'),
('e3be672e-d5f3-4ee5-90c6-d0bc042e3b0f','宿獨覺院','綦崇禮','宋','宋诗','song-poetry','','[]','早發招提宿雨晴，征衫猶带夜香清。',64,'全唐诗/poet.song.90000.json','["早發招提宿雨晴，征衫猶带夜香清。", "山藏鳥道疑無路，石觸溪流自有聲。", "適足此時逃世網，收身何日濯塵纓。", "迂疏愧乏論思效，尚得君王記姓名。"]'),
('38b4f91f-e407-45fb-9f67-02beeb3eecb9','故福國夫人挽歌詞  其一','綦崇禮','宋','宋诗','song-poetry','','[]','從夫禮法舊推稱，訓子詩書亦蚤成。',64,'全唐诗/poet.song.90000.json','["從夫禮法舊推稱，訓子詩書亦蚤成。", "烏府盡言知內助，鳯池得位見親榮。", "隙駒不究期頤壽，風木長悲欲飬情。", "厚福尚餘湯沭地，并歸賢嗣作功名。"]'),
('c0078ade-9a63-4783-b8b3-b755845e07fb','故福國夫人挽歌詞  其二','綦崇禮','宋','宋诗','song-poetry','','[]','蜀都旌節繼輝光，象服重來意獨傷。',64,'全唐诗/poet.song.90000.json','["蜀都旌節繼輝光，象服重來意獨傷。", "許國毋辭驅遠馭，懷人忍復舍中堂。", "新阡豈料今同穴，異縣端如在故鄉。", "錯顧飛雲何處是，西山松檟已成行。"]'),
('1cd89ee6-5fc3-40f1-a5ea-c3484fb7410a','奉和德升尚書探梅之什仍用元韻','綦崇禮','宋','宋诗','song-poetry','','[]','題詩曾動何郎興，寄遠猶傳陸凱名。',64,'全唐诗/poet.song.90000.json','["題詩曾動何郎興，寄遠猶傳陸凱名。", "渴見寒英娛北客，共尋春信向東城。", "蜂粘晴蘂應先破，雀啅芳心已盡驚。", "便擬催開爭賦詠，臘中獨使擅幽情。"]'),
('8d9fb70a-2031-4893-bba9-565fa49f6ec0','七月乙丑作記夢詩初不敢示人而私有傳去者德升尚書遽先枉和索元篇','綦崇禮','宋','宋诗','song-poetry','','[]','清夢分明到玉堂，紫衣催引對龍章。',64,'全唐诗/poet.song.90000.json','["清夢分明到玉堂，紫衣催引對龍章。", "似令裁詔移時罷，尚想揮毫半夜忙。", "千里力疲心已息，十年境熟念難忘。", "此生未有酬恩日，坐撚衰髯祗自傷。"]'),
('4168ab71-1b7f-4b64-937c-0ca1b62c9471','再用韻奉謝德升尚書見和且以解嘲','綦崇禮','宋','宋诗','song-poetry','','[]','西風醒夢入秋堂，夢境還空寄短章。',64,'全唐诗/poet.song.90000.json','["西風醒夢入秋堂，夢境還空寄短章。", "妄見徒嗟妨睡美，閑心久謝趁朝忙。", "流年倐忽身今老，榮路斯須味已忘。", "慚愧君詩真戲謔，邯鄲自警亦何傷。"]'),
('1faef627-a491-498a-902e-aa4671fc91d6','德升尚書併示新詩愈富而愈工不勝歎服顧見戲之語不置而自處太謙謹和答以重致解嘲之意','綦崇禮','宋','宋诗','song-poetry','','[]','慶弔從來不下堂，漫勞善頌費雕章。',64,'全唐诗/poet.song.90000.json','["慶弔從來不下堂，漫勞善頌費雕章。", "自嗤夢已空花散，更看詩爲寐語忙。", "論每闊疏時所棄，才稱美秀上難忘。", "我宜屏跡君當起，出處相違恐兩傷。"]'),
('2bab43ad-f988-4d4f-b506-ca7611b75f0a','重擬自賦一首呈德升尚書','綦崇禮','宋','宋诗','song-poetry','','[]','旋葺幽居卜築堂，歸棲不負乞閑章。',64,'全唐诗/poet.song.90000.json','["旋葺幽居卜築堂，歸棲不負乞閑章。", "飲遭田父那辭醉，雨覓漁師未覺忙。", "汲汲功名徒競逐，悠悠身世已兼忘。", "此心真可安江海，免使莊生笑重傷。"]'),
('a1bcef86-ac43-4478-a7a9-5584eabcf5ec','蒙示叙舊之作情眷甚厚不可虚辱輙次元韻愧非所以爲報也','綦崇禮','宋','宋诗','song-poetry','','[]','八座方登政事堂，一麾却佩郡侯章。',64,'全唐诗/poet.song.90000.json','["八座方登政事堂，一麾却佩郡侯章。", "求閑宛轉常虞謗，治劇從容豈厭忙。", "老去昔遊君尚記，夢回陳迹我俱忘。", "相從且共銜杯樂，世路爭名巧中傷。"]'),
('8f6da1a9-4aa7-4f16-90f7-07feaccb6953','奉酬已懋尚書  其一','綦崇禮','宋','宋诗','song-poetry','','[]','紛紛胡騎來無定，整整王師動有名。',64,'全唐诗/poet.song.90000.json','["紛紛胡騎來無定，整整王師動有名。", "已報妖氛掃秦甸，還聞聘使出龍城。", "灼知天意民皆悦，怯聼風聲寇自驚。", "就飬東朝歸駕近，和戎深見聖人情。"]'),
('e67240a2-70c2-4b06-8cdc-44894c635a41','奉酬已懋尚書  其二','綦崇禮','宋','宋诗','song-poetry','','[]','鄉邦甲第常牽興，玉几金甌久記名。',64,'全唐诗/poet.song.90000.json','["鄉邦甲第常牽興，玉几金甌久記名。", "會秉樞機還魏闕，且栽桃李滿春城。", "郊原氣煖花將發，閭里聲和犬不驚。", "勝日假時聊共樂，未應歸隱狥髙情。"]'),
('69b1b895-b7d6-4143-aa85-5f65b8191ae6','和郭傳師歲晚書事','綦崇禮','宋','宋诗','song-poetry','','[]','塵掩龍韜玩具文，雨昏金甲岸綸巾。',64,'全唐诗/poet.song.90000.json','["塵掩龍韜玩具文，雨昏金甲岸綸巾。", "横行漸復思清海，髙臥端來傲翠筠。", "推轂塞垣終用舊，調絲洞户且酬春。", "不辭勝日來追賞，却恐功名要及辰。"]'),
('10ee83db-aa7e-43eb-8da9-2a00d5e03be2','漫成  其一','綦崇禮','宋','宋诗','song-poetry','','[]','生平雅志在林溪，故里塵昏未定棲。',64,'全唐诗/poet.song.90000.json','["生平雅志在林溪，故里塵昏未定棲。", "晚向瓊臺諧問舍，喜當淮塞罷鳴鞞。", "出郊賸喜園亭勝，策杖應須酒榼携。", "隨意一觴兼一詠，醉言無次亦無題。"]'),
('1b2a64db-ce64-4581-9430-4ab65616f32b','漫成  其二','綦崇禮','宋','宋诗','song-poetry','','[]','書迷今古懶不讀，樽列聖賢時一中。',64,'全唐诗/poet.song.90000.json','["書迷今古懶不讀，樽列聖賢時一中。", "顧我本無當世志，愛君真有古人風。", "賜環忽恐歸期促，放盞常嗟樂事空。", "山鹿野麋便茂草，鳯凰終合止梧桐。"]'),
('8061574b-9585-4272-b0c5-a72332b1dd0b','佚老堂爲丞相文安公作  其一','綦崇禮','宋','宋诗','song-poetry','','[]','社稷功名不自賢，小園卜築賞閒年。',64,'全唐诗/poet.song.90000.json','["社稷功名不自賢，小園卜築賞閒年。", "脱遺富貴還身外，收拾芳菲寓目前。", "未息烟塵勞矚望，莫孤風月且留連。", "一時賦詠多奇作，江漢崧髙好共編。"]'),
('7bc7b5ed-67ab-44e4-8956-d82deb9e5e73','佚老堂爲丞相文安公作  其二','綦崇禮','宋','宋诗','song-poetry','','[]','帝眷民瞻豈暫望，江山信美可終藏。',64,'全唐诗/poet.song.90000.json','["帝眷民瞻豈暫望，江山信美可終藏。", "元勳合冠凌烟閣，雅興聊同綠野堂。", "已作時霖却龍臥，行看天討待鷹揚。", "囑公未用安髙退，准擬功成老故鄉。"]'),
('1f7bbd53-189c-4db9-882d-11433220e374','寄青田縣令楊仲固','綦崇禮','宋','宋诗','song-poetry','','[]','九載分違幾日同，銅章又過淛江東。',64,'全唐诗/poet.song.90000.json','["九載分違幾日同，銅章又過淛江東。", "芝田吏隱常看鶴，山邑官閑早夢熊。", "囹圄屢空知訟簡，囷倉相繼喜年豐。", "傳聞江上風塵息，相國寧忘幕府功。"]'),
('df710afd-08e7-4f77-aa0c-2071d303215a','酬李元叔察院見寄','綦崇禮','宋','宋诗','song-poetry','','[]','書到山中手自披，炎凉不改似君稀。',64,'全唐诗/poet.song.90000.json','["書到山中手自披，炎凉不改似君稀。", "術窮五技緣何事，巢穏一枝聊可依。", "掃跡徑須休去好，冥心深覺向來非。", "緩賡清唱緘題罷，却對松窗静掩扉。"]'),
('e74e33ee-ad86-4485-95f8-d5f54fc3713c','重九日宴臨漳亭','綦崇禮','宋','宋诗','song-poetry','','[]','九日追歡異昔年，强隨時節到層巔。',64,'全唐诗/poet.song.90000.json','["九日追歡異昔年，强隨時節到層巔。", "俯觀殊俗身如客，平瞰丹霄勢欲仙。", "故國傷心滄海外，行朝傾首碧雲邊。", "興闌酒罷催歸馭，四面嵐光合暮烟。"]'),
('76d2a951-cbbe-48b1-8d4f-48294ed4b829','雪晴','綦崇禮','宋','宋诗','song-poetry','','[]','冰箸垂簷滴漸多，眼花眩目氣初和。',64,'全唐诗/poet.song.90000.json','["冰箸垂簷滴漸多，眼花眩目氣初和。", "功成尺瑞追前賦，喜兆千箱可預歌。", "坐看嫩黄滋柳色，遥知新綠漲湖波。", "閉門積玉渾消盡，却有兒童整雀羅。"]'),
('50202fbd-08a0-4a7e-8a66-20e26383d149','喜雪呈已懋使君兼簡德升尚書國佐侍郎','綦崇禮','宋','宋诗','song-poetry','','[]','憂民太守致精祈，愛物天公意不違。',64,'全唐诗/poet.song.90000.json','["憂民太守致精祈，愛物天公意不違。", "要及歲元彰瑞應，故先春至作花飛。", "梅藏疏蘂餘芬馥，山壓羣峰失翠微。", "疫癘已消麰麥潤，更隨晴色探芳菲。"]'),
('0c3ef461-77c6-480e-8825-5ca9bef63f98','陪觀使太尉燕集長句兼簡座中諸公','綦崇禮','宋','宋诗','song-poetry','','[]','遶郭江山四望中，一時共寓接羣公。',96,'全唐诗/poet.song.90000.json','["遶郭江山四望中，一時共寓接羣公。", "戚藩位列三司貴，帥閫班分二府崇。", "華省名卿踵持橐，亷車宿將久櫜弓。", "追遊亦有鑾坡客，顦顇今先鶴髪翁。", "人事等閑欣戚異，賓筵聊喜笑言同。", "更須結伴春遊去，已過催花幾信風。"]'),
('e4276716-57e9-4d15-9929-4ff1dc675f03','次韻成季尚書甯川即事五首 山寺寓居','綦崇禮','宋','宋诗','song-poetry','','[]','宣室思前席，承明虚直廬。',24,'全唐诗/poet.song.90000.json','["宣室思前席，承明虚直廬。", "不肯入州府，分其終隱歟。"]'),
('a1804893-0f47-4f55-be73-bf5a373b6e57','次韻成季尚書甯川即事五首 對客隱几','綦崇禮','宋','宋诗','song-poetry','','[]','世路機兼穽，人情楯與矛。',24,'全唐诗/poet.song.90000.json','["世路機兼穽，人情楯與矛。", "客能知許事，兀兀一時休。"]'),
('1a68394f-f0a6-42fe-bb71-fad12214e8fa','次韻成季尚書甯川即事五首 晚晴讀書','綦崇禮','宋','宋诗','song-poetry','','[]','成功收拾芥，舊讀餘斷編。',24,'全唐诗/poet.song.90000.json','["成功收拾芥，舊讀餘斷編。", "時思賢聖對，久要故依然。"]'),
('0580fc5d-0671-4840-8318-1d0169bc2b7e','次韻成季尚書甯川即事五首 窗下獨酌','綦崇禮','宋','宋诗','song-poetry','','[]','獨飲自成趣，世情何用論。',24,'全唐诗/poet.song.90000.json','["獨飲自成趣，世情何用論。", "生平龍坂客，誰過雀羅門。"]'),
('782ccac6-6468-4611-9b57-cbc53bd11667','次韻成季尚書甯川即事五首 東齋夜坐','綦崇禮','宋','宋诗','song-poetry','','[]','當官肯虞謗，遇事羞摸稜。',24,'全唐诗/poet.song.90000.json','["當官肯虞謗，遇事羞摸稜。", "閒來愛清夜，默坐對青燈。"]'),
('931b40cc-bd49-482e-b748-231df8650605','德升尚書再用前韻見示五絕 山寺寓居','綦崇禮','宋','宋诗','song-poetry','','[]','塵埃暗宫錦，耒耜安田廬。',24,'全唐诗/poet.song.90000.json','["塵埃暗宫錦，耒耜安田廬。", "陳力知不能，不止獨何歟。"]'),
('2d794639-3876-490c-94e4-21a3c6dc1cf9','德升尚書再用前韻見示五絕 對客隱几','綦崇禮','宋','宋诗','song-poetry','','[]','邊書猶插羽，世用在持矛。',24,'全唐诗/poet.song.90000.json','["邊書猶插羽，世用在持矛。", "空言客何務，問事其少休。"]'),
('f00d67e2-8f6a-4c14-acc5-3d78faa30799','德升尚書再用前韻見示五絕 窗下獨酌','綦崇禮','宋','宋诗','song-poetry','','[]','忘憂有妙理，細與麯生論。',24,'全唐诗/poet.song.90000.json','["忘憂有妙理，細與麯生論。", "相携醉鄉去，醒見月當門。"]'),
('cc1705a6-6424-40b9-ad21-253a7392c87b','德升尚書再用前韻見示五絕 東齋夜坐','綦崇禮','宋','宋诗','song-poetry','','[]','一時盛意氣，四海竦風稜。',24,'全唐诗/poet.song.90000.json','["一時盛意氣，四海竦風稜。", "我懷非此念，兀坐對青燈。"]'),
('95fb5557-24a1-4d04-bfdf-1110f2742bd4','題護國寺','綦崇禮','宋','宋诗','song-poetry','','[]','前瞻雁蕩秋最奇，北上天台春更麗。',32,'全唐诗/poet.song.90000.json','["前瞻雁蕩秋最奇，北上天台春更麗。", "兩山特峙天下聞，一郡安閑介茲地。"]'),
('de685f2e-9cd7-441f-8be9-75034306c95d','觀使太尉俯用拙韻有述懷之作謹賦一篇奉酬嘉詠','綦崇禮','宋','宋诗','song-poetry','','[]','掌武當朝獨老成，運籌分閫厭勳名。',64,'全唐诗/poet.song.90000.json','["掌武當朝獨老成，運籌分閫厭勳名。", "旌旄載偃瓊臺路，符竹新拋鐵甕城。", "近塞尚虞秋馬健，空山底卹曉猨驚。", "更須重擬平戎去，欲贊公休似不情。"]'),
('2e25e203-c99d-41c8-b410-233f733b7923','崇禮次韻奉酬聊致挽留之意','綦崇禮','宋','宋诗','song-poetry','','[]','歸艎少緩不須摧，更待東城一訪梅。',64,'全唐诗/poet.song.90000.json','["歸艎少緩不須摧，更待東城一訪梅。", "鐵石心情猶解賦，芝蘭風味合相陪。", "臘殘絕訝遲遲見，春近何妨得得來。", "清賞未諧君欲去，臨邛誰與共銜杯。"]'),
('0081b646-3143-4b7a-9893-ba5556c482e4','送孫太沖守懷安','勾濤','宋','宋诗','song-poetry','','[]','雲頂峰崛奇，金淵水清寫。',24,'全唐诗/poet.song.90000.json','["雲頂峰崛奇，金淵水清寫。", "勉從山水遊，切勿輕民社。"]'),
('a8a794c0-c765-4559-ada9-279d8b95fc4a','泛歙溪用老杜詩青惜峰巒過爲韻  其一','胡舜陟','宋','宋诗','song-poetry','','[]','港浄千尋碧，峰回兩岸青。',48,'全唐诗/poet.song.90000.json','["港浄千尋碧，峰回兩岸青。", "鷺飛煙漠漠，猨嘯竹冥冥。", "雞犬聞聲地，雲霞蔽隱扃。", "桃源疑此是，時復問漁舲。"]'),
('fb22a451-693c-417e-a71c-f033c40b0b7e','泛歙溪用老杜詩青惜峰巒過爲韻  其二','胡舜陟','宋','宋诗','song-poetry','','[]','溪山美有餘，自古神仙宅。',48,'全唐诗/poet.song.90000.json','["溪山美有餘，自古神仙宅。", "築室隱宣平，題詩來李白。", "至今負薪人，間是餐霞客。", "不向此尋真，飄蓬端可惜。"]'),
('1f12fd29-0a91-4997-92cc-1527f491b8df','泛歙溪用老杜詩青惜峰巒過爲韻  其三','胡舜陟','宋','宋诗','song-poetry','','[]','萬山回合處，葱鬰釣臺峰。',48,'全唐诗/poet.song.90000.json','["萬山回合處，葱鬰釣臺峰。", "道義高千古，簟瓢敵萬鍾。", "羊裘甘寂寞，鳳闕肯從容。", "勿謂狂奴態，清風激懦庸。"]'),
('1f10df49-be91-42e6-a0da-54c08f2317ff','泛歙溪用老杜詩青惜峰巒過爲韻  其四','胡舜陟','宋','宋诗','song-poetry','','[]','草木紛紛落，江山正薄寒。',48,'全唐诗/poet.song.90000.json','["草木紛紛落，江山正薄寒。", "雲藏桐子宅，波急沈郎灘。", "回首家林遠，多愁革带寬。", "青楓知客恨，塗血點林巒。"]'),
('81e8fd49-6209-49a5-b997-235939c1566e','泛歙溪用老杜詩青惜峰巒過爲韻  其五','胡舜陟','宋','宋诗','song-poetry','','[]','觀山如走馬，倏忽千羣過。',48,'全唐诗/poet.song.90000.json','["觀山如走馬，倏忽千羣過。", "水從雲際來，舟疑天上坐。", "羈孤猨失羣，往復蟻旋磨。", "五韻寫中腸，悲詞成楚些。"]'),
('bd5d6775-ed5e-4cd3-a32f-fd14d889f14a','題秋香亭','胡舜陟','宋','宋诗','song-poetry','','[]','騷人足奇思，香草比君子。',60,'全唐诗/poet.song.90000.json','["騷人足奇思，香草比君子。", "況此霜下傑，清芬絕蘭茝。", "氣稟金行秀，德備黄中羹。", "古來鶴髪翁，餐英飲其水。", "但恐蓬藋傷，課僕加料理。"]'),
('56568ec1-4568-44ee-b7c1-e979bc6f8a68','秉燭賞梅','胡舜陟','宋','宋诗','song-poetry','','[]','蠟煙青繞雪培堆，神女疑乘香霧來。',32,'全唐诗/poet.song.90000.json','["蠟煙青繞雪培堆，神女疑乘香霧來。", "綽約仙姿明醉眼，橫斜疏影入樽罍。"]'),
('6c15dd60-6b33-4911-9a98-44f8996ea0b7','寄姪','胡舜陟','宋','宋诗','song-poetry','','[]','東輔書初至，西宮夜正寒。',48,'全唐诗/poet.song.90000.json','["東輔書初至，西宮夜正寒。", "感時嗟阻闊，喜汝報平安。", "學耨知兼力，辭淳發巨瀾。", "三冬文史足，軒翥未應難。"]'),
('c5a8b2b7-3960-425d-a13a-12c5b8c63719','建炎丞相成國呂忠穆公退老堂  其一','胡舜陟','宋','宋诗','song-poetry','','[]','中興將相上凌煙，社稷元功孰敢先。',64,'全唐诗/poet.song.90000.json','["中興將相上凌煙，社稷元功孰敢先。", "萬物生春持斗柄，六龍回馭取虞淵。", "中書方記汾陽考，南國俄乘范蠡船。", "卻向園林新棟宇，聊將勝事繼前賢。"]'),
('8d2f0917-42c6-49c9-8288-1addd781425a','建炎丞相成國呂忠穆公退老堂  其二','胡舜陟','宋','宋诗','song-poetry','','[]','爲聞仙伯隱丹丘，三徑新開結勝遊。',64,'全唐诗/poet.song.90000.json','["爲聞仙伯隱丹丘，三徑新開結勝遊。", "庭戶招呼松桂月，樽罍追逐芰荷秋。", "曉猿夜鶴空留戀，風虎雲龍自應求。", "已擁帥旄將入覲，運籌破虜此歸休。"]'),
('a9cce85d-a509-4006-9983-94159a151bb4','白水寺  其一','胡舜陟','宋','宋诗','song-poetry','','[]','雨過川原凈，山寒草木疏。',48,'全唐诗/poet.song.90000.json','["雨過川原凈，山寒草木疏。", "暮鐘鳴古寺，行客解征裾。", "馬祖留遺跡，浮丘傳異書。", "誰能尋勝概，來往謾紛如。"]'),
('48f2460c-f555-4a47-a352-cddfbad65d37','白水寺  其二','胡舜陟','宋','宋诗','song-poetry','','[]','風雨走長道，雲山憶故廬。',48,'全唐诗/poet.song.90000.json','["風雨走長道，雲山憶故廬。", "知還慚倦鳥，真樂羨遊魚。", "野燒痕將沒，新秧隴已鋤。", "桂林在何許，息馬見春餘。"]'),
('35ec8482-64c4-431f-ba2c-7764acfc77b7','滑石泉','胡舜陟','宋','宋诗','song-poetry','','[]','奔走塵沙五十程，泉聲今夜響泠泠。',32,'全唐诗/poet.song.90000.json','["奔走塵沙五十程，泉聲今夜響泠泠。", "明朝畫鼓催征騎，不使行人仔細聽。"]'),
('892e0ecb-f57d-4c29-9ffb-7c141b4d709f','題靜江府枕流亭','胡舜陟','宋','宋诗','song-poetry','','[]','平生壯志在燕然，投老南征示息肩。',33,'全唐诗/poet.song.90000.json','["平生壯志在燕然，投老南征示息肩。", "鼷鼠發機端可笑，暫休戎馬弄潺浮誇。"]'),
('78593a24-cffa-4ffd-89da-a31ea9cecab6','句  其一','胡舜陟','宋','宋诗','song-poetry','','[]','人有悲歡頭易白，山無古今色長青。',16,'全唐诗/poet.song.90000.json','["人有悲歡頭易白，山無古今色長青。"]'),
('79359f94-dd71-45cd-9aee-30200f5f6e19','句  其二','胡舜陟','宋','宋诗','song-poetry','','[]','含桃紅紫鶯聲老，宿麥青青燕子飛。',16,'全唐诗/poet.song.90000.json','["含桃紅紫鶯聲老，宿麥青青燕子飛。"]'),
('d68c3914-6efd-44d1-965b-25b0177a346a','天童山交禪師塔銘辭','黄龜年','宋','宋诗','song-poetry','','[]','西來誰露真消息，教外別傳要端的。',128,'全唐诗/poet.song.90000.json','["西來誰露真消息，教外別傳要端的。", "黄龍佛法付兒孫，臨濟宗風本奇特。", "珍重天童老古錐，聲名四海日星垂。", "當年一喝獅子吼，狐貍望風而避之。", "直截機鋒難湊泊，摘葉尋枝何太錯。", "滿堂龍象競交參，側耳惟聆師一諾。", "虛空撲落水流東，護塔松楸長舊叢。", "龜毛拂子三千丈，光彩流傳太白峰。"]'),
('77d225e7-3d05-4db6-af33-db043db8f25b','寶陀山觀音贊','黄龜年','宋','宋诗','song-poetry','','[]','稽首寶陀山，觀音大菩薩。',288,'全唐诗/poet.song.90000.json','["稽首寶陀山，觀音大菩薩。", "三十二妙應，垂福於人天。", "慧日廓圓明，隱微無不照。", "我等由宿植，於菩薩有緣。", "曩善一毫端，菩薩悉能鑒。", "今茲一何幸，聯檣來寶山。", "淑景德惠風，滄海如鑑凈。", "朝發東秦岸，須臾達蓮宮。", "僧飯洗鉢時，相與瞻遠嶠。", "□□跨巨浪，側足骨毛□。", "自念塵坌身，得伴清凈侶。", "同聲諷密語，復念我師名。", "注目渴慈光，忽覩紫金相。", "崆峒石窟上，宴坐自在容。", "雲霧不蔽虧，跪禮得良久。", "偕來無老稚，咸識應現尊。", "讚嘆且忻懼，得所未曾有。", "我念現前衆，中多大福人。", "久新迎我師，所禱如響應。", "爲我懺衆惡，遂亦見如來。", "同辦起心香，復陳一日供。", "倘以昔善積，獲此大吉禎。", "願敦未來因，永託如來記。", "浮生如夢幻，孰處放教生。"]'),
('bf8bcff7-061e-4678-a8fa-e0d1d3902387','馬秦山碧雲庵聯句','黄龜年','宋','宋诗','song-poetry','','[]','團團深鎖碧煙籠，安隱禪居瑞氣中。',32,'全唐诗/poet.song.90000.json','["團團深鎖碧煙籠，安隱禪居瑞氣中。", "萬頃滄浪終夜月，更於何處覓天宮。"]'),
('2ec784d9-e1ae-439f-87d1-e83e92fdaba0','贈晉水師','黄龜年','宋','宋诗','song-poetry','','[]','文衡卓卓擅英聲，相與明簪笑語清。',32,'全唐诗/poet.song.90000.json','["文衡卓卓擅英聲，相與明簪笑語清。", "報國共盟推轂志，五湖敢羨一舟輕。"]'),
('f21f811e-e1a2-45fa-8734-aa0d875bb17c','馬秦山碧雲庵聯句','黄岳年','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.90000.json','["無正文。"]'),
('7990a080-c13b-42fc-88ad-7adcba079752','馬秦山碧雲庵聯句','馬耆禪師','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.90000.json','["無正文。"]'),
('05b3c977-84ee-4237-8693-560a9ad51e3d','馬秦山碧雲庵聯句','張光','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.90000.json','["無正文。"]'),
('692191ff-65e9-4b45-85f6-dd6868ac9dff','句  其一','釋慶老','宋','宋诗','song-poetry','','[]','交情老去淡如水，病骨秋來瘦似松。',16,'全唐诗/poet.song.90000.json','["交情老去淡如水，病骨秋來瘦似松。"]'),
('3a47e8c0-3be4-4638-a0af-26ddc3a9e638','句  其二','釋慶老','宋','宋诗','song-poetry','','[]','共看栖樹鴉。',6,'全唐诗/poet.song.90000.json','["共看栖樹鴉。"]'),
('948151d5-db06-4c3d-8270-6a62f4b9f744','偈十六首  其一','釋士珪','宋','宋诗','song-poetry','','[]','衲帔蒙頭，下板頭邊，且打瞌睡。',92,'全唐诗/poet.song.90000.json','["衲帔蒙頭，下板頭邊，且打瞌睡。", "蒲團疊足，長連牀上，隨分挨肩。", "忽然露柱眼開，聖僧也須出院。", "切忌釘椿搖櫓，更須看風使帆。", "各各總在其中，人人自宜照顧。", "且道照顧個什麽，堂中賓主句，覿面沒親疏。"]'),
('06df588f-f987-48a9-addc-490139794d11','偈十六首  其二','釋士珪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一山南北煙霞裏，兩寺東西林麓間。',32,'全唐诗/poet.song.90000.json','["一山南北煙霞裏，兩寺東西林麓間。", "開眼如今渾是夢，莫言真個在廬山。"]'),
('5cf8daf8-782c-4c67-a735-6ca44efc73b3','偈十六首  其三','釋士珪','宋','宋诗','song-poetry','','[]','面前一道如絃直，當門不用栽荆棘。',63,'全唐诗/poet.song.90000.json','["面前一道如絃直，當門不用栽荆棘。", "陝府鐵牛，昨夜失卻尾巴；嘉州大像，不是白拈賊。", "趙州南，石橋北。", "黄河九曲吞崑崙，大悲院裏安彌勒。"]'),
('fe5000cc-34c1-4651-980a-a6ad3bc70a0c','偈十六首  其四','釋士珪','宋','宋诗','song-poetry','','[]','東林百不會，瞎驢隨大隊。',60,'全唐诗/poet.song.90000.json','["東林百不會，瞎驢隨大隊。", "鞭打不進前，步步只倒退。", "一日復一日，靈臺轉昏昧。", "死去入地獄，永劫終不悔。", "開口見心肝，實語當懺悔。"]'),
('169870df-006a-477d-bc81-779f7f0f6889','偈十六首  其五','釋士珪','宋','宋诗','song-poetry','','[]','錯錯，東林手把斷貫索，諸方鼻孔都穿卻。',51,'全唐诗/poet.song.90000.json','["錯錯，東林手把斷貫索，諸方鼻孔都穿卻。", "人問如何不自穿，自己鼻頭難摸索。", "而今子細細思量，元來不是而今錯。"]'),
('8ca4c939-60f1-4a48-ae11-51ee62143a77','偈十六首  其六','釋士珪','宋','宋诗','song-poetry','','[]','金鏃慣調經百戰，錢鞭多力恨無讎。',16,'全唐诗/poet.song.90000.json','["金鏃慣調經百戰，錢鞭多力恨無讎。"]'),
('59cdc58f-a4ef-49aa-b422-87d51ccc981f','偈十六首  其七','釋士珪','宋','宋诗','song-poetry','','[]','一陽生，萬物萌。',93,'全唐诗/poet.song.90000.json','["一陽生，萬物萌。", "天本清，地常寧。", "四時行，萬彙成。", "如緯經，如權衡。", "天心平，人心誠。", "日月明，鬼神警。", "方知天地分濁清，古今無虧盈。", "聖泉拄杖猶通靈，敲骨出髓。", "方悟從上諸聖碗鳴聲，猶較芭蕉半月程。"]'),
('30214234-c8fb-4a17-aabe-68685585ab43','偈十六首  其八','釋士珪','宋','宋诗','song-poetry','','[]','半夜穿針，盡十方皆成線路，你諸人爲什麽透不過。',83,'全唐诗/poet.song.90000.json','["半夜穿針，盡十方皆成線路，你諸人爲什麽透不過。", "天明喫粥，無一絲毫不露真機，你諸人爲什麽撥不轉。", "透不過處，路布分明。", "撥不轉時，真機獨露。", "半夜夢中驚驟雨，三更枕上聽秋聲。"]'),
('3e995a5f-d53d-4713-a61d-a85b0e915032','偈十六首  其九','釋士珪','宋','宋诗','song-poetry','','[]','烈火焰中，蟭螟蟲如何棲泊。',84,'全唐诗/poet.song.90000.json','["烈火焰中，蟭螟蟲如何棲泊。", "大爐韛裏，金剛鑽燒得通紅。", "驀然腦後一錐，鐵佛也須汗出。", "佛祖重新煅煉，衲僧再上鉗鎚。", "直饒千手大悲，這裏如何摸索。", "打破從教重錮鏴，休言鈍鐵費鉗鎚。"]'),
('3cf42b0e-094c-4a7b-b4be-3fd48f426b84','偈十六首  其一○','釋士珪','宋','宋诗','song-poetry','','[]','天晴開水路，無事設曹司。',24,'全唐诗/poet.song.90000.json','["天晴開水路，無事設曹司。", "病多諳藥性，小慈妨大慈。"]'),
('dd590a10-2ea3-4e26-9b49-886883425a4d','偈十六首  其一一','釋士珪','宋','宋诗','song-poetry','','[]','塵融法界，念盡毗盧。',174,'全唐诗/poet.song.90000.json','["塵融法界，念盡毗盧。", "千眼頓開，纖塵不立。", "遊戲寶明空海，超越菩提覺場。", "善財入樓閣之門，重重無盡。", "居士供蒲塞之饌，種種莊嚴。", "以上妙飲食供養爲法門，以廣大願心總持爲佛事。", "一一攝入，一一交參。", "一一圓融，一一周徧。", "理事平等，真俗混融。", "凡聖同源，因果不二。", "直得文殊騎獅子，入普賢鼻孔裏藏身。", "普賢騎象王，入文殊眼睛裏瞌睡。", "釋迦彌勒，掩耳偷鈴。", "勢至觀音，抱贜叫屈。"]'),
('1e00568d-22b4-4cb2-ab78-4fefbe3bca61','偈十六首  其一二','釋士珪','宋','宋诗','song-poetry','','[]','老龍千丈湫，晴空散飛雪。',48,'全唐诗/poet.song.90000.json','["老龍千丈湫，晴空散飛雪。", "尊者諾詎羅，坐視眼眨眨。", "老禪來住山，梵志翻著襪。", "乍可刺汝眼，且要話頭活。"]'),
('c81028fd-6748-4bde-8c3e-a825be97a61e','偈十六首  其一三','釋士珪','宋','宋诗','song-poetry','','[]','老禪不打鼓山鼓，送老來看雁范山。',32,'全唐诗/poet.song.90000.json','["老禪不打鼓山鼓，送老來看雁范山。", "傑閣重樓都不見，溪邊茅屋兩三間。"]'),
('587796a7-95a7-4ba9-8a73-0eadffb249eb','偈十六首  其一四','釋士珪','宋','宋诗','song-poetry','','[]','釋迦彌勒，猶是他奴。',76,'全唐诗/poet.song.90000.json','["釋迦彌勒，猶是他奴。", "臨濟德山，是何草芥。", "向上一路，荆棘成林。", "更欲翻身，墮崖落塹。", "總不動著，當處活埋。", "生機臨時，翻成亂統。", "穿耳胡僧葱嶺去，夜行踏雪馬蹄輕。"]'),
('88e2f586-fb2c-4c3f-b16e-f716c882b424','偈十六首  其一五','釋士珪','宋','宋诗','song-poetry','','[]','懸泉千尺瀉龍湫，一葉蕭蕭萬木秋。',32,'全唐诗/poet.song.90000.json','["懸泉千尺瀉龍湫，一葉蕭蕭萬木秋。", "坐看孤雲行看月，更無佛法掛心頭。"]'),
('e7dd5ad7-7fc4-473d-8e16-760671653067','偈十六首  其一六','釋士珪','宋','宋诗','song-poetry','','[]','晷運推移無不動，日南長至幾曾遷。',56,'全唐诗/poet.song.90000.json','["晷運推移無不動，日南長至幾曾遷。", "應時納祜無他事，依舊三門開兩邊。", "三門開兩邊，一句具三玄。", "今古應無墜，分明在目前。"]'),
('ea74e470-b1b6-4479-b7b5-2c1534639ab3','偈十六首  其一七','釋士珪','宋','宋诗','song-poetry','','[]','孔明廟前有古柏，枝如青銅根如石。',74,'全唐诗/poet.song.90000.json','["孔明廟前有古柏，枝如青銅根如石。", "蒼皮溜雨四十圍，黛色參天二千尺。", "但見年年是好年，豈知日日是好日。", "小樹子，傍山栽，花從葉裏開。", "枝高攀不得，羅袖拂將來。"]'),
('de2e81b4-6869-4c0c-8f1a-d21c523d06ab','偈十六首  其一八','釋士珪','宋','宋诗','song-poetry','','[]','塵融法界，念盡毗盧。',71,'全唐诗/poet.song.90000.json','["塵融法界，念盡毗盧。", "咫尺跨於大千，剎那超於三世。", "過去諸如來秤鎚落井，現在諸菩薩塞壑填溝。", "未來修學人，如麻似粟。", "回頭拾得新羅箭，自是諸人不丈夫。"]'),
('be48d400-9385-48d8-9e6b-b98f9a81471b','臨終偈','釋士珪','宋','宋诗','song-poetry','','[]','前三十一，中九下七。',22,'全唐诗/poet.song.90000.json','["前三十一，中九下七。", "老人言盡處，龜歌眼睛赤。"]'),
('da1793af-96cb-4517-8ddd-e37a561d9b8e','頌古六首  其一','釋士珪','宋','宋诗','song-poetry','','[]','不假文殊神通，休要罔明彈指。',28,'全唐诗/poet.song.90000.json','["不假文殊神通，休要罔明彈指。", "爾時靈山會中，女子從定而起。"]'),
('51cd90e3-ce9a-49d0-8054-52f8754e5281','頌古六首  其二','釋士珪','宋','宋诗','song-poetry','','[]','世路風波不見君，一回見面一傷神。',32,'全唐诗/poet.song.90000.json','["世路風波不見君，一回見面一傷神。", "水流華落知何處，洞中桃源別是春。"]'),
('6c9c4617-8b05-4999-976a-49e96e54ced7','頌古六首  其三','釋士珪','宋','宋诗','song-poetry','','[]','劈面三拳，連腮七掌。',20,'全唐诗/poet.song.90000.json','["劈面三拳，連腮七掌。", "盡大地人，不知痛癢。"]'),
('5bf0d2f9-8baa-4cc5-86f0-9b4a80504ea7','頌古六首  其四','釋士珪','宋','宋诗','song-poetry','','[]','夜半墨漆黑，捉得一個賊。',24,'全唐诗/poet.song.90000.json','["夜半墨漆黑，捉得一個賊。", "點火照來看，元是王大伯。"]'),
('9a8b8e30-c116-4881-9bf9-105e5d5ab1bf','頌古六首  其五','釋士珪','宋','宋诗','song-poetry','','[]','近在口皮邊，遠過河沙國。',24,'全唐诗/poet.song.90000.json','["近在口皮邊，遠過河沙國。", "世間多少人，不得油餈喫。"]'),
('5b87bd15-d507-49b6-87a4-11dbec3945a2','頌古六首  其六','釋士珪','宋','宋诗','song-poetry','','[]','船子下揚州，浮萍逐水流。',24,'全唐诗/poet.song.90000.json','["船子下揚州，浮萍逐水流。", "一聲河滿子，千古動悲愁。"]'),
('66373576-410e-4f58-9dfe-74d4fe42e848','偈五首  其一','釋士珪','宋','宋诗','song-poetry','','[]','萬年一念，一念萬年。',44,'全唐诗/poet.song.90000.json','["萬年一念，一念萬年。", "和衣泥裏輥，洗腳上牀眠。", "歷劫來事，祇在如今。", "大海波濤湧，小人方寸深。"]'),
('516195f4-56f7-44a7-b088-2f87757663c5','偈五首  其二','釋士珪','宋','宋诗','song-poetry','','[]','萬機不到，眼見色，耳聞聲。',58,'全唐诗/poet.song.90000.json','["萬機不到，眼見色，耳聞聲。", "一句當堂，頭戴天，腳踏地。", "你諸人祇如今日是五月初一，殊不知金烏半夜忙忙去，玉兔天明上海東。"]'),
('ae15f883-2d8f-4b33-8ac3-ba6aa5dfedb1','偈五首  其三','釋士珪','宋','宋诗','song-poetry','','[]','一葉落，天下秋，欲窮千里目，更上一層樓。',52,'全唐诗/poet.song.90000.json','["一葉落，天下秋，欲窮千里目，更上一層樓。", "一塵起，大地收，嘉州打大像，陝府灌鐵牛。", "久旱簷頭句，橋流水不流。"]'),
('c1c25222-cc5a-4f93-9cd6-76396e852389','偈五首  其四','釋士珪','宋','宋诗','song-poetry','','[]','見見之時，見非是見。',72,'全唐诗/poet.song.90000.json','["見見之時，見非是見。", "見猶離見，見不能及。", "落華有意隨流水，流水無情戀落華。", "諸可還者，自然非汝。", "不汝還者，非汝而誰。", "長恨春歸無覓處，不知轉入此中來。"]'),
('61f13a2e-7054-428a-a2ff-1fcbc1f75e7a','偈五首  其五','釋士珪','宋','宋诗','song-poetry','','[]','馬搭鞍，驢推磨。',50,'全唐诗/poet.song.90000.json','["馬搭鞍，驢推磨。", "靈利衲僧，祇消一個。", "縱使東家明點燈，未必西家暗中坐。", "西來意旨問如何，多口阿師自招禍。"]'),
('e995cb0f-ea76-412e-b698-f7987e04ea8d','觀行上座所作維摩問疾圖','釋士珪','宋','宋诗','song-poetry','','[]','道人眈眈癡虎頭，瞭然電轉開雙眸。',160,'全唐诗/poet.song.90000.json','["道人眈眈癡虎頭，瞭然電轉開雙眸。", "枯木已死寒巖秋，定中霹靂摧四牛。", "起來下筆不能休，新詩字字蟠銀鉤。", "發其餘者漫不收，散而縱橫爲九流。", "我觀此畫真其尤，病維摩詰小有瘳。", "文殊大士從之游，彼上人者難對酬。", "兩公文章虎而彪，萬古凡馬空驊騮。", "向來曹韓與韋侯，筆端亦嘗知此否。", "世間畫本多山丘，閱人何翅如傳郵。", "對此可以銷百憂，先生胡爲吟四愁。"]'),
('88bd9e91-ce3f-43b0-abfa-e66d18682cee','安上座所作墨梅','釋士珪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','道人色心浄，了見造物根。',60,'全唐诗/poet.song.90000.json','["道人色心浄，了見造物根。", "筆端開此花，胸中有丘園。", "清香凝暗夜，疏枝臥黄昏。", "撞鐘西湖寺，見月羅浮村。", "老眼隔煙霧，一笑作籬藩。"]'),
('7d463a1e-094e-4744-a48a-2762ee46ec45','頌古七十六首  其一','釋士珪','宋','宋诗','song-poetry','','[]','老胡不免出胞胎，也解人前恁麽來。',32,'全唐诗/poet.song.90000.json','["老胡不免出胞胎，也解人前恁麽來。", "指地指天稱第一，衆生四十九年災。"]'),
('602d9d70-0054-4b31-a3ef-b363a74c00d8','頌古七十六首  其二','釋士珪','宋','宋诗','song-poetry','','[]','是非海裏橫身人，豺虎羣中自在行。',32,'全唐诗/poet.song.90000.json','["是非海裏橫身人，豺虎羣中自在行。", "莫把是非來辨我，平生穿鑿不相幹。"]'),
('3512cd67-ab5c-4fac-92a8-de845e74cd22','頌古七十六首  其三','釋士珪','宋','宋诗','song-poetry','','[]','月裏姮娥不畫眉，只將雲霧作羅衣。',32,'全唐诗/poet.song.90000.json','["月裏姮娥不畫眉，只將雲霧作羅衣。", "不知夢逐青鸞去，猶把花枝蓋面歸。"]'),
('0636fd39-55f4-4e13-8311-29f5d32de088','頌古七十六首  其四','釋士珪','宋','宋诗','song-poetry','','[]','拄杖頭邊無孔竅，大千沙界猶嫌小。',32,'全唐诗/poet.song.90000.json','["拄杖頭邊無孔竅，大千沙界猶嫌小。", "毗婆尸佛早留心，直至而今不得妙。"]'),
('c2e0701a-a839-4206-9059-ac478ca7a46e','頌古七十六首  其五','釋士珪','宋','宋诗','song-poetry','','[]','舉手攀南斗，翻身倚北辰。',24,'全唐诗/poet.song.90000.json','["舉手攀南斗，翻身倚北辰。", "出頭天外看，誰是我般人。"]'),
('059d4216-829c-41c2-a0a6-7df5d9336c5f','頌古七十六首  其六','釋士珪','宋','宋诗','song-poetry','','[]','種穀不生豆苗，蒸沙豈能成飯。',28,'全唐诗/poet.song.90000.json','["種穀不生豆苗，蒸沙豈能成飯。", "大通智勝如來，一個擔扳底漢。"]'),
('7eeab78c-b271-4d1f-8cef-36ea2cb74e09','頌古七十六首  其七','釋士珪','宋','宋诗','song-poetry','','[]','入林不動草，入水不動波。',24,'全唐诗/poet.song.90000.json','["入林不動草，入水不動波。", "鑊湯無冷處，合眼跳黄河。"]'),
('099dfb67-5786-458d-ad44-1e5a922a02f5','頌古七十六首  其八','釋士珪','宋','宋诗','song-poetry','','[]','破缾豈復作缾事，焦種不因生糵牙。',32,'全唐诗/poet.song.90000.json','["破缾豈復作缾事，焦種不因生糵牙。", "如彼靈空槃大子，毛輪垂法翳花開。"]'),
('3f3a7e4b-b1b7-4699-b9e3-303a8a820eba','頌古七十六首  其九','釋士珪','宋','宋诗','song-poetry','','[]','海水翻空袞底流，魚龍蝦蟹信沉浮。',32,'全唐诗/poet.song.90000.json','["海水翻空袞底流，魚龍蝦蟹信沉浮。", "可憐金色頭陀子，直至如今笑未休。"]'),
('edf67f98-7394-4f69-94b7-d2f6a3647041','頌古七十六首  其一○','釋士珪','宋','宋诗','song-poetry','','[]','少室山前風過耳，九年人事隨流水。',31,'全唐诗/poet.song.90000.json','["少室山前風過耳，九年人事隨流水。", "若還是弄潮人，切須莫入洪波裏。"]'),
('07e2022d-688d-4734-9749-b0133f78faeb','頌古七十六首  其一一','釋士珪','宋','宋诗','song-poetry','','[]','二祖當年立少林，滿庭積雪到腰深。',32,'全唐诗/poet.song.90000.json','["二祖當年立少林，滿庭積雪到腰深。", "叉手當胸無一事，不求不覓不安心。"]'),
('338e5ff7-ee81-42c0-a7e2-8115d1533032','頌古七十六首  其一二','釋士珪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','胡亂三十年，不曾少鹽醬。',24,'全唐诗/poet.song.90000.json','["胡亂三十年，不曾少鹽醬。", "江西馬大師，南嶽讓和尚。"]'),
('839dfc32-2440-4a39-ad11-7a5b4f263ea3','頌古七十六首  其一三','釋士珪','宋','宋诗','song-poetry','','[]','廬陵米價少知音，佛法商量古到今。',32,'全唐诗/poet.song.90000.json','["廬陵米價少知音，佛法商量古到今。", "繡出鴛鴦任人看，無端卻要覓金鍼。"]'),
('a37a9f44-970a-41e0-b50e-9f40322877bb','頌古七十六首  其一四','釋士珪','宋','宋诗','song-poetry','','[]','江西一喝動乾坤，大用全機是滅門。',32,'全唐诗/poet.song.90000.json','["江西一喝動乾坤，大用全機是滅門。", "三日耳聾風過樹，累他黄蘖喪兒孫。"]'),
('f412b57c-d7a1-4633-8986-4bb135738471','頌古七十六首  其一五','釋士珪','宋','宋诗','song-poetry','','[]','百丈野狐，塞鴈銜蘆。',20,'全唐诗/poet.song.90000.json','["百丈野狐，塞鴈銜蘆。", "李廣神箭，張顛草書。"]'),
('59a259ba-a1d2-4c12-a36a-78adb119bdc5','頌古七十六首  其一六','釋士珪','宋','宋诗','song-poetry','','[]','剔起便行三萬里，只今休去八千年。',32,'全唐诗/poet.song.90000.json','["剔起便行三萬里，只今休去八千年。", "分明更爲從頭舉，一任諸方取次傳。"]'),
('85aa9e5f-dcc9-46bf-a712-2a58a796321a','頌古七十六首  其一七','釋士珪','宋','宋诗','song-poetry','','[]','心不是佛，智不是道。',34,'全唐诗/poet.song.90000.json','["心不是佛，智不是道。", "青山白雲，落花芳草。", "若是伶俐阿師，終不回頭轉腦。"]'),
('2fb3f3f2-97c9-45b8-8d40-4d1baaf74455','頌古七十六首  其一八','釋士珪','宋','宋诗','song-poetry','','[]','一道如弦直，心親手更親。',24,'全唐诗/poet.song.90000.json','["一道如弦直，心親手更親。", "箭穿紅日影，方是射鵰人。"]'),
('93b8b06b-af82-4df8-a3be-10d757f49169','頌古七十六首  其一九','釋士珪','宋','宋诗','song-poetry','','[]','南泉不指凈瓶，隱峰何曾潟水。',28,'全唐诗/poet.song.90000.json','["南泉不指凈瓶，隱峰何曾潟水。", "從教打瓦鑽龜，佛法不在這裏。"]'),
('a055616c-fd4c-4561-ad3a-d39503a52c55','頌古七十六首  其二○','釋士珪','宋','宋诗','song-poetry','','[]','大海波濤闊，小人方寸深。',24,'全唐诗/poet.song.90000.json','["大海波濤闊，小人方寸深。", "海枯終見底，人死不知心。"]'),
('2fe5f50d-092e-4aaf-ac1d-ca0d26e15700','頌古七十六首  其二一','釋士珪','宋','宋诗','song-poetry','','[]','四海狼煙靜，中原信息通。',24,'全唐诗/poet.song.90000.json','["四海狼煙靜，中原信息通。", "罷拈三尺劍，休弄一張弓。"]'),
('9ab66b7e-dcda-4dd7-b35d-21431fa90a18','頌古七十六首  其二二','釋士珪','宋','宋诗','song-poetry','','[]','大唐國裏無禪師，禮拜歸堂更不疑。',32,'全唐诗/poet.song.90000.json','["大唐國裏無禪師，禮拜歸堂更不疑。", "堪笑河陽新婦子，不如臨濟小廝兒。"]'),
('28edbc55-79ab-46b1-a7ba-121dc7d99b9f','頌古七十六首  其二三','釋士珪','宋','宋诗','song-poetry','','[]','若知天地本同根，不應重來更問人。',32,'全唐诗/poet.song.90000.json','["若知天地本同根，不應重來更問人。", "卻得南泉親指似，等閑花發夢中春。"]'),
('ada2b095-d887-4f38-b709-9131b136954b','頌古七十六首  其二四','釋士珪','宋','宋诗','song-poetry','','[]','狸奴白牯念摩訶，爭似南泉打破鍋。',32,'全唐诗/poet.song.90000.json','["狸奴白牯念摩訶，爭似南泉打破鍋。", "雖然佛法無多子，天下叢林不奈何。"]'),
('25b6d4ba-0a87-4744-9a88-42e7a3cea7e1','頌古七十六首  其二五','釋士珪','宋','宋诗','song-poetry','','[]','若謂平常心是道，枝蔓向上更生枝。',32,'全唐诗/poet.song.90000.json','["若謂平常心是道，枝蔓向上更生枝。", "貼肉汗衫如脫了，喚來眼上與安眉。"]'),
('87bf9c11-4c37-4d11-82ba-653d7fcf0fcb','頌古七十六首  其二六','釋士珪','宋','宋诗','song-poetry','','[]','眼中見慣是尋常，又不驚人又久長。',32,'全唐诗/poet.song.90000.json','["眼中見慣是尋常，又不驚人又久長。", "留得寒窻夜來月，三更依舊照茅堂。"]'),
('e204d9b3-e63f-461d-a2f0-27173efcf6fa','頌古七十六首  其二七','釋士珪','宋','宋诗','song-poetry','','[]','茱萸這裏無一滴，趙州無言便走出。',32,'全唐诗/poet.song.90000.json','["茱萸這裏無一滴，趙州無言便走出。", "春去秋來三百年，拄杖至今猶倚壁。"]'),
('7a985218-5b64-45b3-8f45-75e19328aa2f','頌古七十六首  其二八','釋士珪','宋','宋诗','song-poetry','','[]','鎮州出大蘿蔔頭，師資道合有來由。',32,'全唐诗/poet.song.90000.json','["鎮州出大蘿蔔頭，師資道合有來由。", "觀音寺裏有彌勒，東院西邊有趙州。"]'),
('4bf4c18c-49b8-4c80-b976-23c4dc11c037','頌古七十六首  其二九','釋士珪','宋','宋诗','song-poetry','','[]','金佛木佛泥佛，度爐度水度火。',42,'全唐诗/poet.song.90000.json','["金佛木佛泥佛，度爐度水度火。", "盡入趙州紅爐，烈焰光中鍛過。", "一聲白雪陽春，萬古無人能和。"]'),
('0e5d9fbe-99fb-490a-b409-720307b10e5b','頌古七十六首  其三○','釋士珪','宋','宋诗','song-poetry','','[]','大地是眼何處屙，天下不奈雪老何。',35,'全唐诗/poet.song.90000.json','["大地是眼何處屙，天下不奈雪老何。", "趙州寄個鍬子去，方得此語圓來龍去堶堶。"]'),
('543fcace-619d-46d1-9746-b54a921a7d11','頌古七十六首  其三一','釋士珪','宋','宋诗','song-poetry','','[]','天子居鬧市裏，山僧在百草頭。',28,'全唐诗/poet.song.90000.json','["天子居鬧市裏，山僧在百草頭。", "擺手御街來往，不怕巡火所由。"]'),
('7457c2df-60fb-4eb6-9137-5dab2a6d4a5f','頌古七十六首  其三二','釋士珪','宋','宋诗','song-poetry','','[]','得入門，在門外。',24,'全唐诗/poet.song.90000.json','["得入門，在門外。", "說向人，人不會。", "更高聲，我耳背。"]'),
('69a09d97-62f9-4b11-ad3d-af7f1d6dd1ba','頌古七十六首  其三三','釋士珪','宋','宋诗','song-poetry','','[]','宣德門前過，回頭便招禍。',24,'全唐诗/poet.song.90000.json','["宣德門前過，回頭便招禍。", "若要無事時，且歸堂裏坐。"]'),
