('31b70995-8329-4267-b975-10645d537769','頌古七十六首  其六五','釋士珪','宋','宋诗','song-poetry','','[]','只要拔楔抽釘，爲人解粘去縛。',28,'全唐诗/poet.song.90000.json','["只要拔楔抽釘，爲人解粘去縛。", "如何洞山老人，先自螣蛇繞腳。"]'),
('69635e96-8874-49ef-849c-f31bc5d404df','頌古七十六首  其六六','釋士珪','宋','宋诗','song-poetry','','[]','網中跳出便飛騰，好個天然俊衲僧。',32,'全唐诗/poet.song.90000.json','["網中跳出便飛騰，好個天然俊衲僧。", "何似當初未入網，悟來方始是知音。"]'),
('e135b71c-5cd4-495e-bc05-0eb1dbff30e8','頌古七十六首  其六七','釋士珪','宋','宋诗','song-poetry','','[]','阿家新婦兩同條，咫尺家鄉路不遙。',32,'全唐诗/poet.song.90000.json','["阿家新婦兩同條，咫尺家鄉路不遙。", "可笑騎驢覓驢者，一生錯認馬鞍橋。"]'),
('adcf1c35-a805-432d-83c7-8743f37ffcff','頌古七十六首  其六八','釋士珪','宋','宋诗','song-poetry','','[]','拈起竹篦子，□□便到家。',24,'全唐诗/poet.song.90000.json','["拈起竹篦子，□□便到家。", "祕魔若不會，隨後卻擎叉。"]'),
('0ad9e75c-f060-4582-b351-951c711a87f5','頌古七十六首  其六九','釋士珪','宋','宋诗','song-poetry','','[]','十年湖海覓冤讎，不得冤讎未肯休。',32,'全唐诗/poet.song.90000.json','["十年湖海覓冤讎，不得冤讎未肯休。", "芍藥花開菩薩面，椶櫚葉長夜叉頭。"]'),
('33910e43-457a-48f5-8524-58ea46e71bec','頌古七十六首  其七○','釋士珪','宋','宋诗','song-poetry','','[]','鋸解秤鎚渾似鐵，大愚老子曾饒舌。',32,'全唐诗/poet.song.90000.json','["鋸解秤鎚渾似鐵，大愚老子曾饒舌。", "水流澗下太忙生，雲在嶺頭閑不徹。"]'),
('26c0f159-2329-4505-ab69-2251fafa90ab','頌古七十六首  其七一','釋士珪','宋','宋诗','song-poetry','','[]','官路無人獨自行，自家公驗甚分明。',32,'全唐诗/poet.song.90000.json','["官路無人獨自行，自家公驗甚分明。", "路傍偷販私鹽客，草裏蹲身過一生。"]'),
('de1af42c-fed2-4e2d-8a49-1301f489c1b5','頌古七十六首  其七二','釋士珪','宋','宋诗','song-poetry','','[]','猛虎當路坐，游魚脚下過。',24,'全唐诗/poet.song.90000.json','["猛虎當路坐，游魚脚下過。", "不學子湖老，便打劉鐵磨。"]'),
('4f0055e1-5f69-40a4-891d-36f28a125efc','頌古七十六首  其七三','釋士珪','宋','宋诗','song-poetry','','[]','三腳驢兒忒殺好，長放後園教喫草。',32,'全唐诗/poet.song.90000.json','["三腳驢兒忒殺好，長放後園教喫草。", "等閑牽去向人前，踼倒湖南瞎長老。"]'),
('5dab0133-4551-490e-b8d7-4842accf09a0','頌古七十六首  其七四','釋士珪','宋','宋诗','song-poetry','','[]','楊歧老人鎖口訣，萬里長城一條鐵。',32,'全唐诗/poet.song.90000.json','["楊歧老人鎖口訣，萬里長城一條鐵。", "斫牌禪客知到來，不動金鎚腦門裂。"]'),
('683f74b1-6fc0-4d7a-862d-187a29da3993','頌古七十六首  其七五','釋士珪','宋','宋诗','song-poetry','','[]','口是禍門，電掣雷奔。',20,'全唐诗/poet.song.90000.json','["口是禍門，電掣雷奔。", "娑竭出海，震動乾坤。"]'),
('ba1ca886-ac96-48c0-9c5f-aa3c0a71a7bb','頌古七十六首  其七六','釋士珪','宋','宋诗','song-poetry','','[]','從前五逆怕聞雷，不似大蟲看水磨。',32,'全唐诗/poet.song.90000.json','["從前五逆怕聞雷，不似大蟲看水磨。", "孤峰頂上要同行，十字街頭還共坐。"]'),
('ffd04b2a-4a94-4691-8282-710b1c2a3edd','句  其一','釋士珪','宋','宋诗','song-poetry','','[]','祇老是生涯。',6,'全唐诗/poet.song.90000.json','["祇老是生涯。"]'),
('06108700-a2d7-46e9-98f8-61a2ecaaa377','句  其二','釋士珪','宋','宋诗','song-poetry','','[]','塢深人不到。',6,'全唐诗/poet.song.90000.json','["塢深人不到。"]'),
('2f3baa06-9418-43a3-9573-6f6195aeec57','句  其三','釋士珪','宋','宋诗','song-poetry','','[]','誰令眼界幽。',6,'全唐诗/poet.song.90000.json','["誰令眼界幽。"]'),
('8611c104-b01c-4b9c-85f2-fa0066a9a1db','遊海雲山','喻汝礪','宋','宋诗','song-poetry','','[]','渺渺天宇初，便復有此山。',132,'全唐诗/poet.song.90000.json','["渺渺天宇初，便復有此山。", "清晨及兹遊，遐想百代前。", "來者幾何人，當時各爲歡。", "淑質揚妙舞，哀絲遞清彈。", "樂事坐如昨，芳歲已屢殫。", "向來所遊人，落葉不復還。", "迥然散遠目，感之爲長嘆。", "竹林遥舊所，鵲巢豈昔眠。", "念誰常久存，而不任所緣。", "破涕聊一怡，山川却萋妍。", "未知後世事，誰復當來旋。"]'),
('d89cea86-2d33-4b18-ab4e-3119e08b8c2b','過府學遂謁文翁堂','喻汝礪','宋','宋诗','song-poetry','','[]','綠荻負幽隱，髙槐泛輕凉。',120,'全唐诗/poet.song.90000.json','["綠荻負幽隱，髙槐泛輕凉。", "各誇一時好，披風互低昂。", "詎知五月中，微陰忽催黄。", "我行魯侯宫，獨謁文翁堂。", "若人骨已朽，道在斯不忘。", "遂令蜀文章，照耀日月旁。", "世事俱腐臭，斯文真久長。", "靡頹能幾時，蕭條翳墟荒。", "富貴豈不好，千載同一塲。", "三嘆過泮宫，撫已涕自滂。"]'),
('9e54094f-8d67-48d8-a25f-53ebab653419','清曉坐四天王院','喻汝礪','宋','宋诗','song-poetry','','[]','杳杳天宇凉，月墜星亦稀。',120,'全唐诗/poet.song.90000.json','["杳杳天宇凉，月墜星亦稀。", "朝暉下檐隙，遠色開林扉。", "寂坐無物役，隱几或在斯。", "曠焉耳目清，擬覺形神歸。", "溷世跡若近，抱沖心獨微。", "故殿經幾年，何人所摹規。", "當時亦姱嫮，作者良已罷。", "快意取一好，於身亮何私。", "不知壯觀地，徒使來者悲。", "坐頃又成昔，安知今是非。"]'),
('22638296-73ff-4335-bd7b-3d141b34ac6f','登正法宫塔','喻汝礪','宋','宋诗','song-poetry','','[]','疏雨洗空闊，髙標插青冥。',132,'全唐诗/poet.song.90000.json','["疏雨洗空闊，髙標插青冥。", "携笻一來登，長嘯謝所攖。", "清香翔遠江，丹氣舒翠岷。", "雪嶺浮夏白，澥雲亦遠青。", "孤花裊危芳，初篁羅新榮。", "手容五十里，颯沓爲我陳。", "陵坻漭變遷，物狀幾屈信。", "念往思自遠，感來意彌臻。", "傷哉千里心，嗟爾百代人。", "胡爲軫其德，戚戚勞所營。", "吾請以此辭，歸來巖下耕。"]'),
('b2adfa35-f640-4e25-bc36-b7d3f9d138f6','遊西臺院暑雪軒觀石鏡','喻汝礪','宋','宋诗','song-poetry','','[]','城中苦伊欎，兹軒獨髙鶱。',132,'全唐诗/poet.song.90000.json','["城中苦伊欎，兹軒獨髙鶱。", "連甍動參差，錯畦横阡眠。", "雪嶠正孤峙，若與我周旋。", "遠翠浮蕩瀁，輕鷗下聮軒。", "密竹罥幽逕，新蒲澹清漣。", "初遊愜餘懷，既久幽念攅。", "慨彼泉下人，灼灼夸令顔。", "忽然墜榛莽，窈窕不可援。", "一鏡空復情，况乃塊石頑。", "哀哉彼愚子，婉孌情所牽。", "差勝茂陵公，更訹方士言。"]'),
('f2a86bb5-f201-4e7d-8190-bd11076ecb5b','遊嚴真觀支機石而壁有記古鼎丹茅事','喻汝礪','宋','宋诗','song-poetry','','[]','古木共幽意，長廊亦晏如。',144,'全唐诗/poet.song.90000.json','["古木共幽意，長廊亦晏如。", "於焉詠逍遥，且復散衣裾。", "塵慮颯已空，道心頗閎舒。", "不知度世人，去此歲幾徂。", "云何有丹砂，尚爾留庭隅。", "支機亦悠哉，誰復訂有無。", "我知此公意，慨彼元鼎初。", "繼之五鳳問，斯民斃刀鋸。", "聊欲謝世網，欻以道自娛。", "抱獨理自會，曠懷遺所拘。", "初匪逃世人，而世自我疏。", "含默念斯人，起我憂患餘。"]'),
('22691845-955f-4b21-913c-887e3f8b950b','謁諸葛廟','喻汝礪','宋','宋诗','song-poetry','','[]','孤雲何其髙，明月不可繫。',144,'全唐诗/poet.song.90000.json','["孤雲何其髙，明月不可繫。", "灼灼抱此心，與世自涇渭。", "適來從所歡，感亂亦歔欷。", "咨惟今之人，竊國未云耻。", "匕首入吳市，秋風動燕水。", "區區袁與曹，等是刺客耳。", "而我於其間，秉義不敢墜。", "哀音回衝飇，清義動幽邃。", "天心固難亮，吾獨信所履。", "溶溶日間雲，漠漠苔點砌。", "饑鼯墜蒼瓦，澹薄公所憩。", "靜然相英姿，孤懷亦差慰。"]'),
('2bb24a64-8d8b-45ae-8581-38808c02d112','謁江瀆廟','喻汝礪','宋','宋诗','song-poetry','','[]','坤軸東南傾，大江日夜注。',168,'全唐诗/poet.song.90000.json','["坤軸東南傾，大江日夜注。", "前驅下荆巫，餘濤略吳楚。", "任勢不期勞，得意緣所遇。", "水也初無營，神哉亮誰主。", "芳蘭沉清華，碧藻舒翠縷。", "晨鵠戲野岸，春鳬集深渚。", "均是得所安，而神豈私汝。", "古來幾精魂，捨此迷所處。", "淫遊不知還，沙村失煙樹。", "而我後千載，悠然在江滸。", "抱嗇貴無競，矜名忌多取。", "冥冥罨岸風，淫淫打船雨。", "舞雪窺洪濤，開蘋渡前浦。", "再拜謝神貺，聊復隨所住。"]'),
('0157ba2b-c15c-446f-ba94-73a328916e8b','子雲墨池','喻汝礪','宋','宋诗','song-poetry','','[]','讀書豈不好，憂憤還自兹。',108,'全唐诗/poet.song.90000.json','["讀書豈不好，憂憤還自兹。", "書中見古人，隱閔惻餘思。", "遇險理有激，尋分意多隨。", "娟娟感姱容，慼慼念幽棲。", "曾是無間然，孰焉愜所宜。", "覽之不自聊，悵然起遥悲。", "不如撥置之，濁酒聊一持。", "先生頗多事，斯心昧前知。", "亦復坐奇字，慘然亡所歸。"]'),
('db5ea295-2c0e-4810-9f4c-de4b0d2a92c5','晚泛浣花遂宿草堂','喻汝礪','宋','宋诗','song-poetry','','[]','扣橈泛澄虚，濯流睇幽芳。',108,'全唐诗/poet.song.91000.json','["扣橈泛澄虚，濯流睇幽芳。", "晚霙襯奇樹，夕霏媚疏篁。", "歸鳥亦暫閒，夜魄動初凉。", "忽焉衆星微，天髙月舒光。", "昔也杜陵子，澹然此茅堂。", "客至酒自斟，句得意已忘。", "云何常念饑，零落在道旁。", "古來技入神，一飯豈所望。", "吾輩天所窮，慨歌淚霑裳。"]'),
('6995a00b-de3a-4c1e-9435-959c4639e1ae','遊琴臺','喻汝礪','宋','宋诗','song-poetry','','[]','臯朔語類俳，上頗倡優之。',144,'全唐诗/poet.song.91000.json','["臯朔語類俳，上頗倡優之。", "嚴吾數預事，慘凛失所棲。", "慨彼猜忌姿，公卿命如絲。", "夫子迺謁閑，翩翩富丰儀。", "眷言彼姝子，深情結幽期。", "浩露泛酒甕，輕雲思琴徽。", "撫絃視八荒，頗覺秦岫低。", "紛紛漢諸子，悟解良獨遲。", "一朝不自保，頸血霑裳衣。", "公豈不炯戒，慮禍盖已微。", "污已迥前識，達生邁天倪。", "闊哉昭曠情，豈屑後代嗤。"]'),
('80539c82-b889-4ddc-94f8-622855105abd','草堂詩  其一','喻汝礪','宋','宋诗','song-poetry','','[]','燦燦詩翁錦里西，只緣詩好遂窮棲。',64,'全唐诗/poet.song.91000.json','["燦燦詩翁錦里西，只緣詩好遂窮棲。", "竹鋪冷色雲連寺，柳漾晴絲鳥過溪。", "凝怨不禁關樹暗，駐情應恨蜀山低。", "離人苦怕春歸盡，可忍紅英半著泥。"]'),
('744a7f7a-938f-433a-a550-724ade6ee579','草堂詩  其二','喻汝礪','宋','宋诗','song-poetry','','[]','閒把煙光次第陳，岷峨風物見精神。',64,'全唐诗/poet.song.91000.json','["閒把煙光次第陳，岷峨風物見精神。", "翻成錦繡千般様，供與江山幾處春。", "深屋長河元老大，蛾眉曼睩却逡巡。", "從公乞取無邊手，免作詩中半箇人。"]'),
('3633cfc6-7cac-4df1-bac4-bdfb70cf090f','草堂詩  其三','喻汝礪','宋','宋诗','song-poetry','','[]','從教日日敞窗扉，嫌怕風光入眼遲。',64,'全唐诗/poet.song.91000.json','["從教日日敞窗扉，嫌怕風光入眼遲。", "剩買芒鞋供看竹，趁乘春雨去裁榿。", "苦無賓客僧來後，薄有生涯鶴下時。", "聞道鄰翁酒初熟，新篘一酌莫相遺。"]'),
('2453b73a-bf22-4568-a8f6-95a6d642256c','草堂詩  其四','喻汝礪','宋','宋诗','song-poetry','','[]','遠嶼曲洲縱復横，沙邊繁鳥弄簫笙。',64,'全唐诗/poet.song.91000.json','["遠嶼曲洲縱復横，沙邊繁鳥弄簫笙。", "一軒檐冷松陰合，十里林香藥草生。", "路轉斷楂逢石坐，風移深竹見僧行。", "晚來冲抱更清曠，時有幽人带月耕。"]'),
('f437b136-730e-4e09-82ef-0e704d8927ca','草堂詩  其五','喻汝礪','宋','宋诗','song-poetry','','[]','亂後飄零歇此身，風光無賴更清新。',64,'全唐诗/poet.song.91000.json','["亂後飄零歇此身，風光無賴更清新。", "客懷易感酒添病，詩思苦慳花減春。", "南枝北枝鶯舌巧，前村後村雨脚匀。", "暫借溪邊老爲客，花心柳眼莫撩人。"]'),
('00a2ddd6-87ac-4369-8f5d-fc6ed0caf0fe','草堂詩  其六','喻汝礪','宋','宋诗','song-poetry','','[]','翠木搖艷溪之灣，游子失氣生愁酸。',64,'全唐诗/poet.song.91000.json','["翠木搖艷溪之灣，游子失氣生愁酸。", "誇力搏虎筋骨絕，雙流迸巘道路難。", "布衾多年窘夜雨，土銼無火啼夜餐。", "一生忠義老寂寞，旋燒竹葉供春寒。"]'),
('b659240c-baf1-4797-85e3-8648b5e3f40b','草堂詩  其七','喻汝礪','宋','宋诗','song-poetry','','[]','詩人以來誰者工，建安元嘉無此翁。',64,'全唐诗/poet.song.91000.json','["詩人以來誰者工，建安元嘉無此翁。", "維摩壁畔不到處，伽梨角邊無限風。", "孟郊空螯但彭越，何晏片甲非虬龍。", "先生住處在何許，我亦不知西北東。"]'),
('4bdecbe7-b8f5-4c56-ae8e-c1e4c98f4115','草堂詩  其八','喻汝礪','宋','宋诗','song-poetry','','[]','朝元閣邊瑶草芳，惟君之故遥相望。',64,'全唐诗/poet.song.91000.json','["朝元閣邊瑶草芳，惟君之故遥相望。", "人歸後雁關塞阻，思入南鳬離夢長。", "懸知同心兩相憶，剩欲共看千里光。", "金輿玉輦不復見，腸斷華清雲樹蒼。"]'),
('197066fd-713b-4cc5-af75-3fb32c332d2d','草堂詩  其九','喻汝礪','宋','宋诗','song-poetry','','[]','竹外清疏侵碧溪，谿邊竹澹煙雨霏。',64,'全唐诗/poet.song.91000.json','["竹外清疏侵碧溪，谿邊竹澹煙雨霏。", "閒看雪嶺題詩罷，醉散西郊信馬歸。", "霄漢直愁雙闕迥，夢魂長著五陵飛。", "故園秀木又春色，只恐歸去池臺非。"]'),
('a72e2d7b-1fbb-405b-a273-7c2ce51cd0c7','草堂詩  其一○','喻汝礪','宋','宋诗','song-poetry','','[]','錦宮城西春草芳，杜陵客子憂思長。',64,'全唐诗/poet.song.91000.json','["錦宮城西春草芳，杜陵客子憂思長。", "浴晴晚樹淡浮綠，臥水幽花深度香。", "交情憫憫言燕阻，舊國迤迤雲山蒼。", "白蘋洲渚落日晚，明邊正銜歸鴈行。"]'),
('fc7e8f47-ac34-491e-b3d2-dd9acc62b1ae','草堂詩  其一一','喻汝礪','宋','宋诗','song-poetry','','[]','浣花四月天氣和，綵舟翠旂樂莫過。',64,'全唐诗/poet.song.91000.json','["浣花四月天氣和，綵舟翠旂樂莫過。", "離人千里起遥怨，緩棹一曲浮靈波。", "惠風曇曇泛蘅杜，流雲演演逾關河。", "終然有懷春復夏，歸去灞滻眠汀莎。"]'),
('be423b4a-fec6-4275-8b3c-b4dfe2c3d798','草堂詩  其一二','喻汝礪','宋','宋诗','song-poetry','','[]','支策翳然林水間，蕭疏神韻淡風煙。',64,'全唐诗/poet.song.91000.json','["支策翳然林水間，蕭疏神韻淡風煙。", "滄浪亭畔各分手，杜宇聲中恰一年。", "自昔風人裁一骨，於今捫膝亦么弦。", "試看堂上百千海，餘子浮漚卻未全。"]'),
('8c95213b-3f41-40f4-b64b-d5ab01d4c737','題周昉美人拜月圖','喻汝礪','宋','宋诗','song-poetry','','[]','東風原自無消息，獨捲珠簾望春色。',64,'全唐诗/poet.song.91000.json','["東風原自無消息，獨捲珠簾望春色。", "風驚紅葉墮珊珊，夢斷行雲泣殘月。", "挹挹柔情不自持，此心端被月先知。", "窺窗入户如相伴，應是嬌娥慣别離。"]'),
('9e46dfa5-2164-4d74-9d77-0e9d28699bbe','散花樓','喻汝礪','宋','宋诗','song-poetry','','[]','濯錦江邊莎草濃，散花樓畔夭芙蓉。',32,'全唐诗/poet.song.91000.json','["濯錦江邊莎草濃，散花樓畔夭芙蓉。", "蜀山疊疊修門遠，誰把丹心問李鄘。"]'),
('3b24e3c7-2101-4340-a0aa-f1861d6e80e4','玉局洞石恪畫仙人四壁','喻汝礪','宋','宋诗','song-poetry','','[]','真人何年下紫清，目睛飄墮如流星。',226,'全唐诗/poet.song.91000.json','["真人何年下紫清，目睛飄墮如流星。", "至今玉洞通窈冥，蕭然紫室之威靈。", "杖履而來六月望，赤旱裂石風淒冷。", "屹然四壁呀欲動，神怪夭矯目喪睛。", "道與之貌非丹青，馭風而行誰使令。", "雲飛電掣集帝所，超然得意皆天人。", "異哉石子偉丈夫，胸中磊磊怪所儲。", "玄圃之山帝所居，子游其間墮雙鳬。", "不然安知天上有此樂，禿筆一掃凌方壺。", "細看毛骨分錙銖，偉形傑狀人人殊。", "古來列真誰所摹，前稱關同後張圖。", "近之豪者郭忠恕，落筆拂戾如奔諸。", "兩公軼蕩不拘束，筆力磊砢相劘扶。", "我來憑欄聊一呼，隨翁聯軒上清都。"]'),
('09855929-8e2d-44e1-87a4-d9791197cbda','上席帥','喻汝礪','宋','宋诗','song-poetry','','[]','先公御吏如御兵，迎刃而解如庖丁。',256,'全唐诗/poet.song.91000.json','["先公御吏如御兵，迎刃而解如庖丁。", "掀髯一笑黠吏走，蜀中草木知威名。", "伯兄渠渠天下士，嵩高少室之英靈。", "妙齡提書噭閶闔，谹議可以諧韶韺。", "昨年兩作益州牧，西南惡少不敢行。", "後來繼者有季弟，潭潭大度涵滄溟。", "指麾萬事不作意，決眥雨電風煙雲。", "南望峨眉西玉壘，逸氣夜與銀河傾。", "幅巾筇杖過何許，閑邀仲元訪君平。", "小蓬董寶夜吹笙，往往笑倒長庚星。", "拔劍起舞者誰子，杜陵老翁醉不醒。", "生平入眼無俗物，胡爲見我眼自青。", "武侯廟前有古柏，風吟雨嘯蛟龍聲。", "我來正欲刳爾腹，琢作巨屋丹其楹。", "琢作巨屋丹其楹，繪此落落三名卿。", "尚使千載知儀刑，喻子作詩如鼎銘。"]'),
('f76dffba-453c-4439-9717-51a1589fd38b','錦江思','喻汝礪','宋','宋诗','song-poetry','','[]','獨詠滄浪古岸邊，牽風柳带綠凝煙。',32,'全唐诗/poet.song.91000.json','["獨詠滄浪古岸邊，牽風柳带綠凝煙。", "得魚且斫金絲鱠，醉折桃花倚釣船。"]'),
('13af3c0c-1793-4327-94db-b0b7fb8a468f','隱德詩','喻汝礪','宋','宋诗','song-poetry','','[]','太虛八境初無二，中有道人常洞視。',386,'全唐诗/poet.song.91000.json','["太虛八境初無二，中有道人常洞視。", "借問道人何等公，從志其名聶其氏。", "華亭春酣戰桃李，香氣入簾人破睡。", "凌波微步度勞塵，梔子同心傳密意。", "道人不動如澄水，看破新裝小年紀。", "回身向郎郎忍棄，愁眺月華空掩涕。", "含羞轉態春百媚，而我定心初不起。", "世人悠悠初未知，故有冥籍還見記。", "儀州判官臨潁生，良原甲夜黄衣吏。", "手提淡墨但倉黄，門列陰兵更奇佹。", "昧爽堂皇勢呀豁，玉带神君氣高厲。", "靖國再拜呼使前，案頭吏抱百葉紙。", "數行具書一善事，聶君夜卻淫奔李。", "由來胸中無濁見，前塵百暗心常止。", "一室超然方隱几，入眼狂花亂飄墜。", "定情豈復顧條脫，合歡未許同陽燧。", "坐令密行動幽祇，棘使華年增一紀。", "出門仍問紫衣翁，陰誅與世無差異。", "百葉部中分次第，忠孝棄捐神所劓。", "殺生之報定何如，朝生暮死蜉蝣爾。", "踏翠裁紅可憐妓，濯足瓊漿被鞭箠。", "房公湖邊秋色裏，阿孫圖南前拜跪。", "扣頭授我如上事，願謁英篇書所以。", "我聞南曹北曹尺有咫，天知地知元密邇。"]'),
('6e0b521a-cb40-42ea-9237-78468b7e68e4','八陣圖','喻汝礪','宋','宋诗','song-poetry','','[]','魚復江邊春事起，萬點紅旗颺清泚。',390,'全唐诗/poet.song.91000.json','["魚復江邊春事起，萬點紅旗颺清泚。", "主人元是劉夢得，載酒娛賓水光裏。", "酒闌放脚步涉磧，細石作行相靡迤。", "臥龍起佐赤龍子，天地風雲入鞭箠。", "蛇盤虎翼飛鳥翔，四正四奇公所壘。", "當時二十四萬師，開門闔門隨臂指。", "幾回嚇殺生仲達，往往宵遁常騎豕。", "海中仙人丈二履，相與往來迂玉趾。", "笑云此公大肚皮，龍拏虎擲堆胸胃。", "江頭風波幾劘蕩，斷岸奔峰俱披靡。", "陽侯鏖戰三峽怒，祇此細石吹不起。", "晉大司馬宣武公，常山之蛇中首尾。", "幙中矹矹何物客，未有一客能解此。", "千年獨有老奇癲，見之斂袂三嘆喟。", "頗知此法自玄女，細與諸公剖根柢。", "君不見風后英謀儘奇詭，龕定蚩尤等蜉蟻。", "漢大將軍親閱試，四夷聞風皆褫氣。", "馬隆三千相角掎，西羌茸茸落牙嘴。", "而公於此出新意，蓋世功名無第二。", "不知何處著雙手，建立乃與天地比。", "河圖洛書亦如此，堂堂孔明今未死。", "我門生人如死人，老了不作一件事。", "卻被獮猴坐御床，孰眎天王出居汜。", "既不能蹠穿膝暴秦王庭，放聲七日哭不已。"]'),
('aecf2f52-ec4f-4d81-b060-58695f85e4de','仙鶴樓二首  其一','喻汝礪','宋','宋诗','song-poetry','','[]','果爲山中州，叢攢少平地。',24,'全唐诗/poet.song.91000.json','["果爲山中州，叢攢少平地。", "斗下金泉峰，十里掃空翠。"]'),
('8fa6f8c8-1645-4ba5-a1b2-b142b144f275','仙鶴樓二首  其二','喻汝礪','宋','宋诗','song-poetry','','[]','岧岧金泉峰，望望朝復夕。',24,'全唐诗/poet.song.91000.json','["岧岧金泉峰，望望朝復夕。", "凄冷雨中樹，曠朗雲外石。"]'),
('2155b83f-b84b-4567-be80-123a026d8b23','雲臺望鶴亭','喻汝礪','宋','宋诗','song-poetry','','[]','江山有英氣，草木多秀拔。',24,'全唐诗/poet.song.91000.json','["江山有英氣，草木多秀拔。", "仙聖之所廬，著眼盡現傑。"]'),
('457f2d1b-b30b-431c-a216-fb98d25a8f66','宿錦屏山暮景','喻汝礪','宋','宋诗','song-poetry','','[]','暝色輕煙罩郡城，漁舟燈火倒觀星。',32,'全唐诗/poet.song.91000.json','["暝色輕煙罩郡城，漁舟燈火倒觀星。", "寒山遠水江村暮，自在粧成水墨屏。"]'),
('c2a9e692-9dfe-429e-bc6d-f98a1b2a887b','下巖寺二首  其一','喻汝礪','宋','宋诗','song-poetry','','[]','徑向山腰轉，門從水面開。',48,'全唐诗/poet.song.91000.json','["徑向山腰轉，門從水面開。", "片雲巖下宿，一鉢朔方來。", "落日鳥衝樹，輕雲花覆苔。", "惟應荔枝熟，時躡白雲回。"]'),
('865070fe-b6b3-4c08-bda0-c8b52b704a8e','下巖寺二首  其二','喻汝礪','宋','宋诗','song-poetry','','[]','路暗松杉密，天空霧雨開。',48,'全唐诗/poet.song.91000.json','["路暗松杉密，天空霧雨開。", "山容依檻轉，鳥影渡江來。", "汲水僧歸寺，啣花鹿印苔。", "年年蠶麥熟，貧道啜齋回。"]'),
('6e6b94fa-9c86-4599-bba9-a9edc342bec5','句  其一','喻汝礪','宋','宋诗','song-poetry','','[]','捫膝來爲普慈守，先生懸車在林藪。',16,'全唐诗/poet.song.91000.json','["捫膝來爲普慈守，先生懸車在林藪。"]'),
('6ba4f407-2c3a-4e38-b991-929ae0dd95e4','句  其二','喻汝礪','宋','宋诗','song-poetry','','[]','閑尋物理幽。',6,'全唐诗/poet.song.91000.json','["閑尋物理幽。"]'),
('b3ad7b17-cb28-4edb-872e-9b8e806144c9','句  其三','喻汝礪','宋','宋诗','song-poetry','','[]','寒林春自芳。',6,'全唐诗/poet.song.91000.json','["寒林春自芳。"]'),
('8591ac7b-e15a-411c-96a7-77c770599ae1','句  其四','喻汝礪','宋','宋诗','song-poetry','','[]','借問幾時辭碧落。',8,'全唐诗/poet.song.91000.json','["借問幾時辭碧落。"]'),
('d4690769-4be6-4602-8a38-4d4de1930f04','聞車駕幸秘府二首  其一','張綱','宋','宋诗','song-poetry','','[]','一聲清蹕九天來，睿主崇文寶運開。',64,'全唐诗/poet.song.91000.json','["一聲清蹕九天來，睿主崇文寶運開。", "光動石渠春滉漾，香浮芸閣晝徘徊。", "天顔有喜垂清問，御筆親題仰聖才。", "鉛槧小臣空悵望，五雲深處認蓬莱。"]'),
('cf9a6205-32b3-4516-ae67-753cefd382b6','聞車駕幸秘府二首  其二','張綱','宋','宋诗','song-poetry','','[]','春旗簇仗石渠邊，東壁分明帝座前。',64,'全唐诗/poet.song.91000.json','["春旗簇仗石渠邊，東壁分明帝座前。", "八品微官恩有地，七年通籍願瞻天。", "心馳魏闕何時到，身滯周南祗自憐。", "遙想道山雲集處，幾多光寵被羣賢。"]'),
('aceeac59-8143-49df-9d1b-e507172509e1','次韻王子飛跋石曼卿洛中題壁','張綱','宋','宋诗','song-poetry','','[]','酒狂翫世芙蓉仙，胸中落落太古全。',64,'全唐诗/poet.song.91000.json','["酒狂翫世芙蓉仙，胸中落落太古全。", "浮雲富貴不着眼，肯復騰上誇鳶肩。", "應怪元龍負豪氣，獻書天子言十事。", "騎騾一去不可追，風月凄凉壁間字。"]'),
('c0bceb88-2ade-4017-a9d1-a4f7103312f5','九日陳少陽同戴國衡王虞章游天清寺菊坡不蒙踐約次韻少陽','張綱','宋','宋诗','song-poetry','','[]','太丘道廣固難周，自有良朋結勝游。',64,'全唐诗/poet.song.91000.json','["太丘道廣固難周，自有良朋結勝游。", "莫使彈琴防性氣，只堪尋竹占清幽。", "三篇解索詩償債，一醉那無酒喚愁。", "貧甚淵明在環堵，忍教空負菊花秋。"]'),
('38b42a38-6f5c-4e53-92a7-706541b89a37','次韻國衡','張綱','宋','宋诗','song-poetry','','[]','古寺凴崇岡，蒼烟蔭喬木。',144,'全唐诗/poet.song.91000.json','["古寺凴崇岡，蒼烟蔭喬木。", "欹斜屋鱗比，繚繞牆带束。", "何人闢層軒，延客寄遐矚。", "醉賞菊坡下，客意豈在菊。", "念昔居此地，名世盡儒服。", "師曠賢多知，蒼史聖重目。", "臺成竟誰游，事去不容跼。", "梁王髙帝孫，名字亦不辱。", "當時盛歌舞，肯使後人逐。", "陳跡今故存，新池爲誰綠。", "感歎世上事，反覆如轉燭。", "請君聽鍾魚，尚想吹紫玉。"]'),
('f274ff14-b7fa-4c82-b3a0-1889e474cfce','次韻虞章','張綱','宋','宋诗','song-poetry','','[]','軌道無停轍，楓林難盡柯。',168,'全唐诗/poet.song.91000.json','["軌道無停轍，楓林難盡柯。", "人生百年間，疾若下走坡。", "何爲行役苦，况乃憂患多。", "淵明頗解事，舍濁揚清波。", "九原骨已朽，萬古名不磨。", "念我獨窘束，處世隨唯阿。", "塵埃眼中滿，歲月馬上過。", "不作鷄肋棄，尚扣牛角歌。", "正賴良友朋，詩句陶天和。", "涓涓吐微溜，浩浩供洪河。", "三篇怯大手，未陳先倒戈。", "借問菊坡游，頗亦狂醉麽。", "獨不飲公榮，冷面看紅酡。", "欲賦無好語，書懷愧陰何。"]'),
('bd957503-bb26-4aaa-88e2-ad870be3a2d0','書懷','張綱','宋','宋诗','song-poetry','','[]','紛紛兒輩謾同時，獨負權奇不受羈。',64,'全唐诗/poet.song.91000.json','["紛紛兒輩謾同時，獨負權奇不受羈。", "刻燭已驚詩句逸，飛觴肯放酒行遲。", "平生白璧休三歎，萬事黄粱僅一炊。", "誰向先賢得風制，空令人笑虎頭癡。"]'),
('df773bf9-7c11-4727-a861-d42b56ddfaf2','夜飲二首  其一','張綱','宋','宋诗','song-poetry','','[]','大木千章難近用，朱絃三歎有遺音。',32,'全唐诗/poet.song.91000.json','["大木千章難近用，朱絃三歎有遺音。", "微言欲扣會心處，濁酒不妨隨意斟。"]'),
('649072d8-0449-4cc5-8dcc-e75439c9b561','夜飲二首  其二','張綱','宋','宋诗','song-poetry','','[]','年少詩狂不自禁，那堪客裏聽孤砧。',32,'全唐诗/poet.song.91000.json','["年少詩狂不自禁，那堪客裏聽孤砧。", "窗寒夜半月初上，酒盡欲眠愁更深。"]'),
('cd4d3957-73e3-423d-bed0-1436a956a4cd','戲張處文二首  其一','張綱','宋','宋诗','song-poetry','','[]','禪房深夜雨蕭蕭，只有青燈伴寂寥。',32,'全唐诗/poet.song.91000.json','["禪房深夜雨蕭蕭，只有青燈伴寂寥。", "咫尺嬋娟鎖朱戶，不知何日枉佳招。"]'),
('4e3d1722-c4d2-433b-a4a4-e33ef76bd028','戲張處文二首  其二','張綱','宋','宋诗','song-poetry','','[]','延賓北海坐常滿，不飲公榮亦太慳。',32,'全唐诗/poet.song.91000.json','["延賓北海坐常滿，不飲公榮亦太慳。", "病渇固應難與酒，嘯歌元自不相關。"]'),
('3883213a-a69f-473b-a1b0-fa62a7f946e6','春末桃李盛開竹間有梅一枝嶷然秀發用唐子西韻簡汪彦章','張綱','宋','宋诗','song-poetry','','[]','在處朱朱兼白白，化工伎倆真多色。',64,'全唐诗/poet.song.91000.json','["在處朱朱兼白白，化工伎倆真多色。", "誰知先生鐵石心，到眼物華如過客。", "髙標可但凌三冬，一枝傑出妖艷中。", "椒蘭絳灌信鼎貴，萬世屈賈留清風。"]'),
('048226c1-bfe2-46b5-861c-1d2597901e9f','館職上元宴集葆真宫以病不赴次龔濬之韻','張綱','宋','宋诗','song-poetry','','[]','春融凖擬千塲醉，底事年來興易厭。',32,'全唐诗/poet.song.91000.json','["春融凖擬千塲醉，底事年來興易厭。", "滿眼笙歌招不出，獨哦詩句遶窮簷。"]'),
('0a567132-b667-41a6-a8b5-cd9901d7324c','鄭樞密生日五首  其一','張綱','宋','宋诗','song-poetry','','[]','黄閣曾居百辟尊，經綸相業滿乾坤。',64,'全唐诗/poet.song.91000.json','["黄閣曾居百辟尊，經綸相業滿乾坤。", "化行風雨年年節，恩到桑麻處處村。", "付與斗樞深拱極，安排鼎鉉再調元。", "贊襄好爲蒼生計，天子文思納盡言。"]'),
('a0ec064c-7869-42ed-bcdf-27898b4e2f39','鄭樞密生日五首  其二','張綱','宋','宋诗','song-poetry','','[]','朝來佳氣滿樞庭，知是君王用老成。',64,'全唐诗/poet.song.91000.json','["朝來佳氣滿樞庭，知是君王用老成。", "素倚房喬關大事，政須裴度張威名。", "三千奏上深憂國，百萬功成看偃兵。", "聽取啼禽催布穀，便將霖雨發春耕。"]'),
('f2163e74-6597-415a-9abd-82a3c88db40b','鄭樞密生日五首  其三','張綱','宋','宋诗','song-poetry','','[]','袞衣廊廟孰推先，元老勳名自卓然。',64,'全唐诗/poet.song.91000.json','["袞衣廊廟孰推先，元老勳名自卓然。", "忠概明堂尊一柱，神鋒長劍倚中天。", "定知闢國功歸召，已見疏封地得燕。", "相業蟬聯應未艾，少翁家學似韋賢。"]'),
('83a1bb5e-be5d-4b53-8573-269db904de71','鄭樞密生日五首  其四','張綱','宋','宋诗','song-poetry','','[]','此日君恩特地深，傳呼星使自天臨。',64,'全唐诗/poet.song.91000.json','["此日君恩特地深，傳呼星使自天臨。", "鸞臺鳯閣滿春色，燕語鶯啼俱好音。", "駿極共歌申降嶽，對揚真賴傅爲霖。", "青氈豈待金甌卜，自有公言格帝心。"]'),
('b1fd8e62-27ca-4e0f-9bb7-d259ec077705','鄭樞密生日五首  其五','張綱','宋','宋诗','song-poetry','','[]','推轂當時起陸沈，巴渝祗恐累知音。',64,'全唐诗/poet.song.91000.json','["推轂當時起陸沈，巴渝祗恐累知音。", "十年謬許門人列，一報長懷國士心。", "沙路待看新築穩，桃陰應念舊蹊深。", "酸寒尚有男兒志，忍使霜華兩鬢侵。"]'),
('3a58c890-6f07-4a0a-8cf0-29c0c02818d3','代人上鄭相生日三首 壽星','張綱','宋','宋诗','song-poetry','','[]','瑞霧祥烟滿絳霄，詔開黄閣宴生朝。',128,'全唐诗/poet.song.91000.json','["瑞霧祥烟滿絳霄，詔開黄閣宴生朝。", "鈞天合奏御香滿，百辟紫宸初散朝。", "流花寶爵傳宣勸，歡聲自逐和風轉。", "四方争獻壽星圖，祝公千歲身長健。", "畫手丹青妙入神，煌煌列宿能寫真。", "貂冠玉带畫中見，便是凌烟閣上人。", "偉哉風骨神仙裔，主張壽禄來塵世。", "不須更占南極星，看取老人朝玉帝。"]'),
('bb207164-38be-47e5-9913-bc5ccb444ffb','代人上鄭相生日三首 壽香','張綱','宋','宋诗','song-poetry','','[]','上方有國名衆香，經行苑囿皆芬芳。',128,'全唐诗/poet.song.91000.json','["上方有國名衆香，經行苑囿皆芬芳。", "世人豈識天香界，但知蘇合及都梁。", "博山氤氳吐微竇，一炷香嬰凈塵垢。", "散成五色空中雲，持獻現前無量壽。", "我公宿悟香嚴因，應緣來現宰官身。", "妙香密圓證無漏，總持不動真天人。", "熏陶四海看無際，便是經行衆香地。", "獻香陋語應已聞，羅筏寧論幾千里。"]'),
('490e5035-550b-42d2-b2b0-339233efa4c9','代人上鄭相生日三首 壽燭','張綱','宋','宋诗','song-poetry','','[]','凝香紅蠟大如椽，華堂兩兩排金蓮。',128,'全唐诗/poet.song.91000.json','["凝香紅蠟大如椽，華堂兩兩排金蓮。", "漏澀銅壺寒夜永，光搖翠幄爭春妍。", "蘭膏芳苡何足道，簾卷香風碧煙裊。", "霜蛾勿用拂麟鬚，合就仙丹會難老。", "我公身依日月光，不假仙丹亦壽康。", "煌煌神燭照天下，光焰何止萬丈長。", "世間爝火知無助，想像丹輝爭欲賦。", "可憐賤士老不才，短檠見跋無佳句。"]'),
('93cdacb8-12da-4c2c-98b8-fbfb7df29787','送趙承之出守鄧州','張綱','宋','宋诗','song-poetry','','[]','蓬萊宮中老仙伯，一首詩堪萬人敵。',128,'全唐诗/poet.song.91000.json','["蓬萊宮中老仙伯，一首詩堪萬人敵。", "胡不佩劍趨明光，要試南陽二千石。", "南陽異時名帝鄉，蘘山菊水秋風香。", "民歌召杜向千載，至今遺俗皆農桑。", "使君此去殊不惡，坐嘯風流有餘樂。", "堂前畫燭照紅粧，席上枯棋響飛雹。", "行看璽書下赤墀，旌旗夾道生光輝。", "應念斯文要羽翼，歸來九萬翔天池。"]'),
('4674e591-7571-4b07-a70f-0a980a0e8a39','謁蔣仲遠坐中出所知和徐學士詩歸而次韻二首是日飲仲遠宅見二侍兒  其一','張綱','宋','宋诗','song-poetry','','[]','剝啄龍門未厭頻，履聲容易出雲津。',64,'全唐诗/poet.song.91000.json','["剝啄龍門未厭頻，履聲容易出雲津。", "求羊徑掃無它客，王謝堂前宴令辰。", "心醉不知簾外雨，眼花唯覺坐中春。", "留連更欲窮歡賞，惆悵金壺啟夕淪。"]'),
('7dfb62ce-d6f2-4883-a26e-0ac263da22be','謁蔣仲遠坐中出所知和徐學士詩歸而次韻二首是日飲仲遠宅見二侍兒  其二','張綱','宋','宋诗','song-poetry','','[]','不須乘月坐胡床，簾底高張蜜炬香。',64,'全唐诗/poet.song.91000.json','["不須乘月坐胡床，簾底高張蜜炬香。", "隨意尊罍供北海，等閑談論到羲皇。", "三朝舊德真忘分，一介微官倍有光。", "禮絕百寮明日事，可能重許上公堂。"]'),
('a63a22f1-8502-43c6-8b29-2cfbb83d0aec','謝周仲弼寄新米','張綱','宋','宋诗','song-poetry','','[]','索米長安甑欲塵，斗升分惠意何親。',64,'全唐诗/poet.song.91000.json','["索米長安甑欲塵，斗升分惠意何親。", "無煩子罕出公粟，自有叔牙知我貧。", "指囷高風懷國士，翻匙佳句憶詩人。", "他年若遂歸田去，盡種香秔老此身。"]'),
('2f6c13cf-94f5-428b-b861-d6ca619eaffd','索仲弼和詩且邀奕','張綱','宋','宋诗','song-poetry','','[]','佳言吐屑破春溫，落落胸懷自不羣。',64,'全唐诗/poet.song.91000.json','["佳言吐屑破春溫，落落胸懷自不羣。", "百萬買鄰輕去我，十千沽酒屢思君。", "懶償詩債緣何事，熟讀棋經要異聞。", "挑戰會從今日始，待嚴旗鼓送奔軍。"]'),
('8b130cc7-f4df-491d-9934-c765d4670ea5','次韻彥章秋夜有感','張綱','宋','宋诗','song-poetry','','[]','萬籟沉沉夜色幽，倚樓長嘯雜吳謳。',64,'全唐诗/poet.song.91000.json','["萬籟沉沉夜色幽，倚樓長嘯雜吳謳。", "干時不利羞魚沫，廩食無功類鼠偷。", "已欲忘言聊卒歲，尚餘豪氣獨悲秋。", "麴生胗味真吾友，誰解招呼與解愁。"]'),
('ad14c410-6560-4886-929d-bf017135680e','秋日野望','張綱','宋','宋诗','song-poetry','','[]','秋雲來不斷，野色浩無窮。',48,'全唐诗/poet.song.91000.json','["秋雲來不斷，野色浩無窮。", "興逸煩襟外，詩成醉眼中。", "懷鄉看宿鳥，轉物悟飛蓬。", "何日江南去，新鱸鱠筯紅。"]'),
('fb4b8bd0-cd90-487e-9237-5894724fe00b','謝洪察院送酒','張綱','宋','宋诗','song-poetry','','[]','嗜酒劉伶絕世無，春衫典盡倒天壺。',64,'全唐诗/poet.song.91000.json','["嗜酒劉伶絕世無，春衫典盡倒天壺。", "造門誰爲傾家釀，見客常留滿眼沽。", "頗訝霜威太嚴令，忽分春色到焦枯。", "一尊且作通宵醉，明日重看朝夕烏。"]'),
('b0a6e4ee-a590-406a-b735-7b9ef426103f','次韻陳去非中秋無月','張綱','宋','宋诗','song-poetry','','[]','蕭瑟中宵雨打窗，那知風月亂飄黄。',64,'全唐诗/poet.song.91000.json','["蕭瑟中宵雨打窗，那知風月亂飄黄。", "已無佳月供清賞，賴有新詩耿夜光。", "蓬戶我方甘寂寞，朱門君勿看輝煌。", "只今天柱峰何在，好約玄真一醉狂。"]'),
('ad5c9675-b150-4511-93b1-485fe6eabf97','送杜子從赴成都倅','張綱','宋','宋诗','song-poetry','','[]','結束征鞍去欲奔，行行折柳送都門。',64,'全唐诗/poet.song.91000.json','["結束征鞍去欲奔，行行折柳送都門。", "壯懷未用看雙鬢，祖席何妨醉一尊。", "玉局仙遊成獨往，草堂詩句與誰論。", "懸知别乘風流處，醉倚紅粧笑語温。"]'),
('3f49e378-5962-4c60-8cfc-5a76cd605c45','友人哭內作詩次韻','張綱','宋','宋诗','song-poetry','','[]','奉倩傷情愛所鍾，佳人難再豈天窮。',64,'全唐诗/poet.song.91000.json','["奉倩傷情愛所鍾，佳人難再豈天窮。", "登臺曾是吹簫侣，對影今爲舞鏡雄。", "虚案故應愁午飯，小窗誰與伴春風。", "夜深它帳遙聞語，莫怨朝來無是公。"]'),
('20498d8f-891f-401a-8faa-e494d13149a2','戲題所見','張綱','宋','宋诗','song-poetry','','[]','破睡輕風透碧紗，寶釵聊插任欹斜。',32,'全唐诗/poet.song.91000.json','["破睡輕風透碧紗，寶釵聊插任欹斜。", "欲尋女伴嬉遊去，試問鞦韆有幾家。"]'),
('d2781303-3ea4-4139-9edd-a9b1b5ea9520','候張彦智承出','張綱','宋','宋诗','song-poetry','','[]','縈蛇路轉惬登臨，一室翛然客静心。',32,'全唐诗/poet.song.91000.json','["縈蛇路轉惬登臨，一室翛然客静心。", "杖履主人山下去，風鳴岩壑自幽深。"]'),
('23412635-9714-4ea4-bce5-303d6bd52c7d','用前韻索彦智和詩','張綱','宋','宋诗','song-poetry','','[]','老將詩壇數按臨，詞鋒疑有受降心。',32,'全唐诗/poet.song.91000.json','["老將詩壇數按臨，詞鋒疑有受降心。", "夜嚴旗鼓吾將勉，只恐秦師壁已深。"]'),
('82a68ae5-b0b9-430e-b263-06b0a8bd86df','彦智贈汧泉一斗使僕淬礪斤斧出長松矯矯之姿甚大惠也因成小詩寄謝昔李太白作詩三千首自謂不直一杯水今詩四句耳較之不直涓滴乃欲酬一斗之贈無乃太鮮乎','張綱','宋','宋诗','song-poetry','','[]','纍纍弱蔓繞長松，未放蒼龍舞太空。',32,'全唐诗/poet.song.91000.json','["纍纍弱蔓繞長松，未放蒼龍舞太空。", "賴有霜刀堪一割，謝公汧水爲磨礱。"]'),
('48c86d5e-cffe-49be-84f9-1b3159f7ecae','喜門客至','張綱','宋','宋诗','song-poetry','','[]','簷桷縱横僅滿筵，維摩病室故蕭然。',64,'全唐诗/poet.song.91000.json','["簷桷縱横僅滿筵，維摩病室故蕭然。", "焚香静掃床前地，宴坐超觀物外天。", "容膝不妨元亮醉，下帷誰識仲舒賢。", "白頭千里來相就，知是吾兒幾世緣。"]'),
('2cc9c9ec-1418-4b92-9d33-54b7453f1b38','讀周仲弼雪中友人過訪詩次其韻','張綱','宋','宋诗','song-poetry','','[]','騎馬走天闕，着破幾狐裘。',108,'全唐诗/poet.song.91000.json','["騎馬走天闕，着破幾狐裘。", "功名藐未涯，日月去不留。", "從來舌本彊，游談愧枚鄒。", "閉門有樂地，未用兒女憂。", "故人寄新詩，卷軸紅牙頭。", "飄然雪中作，乘興將誰謀。", "相與情未疏，連夜飛輕舟。", "此身一縷微，豈待萬戶侯。", "有酒且共樂，貧交乃勝游。"]'),
('2e5e001a-3738-4f75-a13c-acf6be10fb92','次韻仲弼重九','張綱','宋','宋诗','song-poetry','','[]','黄花白酒兩相逢，把酒簪花對晚風。',64,'全唐诗/poet.song.91000.json','["黄花白酒兩相逢，把酒簪花對晚風。", "千里故園雲水外，三年歸路夢魂中。", "自憐晼晚傷秋色，誰解疏狂發醉紅。", "寄語髯周頗知否，此時情緒與君同。"]'),
('a57c3410-9d9d-4cbd-8bb7-9ec43057c751','送姪合赴省試三首  其一','張綱','宋','宋诗','song-poetry','','[]','破的雄鄉國，擔簦上帝京。',48,'全唐诗/poet.song.91000.json','["破的雄鄉國，擔簦上帝京。", "路夷驤逸驥，天闊轉飛鯨。", "學就千人敵，名歸四海争。", "莫言年少在，歲月易峥嶸。"]'),
('8b6b1823-f6ed-4aa4-abc6-52f7414cb8f5','送姪合赴省試三首  其二','張綱','宋','宋诗','song-poetry','','[]','黄卷新儒業，青錢舊世家。',48,'全唐诗/poet.song.91000.json','["黄卷新儒業，青錢舊世家。", "征衣輕遠别，祖席倍歡譁。", "雲薄堯天近，山昏楚日斜。", "髙堂朝夕念，擢桂是生涯。"]'),
('52baa7bc-4879-46bb-a9df-b11e94d58bfc','送姪合赴省試三首  其三','張綱','宋','宋诗','song-poetry','','[]','聖主收羣策，終軍正妙年。',48,'全唐诗/poet.song.91000.json','["聖主收羣策，終軍正妙年。", "精神揮玉雪，翰墨灑雲烟。", "舊學嗟予老，衰宗繼汝賢。", "决科須第一，慎勿棄青氈。"]'),
('ae3b82dd-680c-42b2-af8c-8262985f4563','次韻蘇養直破虜謠','張綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','旌旗千里照江紅，學語小兒争挽弓。',96,'全唐诗/poet.song.91000.json','["旌旗千里照江紅，學語小兒争挽弓。", "春風江岸草無際，馬蹄踏遍青茸茸。", "將軍面作石稜紫，百萬胡羣陣前死。", "游魂假息度長江，京觀應慚望西滸。", "蘇侯筆力壯三軍，破虜長謠入眼驚。", "何當更獻中興頌，坐看萬國朝神京。"]'),
('891df1b2-7f69-47ff-9a3d-2372fb8d0278','次韻仲弼  其一','張綱','宋','宋诗','song-poetry','','[]','髙臥元龍百尺樓，飽看風月自忘憂。',64,'全唐诗/poet.song.91000.json','["髙臥元龍百尺樓，飽看風月自忘憂。", "雖無濁酒招陶令，尚有枯棋伴奕秋。", "俗事可堪遮眼底，愁情終莫上眉頭。", "襟懷落落誰能測，方寸端容萬斛舟。"]'),
('5e67c4a7-c95c-4fbb-b3e9-c60758819b1e','次韻仲弼  其二','張綱','宋','宋诗','song-poetry','','[]','千里長懷北固樓，客居顔巷不堪憂。',64,'全唐诗/poet.song.91000.json','["千里長懷北固樓，客居顔巷不堪憂。", "清熒坐看孤燈夜，搖落初驚一葉秋。", "已厭清談揮麈尾，誰能細字寫蠅頭。", "蒓鱸固是吾家味，好約西風買釣舟。"]'),
('b973a846-2f6f-4819-acbf-940a1912ce8c','次韻李傳道感事','張綱','宋','宋诗','song-poetry','','[]','臥病何人爲掃門，墮霜黄葉任繽紛。',64,'全唐诗/poet.song.91000.json','["臥病何人爲掃門，墮霜黄葉任繽紛。", "旋沽濁酒難禁醉，厭數孤砧遠更聞。", "冉冉生涯飄似夢，悠悠心緒亂如雲。", "幾時得遂江湖去，野性終隨鷗鷺羣。"]'),
('544a2b81-9f34-4709-979d-fa1f37513419','聞官軍掩殺城中羣寇次傳道韻','張綱','宋','宋诗','song-poetry','','[]','未復錢塘郡，先收鐵瓮城。',48,'全唐诗/poet.song.91000.json','["未復錢塘郡，先收鐵瓮城。", "妖星隨月落，殺氣逐參橫。", "已築鯨鯢觀，重新鼓角聲。", "大江應好在，流恨幾時平。"]'),
('4304fe0a-37dc-4421-ad76-64fb53b52762','飲散','張綱','宋','宋诗','song-poetry','','[]','懶性時難合，愁腸酒易醺。',48,'全唐诗/poet.song.91000.json','["懶性時難合，愁腸酒易醺。", "雨聲窗外過，客語夢中聞。", "借問安邦策，誰堪破賊羣。", "可憐吾老矣，生意薄如雲。"]'),
('6e29ddf5-daad-4e28-b963-ffe6ac726447','聞鎮江賊平','張綱','宋','宋诗','song-poetry','','[]','賊隨寛詔免，恩浹大江浮。',48,'全唐诗/poet.song.91000.json','["賊隨寛詔免，恩浹大江浮。", "人少餘新市，城荒剩古丘。", "瘡痍誰共理，宵旰獨深憂。", "莫上西樓望，黄雲滿眼愁。"]'),
('3020af0a-6c24-49d7-8fe8-e9b11507af7b','次韻彦智夜歸三首  其一','張綱','宋','宋诗','song-poetry','','[]','餘年知有幾，時過如激箭。',60,'全唐诗/poet.song.91000.json','["餘年知有幾，時過如激箭。", "况乃世味惡，酸辛幾嘗徧。", "朝來忽覽鏡，坐嘆華髪變。", "故人尚青眼，危論排月旦。", "慰我出新詩，驪珠有餘燦。"]'),
('89c08d7a-ab1b-4add-934e-1e6f3da394f4','次韻彦智夜歸三首  其二','張綱','宋','宋诗','song-poetry','','[]','國步何多艱，戎虜尚傳箭。',60,'全唐诗/poet.song.91000.json','["國步何多艱，戎虜尚傳箭。", "萬里眇寰海，澒洞風塵徧。", "其間蟣虱臣，亦作豺狼變。", "中興賴明主，掃除在一旦。", "凴君深夜望，已失妖星燦。"]'),
('126d769e-2482-4726-9cc6-9487ffb9dc7c','次韻彦智夜歸三首  其三','張綱','宋','宋诗','song-poetry','','[]','扁舟連夜發，歸興急如箭。',60,'全唐诗/poet.song.91000.json','["扁舟連夜發，歸興急如箭。", "喪亂男女悲，一息萬慮徧。", "人生豈匏繫，事業有豹變。", "聖主纂洪業，廟堂用伊旦。", "拔茅到公等，王道何其燦。"]'),
('a9f6106f-98c4-471f-83a5-9bbf728adc7f','次韻蘇晉翁見寄','張綱','宋','宋诗','song-poetry','','[]','不見梁王舊吹臺，年來愁眼向誰開。',128,'全唐诗/poet.song.91000.json','["不見梁王舊吹臺，年來愁眼向誰開。", "求賢廊廟無虚日，報國涓塵自乏才。", "直指漫能迎櫑具，永懷寧敢咏金罍。", "相看鬢髪霜千丈，自視文章水一杯。", "晚歲可憐神氣索，故人猶寄好詩來。", "追還正始真堪喜，突過黄初豈易陪。", "婉孌也知能度曲，葡萄應已釀新醅。", "何時東閣容驚坐，一日那辭一百迴。"]'),
('786e31e4-54b3-467d-9962-c9056a39b908','傷春','張綱','宋','宋诗','song-poetry','','[]','老來心事不禁春，風物相撩入眼新。',64,'全唐诗/poet.song.91000.json','["老來心事不禁春，風物相撩入眼新。", "苦索吟哦成底急，且休拘束任吾真。", "有錢買酒須饒醉，無事看山莫厭頻。", "憂國只今夔契在，應容衰疾伴樵人。"]'),
('c8706b13-9fda-4857-b195-f0bf01727caf','用前韻送春','張綱','宋','宋诗','song-poetry','','[]','滿眼鶯花自在春，送春情緒怯愁新。',64,'全唐诗/poet.song.91000.json','["滿眼鶯花自在春，送春情緒怯愁新。", "鼓琴不用戴安道，行酒卻須温太真。", "晚歲深交能有幾，相逢爛醉莫辭頻。", "新條更有明年在，重與東風作主人。"]'),
('7fdd66b8-70fa-4a66-9d1d-b7d270a1b265','次韻傳道夜觀牡丹','張綱','宋','宋诗','song-poetry','','[]','年來春事不相關，一笑除非醉裏拚。',64,'全唐诗/poet.song.91000.json','["年來春事不相關，一笑除非醉裏拚。", "未信花枝憎白髪，且隨月色傍朱欄。", "他時拜賜猶能記，此夜傷心更忍看。", "姚魏風流渾謾與，坐來雙泪落金盤。"]'),
('6d92af8b-942c-46da-88bb-544a9806c67d','七月晦','張綱','宋','宋诗','song-poetry','','[]','七月忽逢晦，悲秋竟若何。',48,'全唐诗/poet.song.91000.json','["七月忽逢晦，悲秋竟若何。", "破羌無妙略，中聖有狂歌。", "世味羞嘗鼎，心源欲静波。", "由來麋鹿性，幽興滿烟莎。"]'),
('38faafc0-2af3-4965-90e3-6c2f1c1f001d','歸鄉','張綱','宋','宋诗','song-poetry','','[]','窮巷歸來已白頭，結茅何必榜休休。',64,'全唐诗/poet.song.91000.json','["窮巷歸來已白頭，結茅何必榜休休。", "好山當戶碧雲晚，明月滿谿寒葦秋。", "詩社縱添新句法，醉鄉難覓舊交遊。", "平生幸自無機械，一棹夷由去狎鷗。"]'),
('523d9b73-88b4-4ae6-a032-9b80d4f34e17','用前韻','張綱','宋','宋诗','song-poetry','','[]','愁來莫遣上眉頭，着酒驅除醉即休。',64,'全唐诗/poet.song.91000.json','["愁來莫遣上眉頭，着酒驅除醉即休。", "未省一官堪送老，已驚雙鬢不禁秋。", "收心香火供清夢，洗眼雲溪結勝遊。", "喚取短篷乘晚興，坐看烟浪没輕鷗。"]'),
('0ec48438-b5e3-4733-81bb-378495906cbf','對月','張綱','宋','宋诗','song-poetry','','[]','蓬鬢秋風老，柴門轍跡疏。',48,'全唐诗/poet.song.91000.json','["蓬鬢秋風老，柴門轍跡疏。", "誰同今夜月，望絕故人書。", "止酒愁元亮，何心賦子虚。", "得詩還喜誦，習氣未全除。"]'),
('00410a82-7547-4118-91a3-d6f204061779','避寇艤舟遇雪','張綱','宋','宋诗','song-poetry','','[]','西山羣盜欲侵凌，小艇移家傍險行。',64,'全唐诗/poet.song.91000.json','["西山羣盜欲侵凌，小艇移家傍險行。", "遮眼亂雲方合沓，向人飛雪忽縱橫。", "心憂出穴虎狼近，身似遶枝烏鵲驚。", "天闊此時難借問，地偏何處可偷生。"]'),
('87660c12-4be7-4915-b54d-2133b4d4189b','用前韻','張綱','宋','宋诗','song-poetry','','[]','雪花吹面凍凌凌，客路艱危敢緩行。',64,'全唐诗/poet.song.91000.json','["雪花吹面凍凌凌，客路艱危敢緩行。", "春酒可賖三日近，野梅初見一枝橫。", "傷時在處愁先滿，討賊無期夢自驚。", "誰解山東問消息，謝公應起爲蒼生。"]'),
('c0169dd8-a7c5-471c-9719-2b5a4f65c4de','泊舟廟灣次姪合','張綱','宋','宋诗','song-poetry','','[]','泊船髙岸曲，散策小村傍。',48,'全唐诗/poet.song.91000.json','["泊船髙岸曲，散策小村傍。", "盜賊耳邊滿，朝廷天際望。", "繫愁官柳嫩，醒醉野梅香。", "後進推吾子，詞鋒不可當。"]'),
('f9accb18-6fe2-49ac-994e-5978dbb5a67f','春耕','張綱','宋','宋诗','song-poetry','','[]','亂後荒田杞棘生，歸來還喜見春耕。',64,'全唐诗/poet.song.91000.json','["亂後荒田杞棘生，歸來還喜見春耕。", "隨犁細雨濛濛濕，轉壠新泉聒聒鳴。", "好勸賣刀添健犢，盡令長畝種香秔。", "腐儒一飽真餘事，莫遣閭閻有歎聲。"]'),
('4be353b1-75ed-4baf-9047-615db06fa16b','次韻黄堯翁鬭雞三首  其一','張綱','宋','宋诗','song-poetry','','[]','宴罷金雞列，籠瞻黼座遙。',48,'全唐诗/poet.song.91000.json','["宴罷金雞列，籠瞻黼座遙。", "兩雄争定霸，一戰息虚憍。", "忍受摧冠辱，貪承賜錦饒。", "如何紀渻氏，今乃混漁樵。"]'),
('4c1b058b-ce2d-412a-b644-1358bd5479bd','次韻黄堯翁鬭雞三首  其二','張綱','宋','宋诗','song-poetry','','[]','繫馬翠樓下，鬭雞花樹傍。',48,'全唐诗/poet.song.91000.json','["繫馬翠樓下，鬭雞花樹傍。", "飛毛驚辟易，喋血壯摧傷。", "奮撃方乘勢，歡呼忽擅場。", "忿心能幾許，嗟爾太匆忙。"]'),
('eda0d13f-00ef-4034-a4d3-329efc4a27e1','次韻黄堯翁鬭雞三首  其三','張綱','宋','宋诗','song-poetry','','[]','約鬭提籠出，無譁倚壁看。',48,'全唐诗/poet.song.91000.json','["約鬭提籠出，無譁倚壁看。", "禍心藏芥羽，碎首濕朱冠。", "擒敵壯夫事，策勳公子歡。", "棲羣噲等伍，今日始知韓。"]'),
('68f2bb4e-8946-4221-a09a-4e1db79be774','次韻顧應文','張綱','宋','宋诗','song-poetry','','[]','萬事浮雲過眼空，羞將白髪競春紅。',64,'全唐诗/poet.song.91000.json','["萬事浮雲過眼空，羞將白髪競春紅。", "折腰久已慚元亮，作賦何勞慕敬通。", "經世豈無天下士，知心應有古人同。", "破除孤憤難忘酒，聖處時時且一中。"]'),
('37387e2e-a11c-42f7-922d-794b639a17cc','讀書','張綱','宋','宋诗','song-poetry','','[]','卻老慚無術，驅愁賴有書。',48,'全唐诗/poet.song.91000.json','["卻老慚無術，驅愁賴有書。", "披尋窮浩渺，領略造玄虚。", "窗日三竿静，爐薫一炷餘。", "倦來還自哂，蠧簡類蟫魚。"]'),
('2f36fe4c-9213-469c-a29b-34044393ab7a','次韻孫仲益食豚魚','張綱','宋','宋诗','song-poetry','','[]','說食書生費口牙，一盃初捧白瓷花。',64,'全唐诗/poet.song.91000.json','["說食書生費口牙，一盃初捧白瓷花。", "晨鳬夜鯉可亡命，早韮晚菘同世家。", "毒甚鏌鎁渾謾語，詩成珠玉且雄誇。", "腐儒一飽忘麤糲，更索盧仝七椀茶。"]'),
('91852a6a-f795-4915-a26d-8430d0c7c85f','次韻應文遊東園','張綱','宋','宋诗','song-poetry','','[]','筋力摧頹老自知，追歡猶學少年時。',64,'全唐诗/poet.song.91000.json','["筋力摧頹老自知，追歡猶學少年時。", "園林勝處看如夢，杖履行來步懶移。", "對酒不堪蕉葉滿，插花那復帽簷欹。", "羡君詩句方豪甚，應笑疏狂亦强隨。"]'),
('9eba08db-4c56-4567-9ff1-34b243f4180a','次韻李道士觀南山三首  其一','張綱','宋','宋诗','song-poetry','','[]','濛濛烟雨忽晴開，坐覺羣山爽氣來。',32,'全唐诗/poet.song.91000.json','["濛濛烟雨忽晴開，坐覺羣山爽氣來。", "誰向此間尋賀老，相逢莫放酒船回。"]'),
('10f06d9d-28e4-4ca3-9014-5d055d18f20c','次韻李道士觀南山三首  其二','張綱','宋','宋诗','song-poetry','','[]','山似圍屏六曲開，小谿如带傍山來。',32,'全唐诗/poet.song.91000.json','["山似圍屏六曲開，小谿如带傍山來。", "結廬谿北對山住，俗駕何妨且勒回。"]'),
('616c03d2-3d5c-4ef7-a15d-a0326a6e32b0','次韻李道士觀南山三首  其三','張綱','宋','宋诗','song-poetry','','[]','柴門無事晝慵開，杖履誰曾得得來。',32,'全唐诗/poet.song.91000.json','["柴門無事晝慵開，杖履誰曾得得來。", "隔岸野花隨處發，護巢幽鳥傍林回。"]'),
('1cb8e2a4-a6c1-41b9-b82e-e51990199e22','與韓子蒼别久忽邂逅於臨川遭時亂離道舊感歎子蒼有詩見贈次韻奉呈二首  其一','張綱','宋','宋诗','song-poetry','','[]','三顧當年尚草廬，南陽誰識臥龍居。',64,'全唐诗/poet.song.91000.json','["三顧當年尚草廬，南陽誰識臥龍居。", "舍人自是出世佛，學子猶呼行秘書。", "視草似聞虚翰苑，追鋒看即近郊墟。", "論思好爲蒼生計，莫學辛毗謾引裾。"]'),
('fbd34925-ba51-4e9a-a9b1-961f8a977e82','與韓子蒼别久忽邂逅於臨川遭時亂離道舊感歎子蒼有詩見贈次韻奉呈二首  其二','張綱','宋','宋诗','song-poetry','','[]','隨緣到處是吾廬，風雨飄颻敢定居。',64,'全唐诗/poet.song.91000.json','["隨緣到處是吾廬，風雨飄颻敢定居。", "異縣逢君如隔世，七年怪我苦無書。", "平生出處皆陳跡，大半交遊已故墟。", "愁絕不知尊酒盡，醉歸兒女笑牽裾。"]'),
('63553d4d-c2ae-421f-82b5-33f61a81b76c','言懷用子蒼韻','張綱','宋','宋诗','song-poetry','','[]','早從微宦去田廬，慚愧英游許並居。',64,'全唐诗/poet.song.91000.json','["早從微宦去田廬，慚愧英游許並居。", "拙計自憐嵇叔懶，暮年空悔子公書。", "歸尋松竹開幽徑，坐看牛羊下夕墟。", "已把經綸付王導，不妨綀布製襟裾。"]'),
('509fdbb1-88e6-45aa-8716-4173eb1bbe82','謝錢巽叔用子蒼韻','張綱','宋','宋诗','song-poetry','','[]','底事承明厭直廬，孤城天遠寄幽居。',64,'全唐诗/poet.song.91000.json','["底事承明厭直廬，孤城天遠寄幽居。", "根塵已悟三乘祖，香火聊看八會書。", "是處風烟供翰墨，何妨杖履入村墟。", "皇文近日收遺老，妙手終煩補帝裾。"]'),
('493b9a96-c463-416c-ba09-20bc6dfaffe5','寄曾公袞用子蒼韻','張綱','宋','宋诗','song-poetry','','[]','五馬歸來識舊廬，相門曾對水雲居。',64,'全唐诗/poet.song.91000.json','["五馬歸來識舊廬，相門曾對水雲居。", "家聲自可威戎虜，吏最何勞課簿書。", "好扈六飛還魏闕，卻麾单騎復姚墟。", "莫欺霜鬢將軍老，矍鑠猶能一攬裾。"]'),
('f7efed41-c566-42e5-894a-3e9f376cf51d','晚興二首次人韻  其一','張綱','宋','宋诗','song-poetry','','[]','病骨支離怯晚風，可堪遊目送飛鴻。',64,'全唐诗/poet.song.91000.json','["病骨支離怯晚風，可堪遊目送飛鴻。", "書淫老去還知倦，酒聖秋來却喜中。", "北伐會須空虎落，西邊先欲靖蠶叢。", "卑飛莫起扶搖念，徒使莊生笑二蟲。"]'),
('d24988f3-9b48-4669-ad8a-891a9f428379','晚興二首次人韻  其二','張綱','宋','宋诗','song-poetry','','[]','衰草連雲萬木風，天髙滅没見孤鴻。',64,'全唐诗/poet.song.91000.json','["衰草連雲萬木風，天髙滅没見孤鴻。", "夕陽人散酒旗下，遠浦船歸漁笛中。", "兀兀松窗翻蠧簡，垂垂蓬鬢颯霜叢。", "自憐世味諳來慣，已覺忘辛似蓼蟲。"]'),
('55c77197-10d4-4077-b7f5-724616e25031','次韻謝人惠詩','張綱','宋','宋诗','song-poetry','','[]','翩翩才氣逸輕翰，倒寫波瀾筆力寛。',64,'全唐诗/poet.song.91000.json','["翩翩才氣逸輕翰，倒寫波瀾筆力寛。", "沈醉不辭金盞側，清吟長占竹窗寒。", "捧心欲效羞顰媚，斵鼻須煩盡堊漫。", "辱贈驪珠念無報，但驚懷袖有奇觀。"]'),
('eb91b1ce-7893-4b95-bc7d-75a2260eff42','夜雨','張綱','宋','宋诗','song-poetry','','[]','夜雨妨清夢，疏簷落細聲。',48,'全唐诗/poet.song.91000.json','["夜雨妨清夢，疏簷落細聲。", "幽懷無客語，偶坐有琴橫。", "水闊柴荆迥，風髙鴈鶩驚。", "感時思報主，材薄愧平生。"]'),
('a29ced64-1286-476b-adbc-9d63fba1ee60','閉閤','張綱','宋','宋诗','song-poetry','','[]','閉閤静無寐，觀書空復愁。',48,'全唐诗/poet.song.91000.json','["閉閤静無寐，觀書空復愁。", "虞卿雙白璧，晏子一狐裘。", "萬事等歸盡，百年誰得留。", "還將句中眼，爲問賈長頭。"]'),
('25e3ca4e-1c5f-4246-a0c5-80603a261d64','行部至南陵題隱静寺','張綱','宋','宋诗','song-poetry','','[]','籃輿行盡萬松岡，得得來看古道場。',32,'全唐诗/poet.song.91000.json','["籃輿行盡萬松岡，得得來看古道場。", "飛錫落花成佛去，後人誰見紫金光。"]'),
('ebcb876d-a20c-4fea-9ff9-54ebc9a1f844','寄宿隱静東軒軒外竹引飛泉落地中隔窗聞之如秋雨瀉簷聲','張綱','宋','宋诗','song-poetry','','[]','踏殘西日寄僧房，一炷爐熏秋夜長。',32,'全唐诗/poet.song.91000.json','["踏殘西日寄僧房，一炷爐熏秋夜長。", "誰作響泉喧客枕，夢回欹聽雨淋浪。"]'),
('7bdb8a46-957a-4f5a-a576-3954824ebc26','次韻李彦達客舍秋懷','張綱','宋','宋诗','song-poetry','','[]','落日孤村静，凄風一笛秋。',48,'全唐诗/poet.song.91000.json','["落日孤村静，凄風一笛秋。", "寸心灰欲死，雙鬢雪添愁。", "未報中原復，應煩肉食謀。", "獨慚蘇季子，計拙敝貂裘。"]'),
('5ffd0562-2404-45f6-8c4c-025e26ea1a0f','次韻彦達','張綱','宋','宋诗','song-poetry','','[]','之子初傾盖，論詩即定交。',48,'全唐诗/poet.song.91000.json','["之子初傾盖，論詩即定交。", "心清懸水鑑，才逸奮蒲梢。", "貰酒移賓榻，攜盤雜野肴。", "半醒還半醉，相對老蘅茅。"]'),
('343b5da9-ec56-48c0-8764-127f352ed314','木落','張綱','宋','宋诗','song-poetry','','[]','木落秋聲迥，山寒暮色連。',48,'全唐诗/poet.song.91000.json','["木落秋聲迥，山寒暮色連。", "時危羞冕紱，身老寄林泉。", "濁酒平孤憤，清吟續短篇。", "一枝吾已足，鴻鵠謝哀憐。"]'),
('e7bf5532-e983-45da-b708-52b3dc8930d0','思歸','張綱','宋','宋诗','song-poetry','','[]','梧陰低落月，蛩響怨凄風。',48,'全唐诗/poet.song.91000.json','["梧陰低落月，蛩響怨凄風。", "舊隱江烟裏，歸期客夢中。", "攬衣驚带緩，看燭待花紅。", "莫謾呼歡伯，驅愁正罔功。"]'),
('853609ee-df35-4711-ab65-241a4105f696','次韻酬彦達','張綱','宋','宋诗','song-poetry','','[]','浮榮過眼風脫葉，鴛行無復清夢接。',144,'全唐诗/poet.song.91000.json','["浮榮過眼風脫葉，鴛行無復清夢接。", "柴門晝閉雀可羅，寒日暉暉弄疏樾。", "已種芳蘭滋九畹，更遣胎仙舞三叠。", "李侯壯志亦可人，舉目萬里欲橫絕。", "醉眼時看石稜紫，吟鬢半作霜棘折。", "方今聖主躬儉勤，奏賦不須誇羽獵。", "中興盛事要磨崖，老於文字誰踰結。", "願君勉力上扶搖，渺渺雲海出飛楫。", "莫隨鎩翮臥窮巷，漫學啼螿弔寒月。"]'),
('505467f7-09a4-49dc-964e-0514befb81fa','燒香三絕句  其一','張綱','宋','宋诗','song-poetry','','[]','卷去竹書閑棐几，臥看桐影轉簷牙。',32,'全唐诗/poet.song.91000.json','["卷去竹書閑棐几，臥看桐影轉簷牙。", "試憑波律送清夢，未信華胥天一涯。"]'),
('74c29bca-2925-47d1-8a58-aac4278a61ba','燒香三絕句  其二','張綱','宋','宋诗','song-poetry','','[]','霏霏沉水屑玄玉，靄靄博山生翠雲。',32,'全唐诗/poet.song.91000.json','["霏霏沉水屑玄玉，靄靄博山生翠雲。", "羅筏城旁知幾里，坐令香界徹微熏。"]'),
('9cae2888-52f1-41f0-9ce0-c7a809b84afb','燒香三絕句  其三','張綱','宋','宋诗','song-poetry','','[]','閉眼無勞身外思，安心有法静中知。',32,'全唐诗/poet.song.91000.json','["閉眼無勞身外思，安心有法静中知。", "香添細炷焚千和，茶碾新芽試一旗。"]'),
('4f1be419-2ecd-4cee-930f-19749f9157ee','次韻錢巽叔見贈','張綱','宋','宋诗','song-poetry','','[]','阻闊書郵頓兩忘，三年清夢獨徜徉。',64,'全唐诗/poet.song.91000.json','["阻闊書郵頓兩忘，三年清夢獨徜徉。", "風旌引興與天遠，繭緒牽愁知日長。", "逸翮佇歸鴛鷺列，鳴騶忽下水雲鄉。", "秋霖窮巷無人到，裹飯應煩問子桑。"]'),
('486fdba4-6764-4270-80b5-fe6045fe73de','感恩','張綱','宋','宋诗','song-poetry','','[]','伊昔趨青鎖，嘗叨奉紫宸。',48,'全唐诗/poet.song.91000.json','["伊昔趨青鎖，嘗叨奉紫宸。", "燕間承仄席，清問及垂綸。", "寵荷皇恩重，歸慚白髪新。", "粉身那足報，結草是吾鄰。"]'),
('0f243379-9808-4541-b278-a4ea7960e125','幽情','張綱','宋','宋诗','song-poetry','','[]','褊性多違俗，忘年只舊山。',48,'全唐诗/poet.song.91000.json','["褊性多違俗，忘年只舊山。", "心隨黄葉謝，身與白雲閑。", "杜酒頻應酌，莱衣賸喜班。", "幽情在叢桂，爲着槿籬環。"]'),
('1ca8a4be-f29e-4e16-ae6b-80167b89f2c8','彦達作詩自歎次韻勉之','張綱','宋','宋诗','song-poetry','','[]','未試屠龍學，頻應引劍看。',48,'全唐诗/poet.song.91000.json','["未試屠龍學，頻應引劍看。", "夢驚秋枕雨，愁入曙窗寒。", "戰伐今年定，乾坤萬里寛。", "扶搖終一舉，回首謝悲酸。"]'),
('0ba90d7c-5141-453a-8c8c-f470558b2d55','日暮','張綱','宋','宋诗','song-poetry','','[]','地偏車馬静，門閉水雲深。',48,'全唐诗/poet.song.91000.json','["地偏車馬静，門閉水雲深。", "野艇收晴網，村舂續暮砧。", "危腸逢酒怯，病骨畏寒侵。", "又見鴉歸盡，誰賡梁甫吟。"]'),
('d3292267-40bc-4ece-8b78-d67e4dfbd41e','次韻彦達雨霽','張綱','宋','宋诗','song-poetry','','[]','坐看飛雨激風雷，忽變晴空萬里開。',64,'全唐诗/poet.song.91000.json','["坐看飛雨激風雷，忽變晴空萬里開。", "殘暑暗隨簷溜去，新凉頻逐樹聲來。", "朱絃奏罷空三歎，白酒篘殘尚一杯。", "病懶怕催詩債急，彊吟狂斐不知裁。"]'),
('70615259-0d3e-423f-a304-cbbd976b4fa5','晚雨','張綱','宋','宋诗','song-poetry','','[]','急雨鳴初歇，崇雲凝不流。',48,'全唐诗/poet.song.91000.json','["急雨鳴初歇，崇雲凝不流。", "客帆迷息浦，漁火聚烟洲。", "委巷藏身拙，殘編亂眼愁。", "功名心已謝，肯負故山幽。"]'),
('84424a80-0895-4d67-9f56-ea3318c8ed9f','彦達借研意在白取次韻戲答','張綱','宋','宋诗','song-poetry','','[]','斵石染輕翰，對面可十手。',48,'全唐诗/poet.song.91000.json','["斵石染輕翰，對面可十手。", "價重千黄金，欲見那得苟。", "難欺相如璧，寧碎范增斗。", "作詩伐君謀，聊以當墨守。"]'),
('1ace081c-cca6-42fd-84f5-e38a4e377158','家叔示秋夜詩次韻','張綱','宋','宋诗','song-poetry','','[]','秋來天色半晴陰，衰鬢難禁節物侵。',64,'全唐诗/poet.song.91000.json','["秋來天色半晴陰，衰鬢難禁節物侵。", "蘭葉向人方泣露，菊花催酒已浮金。", "莫將詩課頻頻聒，不那愁城日日深。", "咫尺南山堪寄傲，欲隨鳩杖徧幽尋。"]'),
('d3fa81ec-b74c-47ca-9355-800a0313114e','用前韻','張綱','宋','宋诗','song-poetry','','[]','蕭然雲屋敞溪陰，荒徑蒿莱故故侵。',64,'全唐诗/poet.song.91000.json','["蕭然雲屋敞溪陰，荒徑蒿莱故故侵。", "穿竹晚風輕戞玉，入簾凉月碎搖金。", "畏寒皮骨驚秋早，得酒情懷語夜深。", "臨老工夫在禪說，試拈波若爲重尋。"]'),
('9eb2fc5d-051e-4c98-a03d-e913cba34cfa','次韻戲彦達思歸','張綱','宋','宋诗','song-poetry','','[]','月窗明素練，風榻浄飛沙。',48,'全唐诗/poet.song.91000.json','["月窗明素練，風榻浄飛沙。", "飲極樽無綠，更長燭自花。", "感時憂未散，得句喜能誇。", "莫寄思歸語，粧寒損鬢鴉。"]'),
('daf76f71-400a-4226-8af7-e104ca0e9f76','月夜','張綱','宋','宋诗','song-poetry','','[]','漁火前村近，秋砧静夜多。',48,'全唐诗/poet.song.91000.json','["漁火前村近，秋砧静夜多。", "山烟歸宿鳥，水月動明波。", "燭短催詩急，樽空奈客何。", "抱愁眠不穩，林影半床過。"]'),
('87c5a02b-aa15-46ea-adee-826809853057','秋夜小酌','張綱','宋','宋诗','song-poetry','','[]','宇宙秋光老，崦嵫夜色連。',48,'全唐诗/poet.song.91000.json','["宇宙秋光老，崦嵫夜色連。", "澄波寒浸月，低樹遠浮烟。", "巷僻喧都騎，杯行促廣筵。", "摩尼元自照，沉醉不妨禪。"]'),
('a1b285a2-e3b9-496e-8475-5405b2730934','探梅','張綱','宋','宋诗','song-poetry','','[]','俗態多違性，憂梅不近城。',48,'全唐诗/poet.song.91000.json','["俗態多違性，憂梅不近城。", "詩書看長物，林壑寄餘情。", "傍驛尋梅使，衝寒過麴生。", "一枝供細酌，歸路見參橫。"]'),
('c0d95c22-55ae-4f3d-a127-2e0a6c118c10','山中即事','張綱','宋','宋诗','song-poetry','','[]','地僻官仍冷，心閑日自長。',48,'全唐诗/poet.song.91000.json','["地僻官仍冷，心閑日自長。", "松篁供遠吹，芝朮度幽香。", "直木應先伐，驚禽忍再傷。", "家山吾所愛，投老慰相望。"]'),
('301384b6-dd5b-43f9-ae1b-6c64da275f37','次韻彦達折梅','張綱','宋','宋诗','song-poetry','','[]','信步尋梅約，欣逢亞雪枝。',48,'全唐诗/poet.song.91000.json','["信步尋梅約，欣逢亞雪枝。", "春藏紅蕚小，寒嗇暗香遲。", "畫角傳新曲，粧臺歛翠眉。", "廣平心不動，唯許筆端知。"]'),
('fd21628a-21c1-448d-b537-cda3e32dd52e','僻居','張綱','宋','宋诗','song-poetry','','[]','陋巷人誰樂，窮居意自安。',48,'全唐诗/poet.song.91000.json','["陋巷人誰樂，窮居意自安。", "擁門雲樹暗，繚徑土花乾。", "白髪驚時速，青燈耿夜寒。", "中原滿胡騎，一念一悲酸。"]'),
('a94512fe-4efe-4ec4-b688-31fd3113992b','次韻彦達對雪有感','張綱','宋','宋诗','song-poetry','','[]','朔風卷地寒雲繁，忽驚空花墮簷間。',128,'全唐诗/poet.song.91000.json','["朔風卷地寒雲繁，忽驚空花墮簷間。", "遠山歷亂眼中失，飛鳥滅没天際還。", "緬想端門萬官賀，雲陛儼列鳴珮環。", "豐年獻瑞天一笑，聲動四海具歡顔。", "李侯人物妙天下，何獨臥窮看屋山。", "胸次冰壺自深瑩，管中霧豹難窺斑。", "異時富貴恐不免，詎忍空歌梁甫艱。", "君看鴻鵠有髙志，一舉九萬誰能攀。"]'),
('5a57f298-4ffb-4d1b-b83c-33f432584745','雪晴','張綱','宋','宋诗','song-poetry','','[]','雪晴日脚下茅屋，深巷泥融頻屐聲。',64,'全唐诗/poet.song.91000.json','["雪晴日脚下茅屋，深巷泥融頻屐聲。", "幽鳥喚春啼不那，野梅迎客意先傾。", "愁腸斷送酒邊散，詩眼安排烟際橫。", "晚歲浮榮安用許，祗應丘壑未忘情。"]'),
('61966a1e-d2bc-457f-8008-a66b6ec1476a','次韻彦達催詩','張綱','宋','宋诗','song-poetry','','[]','老去交親渾謾與，興來終日飲亡何。',64,'全唐诗/poet.song.91000.json','["老去交親渾謾與，興來終日飲亡何。", "扣門頗厭催書債，隱几憑誰遣睡魔。", "肯怪物情相楚越，端由吾道自丘軻。", "衰慵更着詩煩惱，筆陣方開已倒戈。"]'),
('253684e9-4294-4271-a291-3698e063d591','歲暮二首  其一','張綱','宋','宋诗','song-poetry','','[]','忽忽歲云暮，霏霏山雨頻。',48,'全唐诗/poet.song.91000.json','["忽忽歲云暮，霏霏山雨頻。", "鳥啼茅舍静，梅映竹籬新。", "陋巷無深轍，清酤有善隣。", "中原消息斷，聊與醉鄉親。"]'),
('d8c1ad18-4299-4c39-8198-8e8bc98a8f01','歲暮二首  其二','張綱','宋','宋诗','song-poetry','','[]','寒逐雲陰散，年催節物新。',48,'全唐诗/poet.song.91000.json','["寒逐雲陰散，年催節物新。", "桃符趨臘市，社鼓賽田神。", "任性琴書懶，呼兒杖履頻。", "君恩難報處，家食奉雙親。"]'),
('aa9ecf65-5b93-49f5-990a-15e1d4efbf6a','用前韻','張綱','宋','宋诗','song-poetry','','[]','雪殘春信近，山迥客愁新。',48,'全唐诗/poet.song.91000.json','["雪殘春信近，山迥客愁新。", "興極樽無酒，詩成筆有神。", "玩心雲物變，驚夢雨聲頻。", "坐對華嚴海，忘言意自親。"]'),
('a709ec8f-29d5-4e95-b2ab-13792cee4d1e','野望','張綱','宋','宋诗','song-poetry','','[]','日落寒雲薄，樓髙望眼迷。',48,'全唐诗/poet.song.91000.json','["日落寒雲薄，樓髙望眼迷。", "興亡千古恨，衰病萬行啼。", "拔士空巖穴，防秋尚鼓鼙。", "建章何處是，坐待玉繩低。"]'),
('7bc229bb-4083-4922-9808-14f861423f01','探梅','張綱','宋','宋诗','song-poetry','','[]','倚空山翠羅曲屏，入山曉日寒凄清。',64,'全唐诗/poet.song.91000.json','["倚空山翠羅曲屏，入山曉日寒凄清。", "蒼龍導前散疏影，幽鳥勸坐回新聲。", "探梅忽見數枝發，曳杖折來雙眼明。", "綽約東窗可無伴，煩君火急呼麯生。"]'),
('aab4bc18-70c9-4729-b6b6-eb5187b60598','彦達乘小舟醉歸墮水作此戲之','張綱','宋','宋诗','song-poetry','','[]','舍爵頺然飲中仙，夜歸一葦航深淵。',64,'全唐诗/poet.song.91000.json','["舍爵頺然飲中仙，夜歸一葦航深淵。", "長歌扣舷天上坐，起舞失脚水底眠。", "未省渇羌笑肉動，會令鼹鼠驚腹便。", "布帆無恙急藏去，明年更試春江船。"]'),
('412e3477-b766-4228-baf3-95fea37cab20','次韻李公顯','張綱','宋','宋诗','song-poetry','','[]','士有鴻鵠志，萬里一舉翮。',132,'全唐诗/poet.song.91000.json','["士有鴻鵠志，萬里一舉翮。", "胸中自廊廟，肯顧三畝宅。", "李侯氣邁爽，詞鋒凜霜戟。", "老夫晚結交，文會欣有繹。", "劇談到時事，唾手欲任責。", "短褐天路髙，畎畝抱忠赤。", "風雷惜變化，泥蟠等蜥蜴。", "結茅西山下，樵爨走僮獲。", "富貴會有時，簞飄豈不適。", "世態翻覆手，寧較黑與白。", "興來時一杯，南窗俯遙碧。"]'),
('9a43d022-1b0a-4e52-9654-f2cbe2323fde','歸自金壇值雨宿顧龍山翌日施米作供','張綱','宋','宋诗','song-poetry','','[]','蒲牢不擊欠晨炊，風伯如何聖得知。',32,'全唐诗/poet.song.91000.json','["蒲牢不擊欠晨炊，風伯如何聖得知。", "留我艤舟明日去，滿堂香飯雪翻匙。"]'),
('a7c020a8-710c-4c0d-a84b-a3d3dcf63310','次韻公顯見贈  其一','張綱','宋','宋诗','song-poetry','','[]','李侯詞氣吐朝陽，光焰真成萬丈長。',32,'全唐诗/poet.song.91000.json','["李侯詞氣吐朝陽，光焰真成萬丈長。", "綠髪莫將塵土暗，會看它日照金章。"]'),
('3241c8dd-1613-4ebd-9053-0ac7acf998cf','次韻公顯見贈  其二','張綱','宋','宋诗','song-poetry','','[]','年齊耆舊愧衰陽，懶性唯耽野趣長。',32,'全唐诗/poet.song.91000.json','["年齊耆舊愧衰陽，懶性唯耽野趣長。", "了卻官租更何事，君王約法已三章。"]'),
('79c2ed50-eb83-4885-a29c-d6a0e0a033f9','用前韻戲公顯','張綱','宋','宋诗','song-poetry','','[]','初試梅粧惬壽陽，藁砧山上夜何長。',32,'全唐诗/poet.song.91000.json','["初試梅粧惬壽陽，藁砧山上夜何長。", "式微未盡閨中怨，束晳那辭補一章。"]'),
('9c9e6010-f306-442b-98ed-7c2ef031e666','送公顯應舉','張綱','宋','宋诗','song-poetry','','[]','堂堂筆陣一當千，得意秋風急着鞭。',32,'全唐诗/poet.song.91000.json','["堂堂筆陣一當千，得意秋風急着鞭。", "百萬破荒明日事，未應長欠畝頭錢。"]'),
('3a75ca81-f580-4655-8213-3c84dbaf2286','次韻公顯木犀','張綱','宋','宋诗','song-poetry','','[]','鋪茸紫葵亂晴颸，點金寒菊棲短籬。',128,'全唐诗/poet.song.91000.json','["鋪茸紫葵亂晴颸，點金寒菊棲短籬。", "木犀韻髙陋凡枝，顧與葵菊同階墀。", "香聞十里自絕奇，造物豈偏雨露滋。", "閒見層出珠琲垂，鵝黄靛粧宫様宜。", "烟銷紅日下薄帷，宴坐幽窗風度時。", "頗覺飄飄蘭蕙姿，着人不去催作詩。", "李侯爲續離騷辭，香草端從筆下移。", "花前把卷不停披，何以酬君金屈巵。"]'),
('744e9ac6-cb20-487e-9588-afcebc4fb58d','次韻公顯賦蠟梅詩二首  其一','張綱','宋','宋诗','song-poetry','','[]','壽陽催粧花睡起，半額殘黄嬌欲語。',80,'全唐诗/poet.song.91000.json','["壽陽催粧花睡起，半額殘黄嬌欲語。", "香魂浮動滿幽思，着莫春風暗相與。", "李侯鐵心似廣平，筆力萬鈞談笑舉。", "詩成夜誦更清絕，向來誰識袁臨汝。", "句中有味應獨知，吟罷餘甘發微咀。"]'),
('fc930ac7-09ab-42cd-9170-d0968b3895bb','次韻公顯賦蠟梅詩二首  其二','張綱','宋','宋诗','song-poetry','','[]','愁裏危腸日九迴，今朝愁眼爲花開。',32,'全唐诗/poet.song.91000.json','["愁裏危腸日九迴，今朝愁眼爲花開。", "一枝斜倚向人笑，應報上林春信來。"]'),
('fa187d5f-da33-4bf1-b987-999903faa282','從丁世叔覓花栽','張綱','宋','宋诗','song-poetry','','[]','老去看花能幾回，旋移花樹着行栽。',32,'全唐诗/poet.song.91000.json','["老去看花能幾回，旋移花樹着行栽。", "君家封植滿烟露，分我一枝春色來。"]'),
('7309a4ba-0429-4a6e-813b-292872f215fb','庚午三月十日遊茅山','張綱','宋','宋诗','song-poetry','','[]','雨餘沙逕浄無泥，策杖何妨過竹谿。',64,'全唐诗/poet.song.91000.json','["雨餘沙逕浄無泥，策杖何妨過竹谿。", "迎客野花隨處發，勸沽幽鳥向人啼。", "峰巒路轉攀蘿倦，樓觀烟深望眼迷。", "疑是武陵仙地隔，坐來遐想舊桃蹊。"]'),
('bac24554-04d5-4b73-a9e7-9eba7507e4fc','王伯壽見復用前韻奉答','張綱','宋','宋诗','song-poetry','','[]','瓶空何必醉如泥，送客誰能過虎谿。',64,'全唐诗/poet.song.91000.json','["瓶空何必醉如泥，送客誰能過虎谿。", "一枕閉門追蝶夢，兩行森木聽鶯啼。", "新詩未讀心先伏，細字徐看眼欲迷。", "筆底春風有生意，他年桃李會成蹊。"]'),
('fff442d7-593e-43e9-a901-454f77e282fd','次韻伯壽述懷','張綱','宋','宋诗','song-poetry','','[]','仲蔚蓬蒿滿徑荒，主人曾是漢中郎。',64,'全唐诗/poet.song.91000.json','["仲蔚蓬蒿滿徑荒，主人曾是漢中郎。", "干時不利初無術，醫國那知别有方。", "老去與誰同臭味，秋來多病獨悲凉。", "倚天長劍君休問，腐肉當前亦歛鋩。"]'),
('8fe75e12-6f6e-41e3-9963-f60523bede2b','邀韋汝昭同宿上館','張綱','宋','宋诗','song-poetry','','[]','打窗風雨夜蕭蕭，客裏誰堪伴寂寥。',32,'全唐诗/poet.song.91000.json','["打窗風雨夜蕭蕭，客裏誰堪伴寂寥。", "五字蘇州有苗裔，髙吟何必更聞韶。"]'),
('2c564e76-b94f-4218-89dd-f3f723d90bce','題華陽南窗','張綱','宋','宋诗','song-poetry','','[]','擾擾何年斷俗緣，從今便合老山間。',32,'全唐诗/poet.song.91000.json','["擾擾何年斷俗緣，從今便合老山間。", "會將碧澗洗心浄，坐看白雲終日閒。"]'),
('49e395c7-a8e0-4f24-b6b2-6be070cfb28a','衰病辭祿蒙恩賜可時小子堅方塵末第陳德昭袁仲誠惠詩褒借褒借甚寵次韻奉答二首  其一','張綱','宋','宋诗','song-poetry','','[]','蕭蕭兩鬢雪毛新，忝竊清朝舊薦紳。',64,'全唐诗/poet.song.91000.json','["蕭蕭兩鬢雪毛新，忝竊清朝舊薦紳。", "陳力心知難就列，引年恩許致爲臣。", "臥家正恐貽官謗，增秩俄驚捧帝綸。", "温飽一門生意足，捐軀無路報涓塵。"]'),
('f95bb6d8-2f1e-4bb6-a100-240a2e375612','衰病辭祿蒙恩賜可時小子堅方塵末第陳德昭袁仲誠惠詩褒借褒借甚寵次韻奉答二首  其二','張綱','宋','宋诗','song-poetry','','[]','月窟當年裛桂香，衰蘭那敢望重芳。',64,'全唐诗/poet.song.91000.json','["月窟當年裛桂香，衰蘭那敢望重芳。", "姓名忽見偕千佛，骨相端知誤九方。", "老樹逢春欣有蘖，新雛出谷敢争翔。", "琢磨賴有交朋在，髙義無專數范張。"]'),
('4e048d66-10e1-4593-b1b8-e8d89f4bf7f9','用前韻再簡二首  其一','張綱','宋','宋诗','song-poetry','','[]','三復長篇句法新，蘭言紉佩更書紳。',64,'全唐诗/poet.song.91000.json','["三復長篇句法新，蘭言紉佩更書紳。", "才髙奚啻千人敵，譽過空慚一介臣。", "莫訝筆端能品藻，定由胸次有經綸。", "波瀾萬頃分餘滴，洗盡昏花滿眼塵。"]'),
('3a35ac61-519d-442a-9ffc-afd86edf38cb','用前韻再簡二首  其二','張綱','宋','宋诗','song-poetry','','[]','二妙争開古錦囊，爛然佳句壓羣芳。',64,'全唐诗/poet.song.91000.json','["二妙争開古錦囊，爛然佳句壓羣芳。", "奉髙遺德歸臨汝，文範流風在季方。", "顧我挂冠寧復振，生兒附翼豈能翔。", "願公勉力躋雲路，視草斯文要主張。"]'),
('b27a3aa8-54b7-4946-afd5-e8216238eec7','赴喜雪御筵歸作','張綱','宋','宋诗','song-poetry','','[]','喜雪排筵曉漏催，玉人傳詔下天來。',64,'全唐诗/poet.song.91000.json','["喜雪排筵曉漏催，玉人傳詔下天來。", "香隨日轉蓬萊近，花带春回錦繡開。", "一線新陰留鼓吹，三登和氣入樽罍。", "叨霑惠渥思歸美，授簡梁園愧乏才。"]'),
('71b0054b-a469-408d-9347-d17537f923e0','進呈皇太后回鑾事實','張綱','宋','宋诗','song-poetry','','[]','奕世占來寶運昌，母儀垂慶肇生商。',64,'全唐诗/poet.song.91000.json','["奕世占來寶運昌，母儀垂慶肇生商。", "鑾回長樂神人喜，書就蓬山日月光。", "北闕導迎三衞仗，東朝歡奉萬年觴。", "太平盛事人相語，孝德回天賴我皇。"]'),
('8cd9d2fe-cd1a-49bd-a262-1f6c514f57e2','太廟靈芝産于仁宗皇帝英宗皇帝兩室前楹芝上有文成王字臣叨陪政府得預榮觀謹課成律詩二首  其一','張綱','宋','宋诗','song-poetry','','[]','吾皇聖德紹先猷，清廟華芝屢降休。',64,'全唐诗/poet.song.91000.json','["吾皇聖德紹先猷，清廟華芝屢降休。", "道盛百王神畫驗，祥開兩室化功侔。", "犧尊影照彤雲聚，藻梲光連瑞氣浮。", "願詔樂章歌偉蹟，更從來歲薦郊丘。"]'),
('f13d1464-54f2-45dd-a0cd-55ed6db6b127','太廟靈芝産于仁宗皇帝英宗皇帝兩室前楹芝上有文成王字臣叨陪政府得預榮觀謹課成律詩二首  其二','張綱','宋','宋诗','song-poetry','','[]','升平和氣格天淵，瑞物嘉生太室前。',64,'全唐诗/poet.song.91000.json','["升平和氣格天淵，瑞物嘉生太室前。", "根托丹楹朝麗日，葉敷華盖護非烟。", "燕胎爲祝多男慶，天母人符萬歲篇。", "聖意每勤宗廟事，屢蒙休應答精虔。"]'),
('22b61a38-3d27-4ed7-80c0-f3de8deba66a','歲前三日立春值雪會同僚飲','張綱','宋','宋诗','song-poetry','','[]','三日殘冬趁臈回，飛霙滿眼送春來。',64,'全唐诗/poet.song.91000.json','["三日殘冬趁臈回，飛霙滿眼送春來。", "香浮綵勝隨宜带，花着瑤林是處開。", "已卜屢豐歌井邑，何妨乘興倒樽罍。", "東陽莫訝休文瘦，老病仍添一歲催。"]'),
('2d33ecfb-9cdf-4a71-8648-6f8077c2428c','上元','張綱','宋','宋诗','song-poetry','','[]','上元春色壓輕寒，故事賓僚集晚筵。',64,'全唐诗/poet.song.91000.json','["上元春色壓輕寒，故事賓僚集晚筵。", "合坐香浮花裊娜，捲簾風定月嬋娟。", "閭閻盡道宜新歲，燈火何妨減去年。", "堪笑樽前窮太守，只愁老病欲歸田。"]'),
('0db8e428-499a-409f-9a4a-6bf60ed3d3b0','休官','張綱','宋','宋诗','song-poetry','','[]','乞得清朝一病身，杖藜歸去老山村。',64,'全唐诗/poet.song.91000.json','["乞得清朝一病身，杖藜歸去老山村。", "室廬旋築新椽就，松菊猶尋舊徑存。", "漸喜有緣窮野興，只慚無路報君恩。", "百年來日知餘幾，且把生涯付一樽。"]'),
('2817e857-e2e5-4959-9aec-22a792bc1ee1','弟姪三人同日受官實爲吾家盛事老懷不勝忭喜作四小詩見區區之意  其一','張綱','宋','宋诗','song-poetry','','[]','恩光初自九天來，玉樹三枝一日開。',32,'全唐诗/poet.song.91000.json','["恩光初自九天來，玉樹三枝一日開。", "造物無私人共慶，那知陰德舊栽培。"]'),
('31aea6ea-7cbb-45ff-9896-0a78a521f517','弟姪三人同日受官實爲吾家盛事老懷不勝忭喜作四小詩見區區之意  其二','張綱','宋','宋诗','song-poetry','','[]','三世追榮荷聖恩，諸孫仍見捧絲綸。',32,'全唐诗/poet.song.91000.json','["三世追榮荷聖恩，諸孫仍見捧絲綸。", "當年孝友家聲在，流慶增光屬後人。"]'),
('d6049491-40ec-420a-bb84-480fe3f14ae7','弟姪三人同日受官實爲吾家盛事老懷不勝忭喜作四小詩見區區之意  其三','張綱','宋','宋诗','song-poetry','','[]','恩袍新綠照新秋，文雅鄉評早見收。',32,'全唐诗/poet.song.91000.json','["恩袍新綠照新秋，文雅鄉評早見收。", "王謝故應人物勝，芝蘭生處自風流。"]'),
('35be544d-1dfa-402c-8f35-1d9c8f0db985','弟姪三人同日受官實爲吾家盛事老懷不勝忭喜作四小詩見區區之意  其四','張綱','宋','宋诗','song-poetry','','[]','清時得謝老山村，弟姪相過慶一門。',32,'全唐诗/poet.song.91000.json','["清時得謝老山村，弟姪相過慶一門。", "結綬滿庭青若若，莫辭勤苦報君恩。"]'),
('105d7818-2c91-4e30-99f9-8269b48e1940','郊祀慶成用堅韻','張綱','宋','宋诗','song-poetry','','[]','圓丘迎日至，大駕肅天臨。',48,'全唐诗/poet.song.91000.json','["圓丘迎日至，大駕肅天臨。", "樂奏來靈享，嵩呼動德音。", "均恩寰宇慶，望闕老臣心。", "基命歌周雅，何勞五字吟。"]'),
('b9456197-a7fe-4d84-b5c1-ab871013367f','作亭池上日游其間頗覺自適','張綱','宋','宋诗','song-poetry','','[]','歲晚穿池結小亭，地偏聊欲寄幽情。',64,'全唐诗/poet.song.91000.json','["歲晚穿池結小亭，地偏聊欲寄幽情。", "虚簷風度披襟爽，曲岸波平照眼明。", "過我賓朋無厭數，傍人鷗鷺不須驚。", "聖朝乞得身閑散，便覺淵明是隔生。"]'),
('fabb3646-1c0e-4ef7-a818-5aac5118caa0','題喜歸亭','張綱','宋','宋诗','song-poetry','','[]','君恩賜我老菟裘，旋築池亭野趣幽。',64,'全唐诗/poet.song.91000.json','["君恩賜我老菟裘，旋築池亭野趣幽。", "地勢曲連青嶂遶，波光環匝翠烟浮。", "興來樽酒隨時辦，客散琴書盡日留。", "爲問標題意何在，一生心足是歸休。"]'),
('5ca5d0d5-7116-43c2-8d43-93e577f37768','次韻袁仲誠見贈','張綱','宋','宋诗','song-poetry','','[]','解組清朝返舊鄉，依然門巷接回塘。',64,'全唐诗/poet.song.91000.json','["解組清朝返舊鄉，依然門巷接回塘。", "閒身乍覺鳥聲樂，緩步重尋花徑香。", "多謝故人停桂棹，何妨清夜醉霞觴。", "新詩贈我光蓬屋，什襲應同夏后璜。"]'),
('89c46327-11aa-48ea-ba53-27f5b7b74210','再用喜歸亭韻','張綱','宋','宋诗','song-poetry','','[]','晏子區區惜敝裘，吾衰亦戀故山幽。',64,'全唐诗/poet.song.91000.json','["晏子區區惜敝裘，吾衰亦戀故山幽。", "得歸更喜詩盈軸，任達寧須酒拍浮。", "已縱虚名身外去，肯將俗物眼邊留。", "只慚老負君恩重，結草他年報未休。"]'),
('cf8995fc-8edb-47de-b622-fca1585dc91c','送張輔卿省試','張綱','宋','宋诗','song-poetry','','[]','明詔搜賢動四陲，西來一鶚冠羣飛。',64,'全唐诗/poet.song.91000.json','["明詔搜賢動四陲，西來一鶚冠羣飛。", "擅埸筆勢驚華省，發策才名上紫微。", "無負題橋平日志，要看懷綬故鄉歸。", "相逢肯惜傾家釀，已約鶯花慎勿違。"]'),
('1f78f8c5-1f77-44be-a22e-4c742af732b0','簡袁仲誠覓芍藥花','張綱','宋','宋诗','song-poetry','','[]','老來百計不相關，詩句雕鐫興亦闌。',32,'全唐诗/poet.song.91000.json','["老來百計不相關，詩句雕鐫興亦闌。", "只有好花堪照眼，從君聊借一枝看。"]'),
('54ca582b-aab1-4c9f-9ba1-aada89af2f91','仲誠和詩四首又疊送花再用韻答','張綱','宋','宋诗','song-poetry','','[]','筆陣橫飛屢叩關，嚴兵夜點迫更闌。',32,'全唐诗/poet.song.91000.json','["筆陣橫飛屢叩關，嚴兵夜點迫更闌。", "好花多謝頻分我，怯敵魂驚未暇看。"]'),
('df41d180-388b-4972-8259-b895089ab33c','避寇舟中風雨大作','張綱','宋','宋诗','song-poetry','','[]','扁舟避艤山隈，問捷江城信未迴。',63,'全唐诗/poet.song.91000.json','["扁舟避艤山隈，問捷江城信未迴。", "犯夜號風驚夢破，催寒飛雪送愁來。", "三軍挾纊煩溫詔，百戰搴旗賴雋材。", "已辦磨崖頌功烈，竚還生意發春雷。"]'),
('6608069e-77aa-494c-a512-e8d1a8984206','王伯壽示佳作備述窮苦次韻奉呈','張綱','宋','宋诗','song-poetry','','[]','吟殘翻水筆生春，秀句驚人字字新。',64,'全唐诗/poet.song.91000.json','["吟殘翻水筆生春，秀句驚人字字新。", "賦料揚雄誰可敵，才高太白善無鄰。", "清心鳴鏑增豪氣，刮膜神篦凈俗塵。", "唯有訴窮疑太過，文章從古忌悲辛。"]'),
('d682a772-9126-4711-b99f-5334c7cad43b','雪作','張綱','宋','宋诗','song-poetry','','[]','朔風吹雪應嘉時，蔌蔌空庭靜夜知。',64,'全唐诗/poet.song.91000.json','["朔風吹雪應嘉時，蔌蔌空庭靜夜知。", "歲稔不須占瑞諜，家貧尤喜映書帷。", "花雖無艶難争巧，舞不成行也自奇。", "病起老翁迷眼界，寒窗呵筆强裁詩。"]'),
('a36c2c3a-87e5-484c-ad95-f2417e8599a3','招親舊賞花','張綱','宋','宋诗','song-poetry','','[]','名花朵朵向人開，家釀沈沈旋撥醅。',32,'全唐诗/poet.song.91000.json','["名花朵朵向人開，家釀沈沈旋撥醅。", "咫尺晴川風更便，追歡何惜片帆來。"]'),
('bdf9849e-8d2b-4208-993d-359d67e35663','安人生日','張綱','宋','宋诗','song-poetry','','[]','聞道防秋吉語來，生朝宴席爲君開。',32,'全唐诗/poet.song.91000.json','["聞道防秋吉語來，生朝宴席爲君開。", "黄花也似知人意，争挽歡聲入壽杯。"]'),
('696aa97c-009e-4367-a392-0e02616fcf41','聞大帥勇决直趨北界喜而作此','張綱','宋','宋诗','song-poetry','','[]','牙旗動處擁貔貅，直渡黄河塞草秋。',32,'全唐诗/poet.song.91000.json','["牙旗動處擁貔貅，直渡黄河塞草秋。", "百萬强兵陣前死，肯教衛霍獨封侯。"]'),
('9261f5f8-427b-4dc1-a71b-8b26fc02e358','次韻王周伯和應文詩','張綱','宋','宋诗','song-poetry','','[]','先生詩興浩難收，苦思俄驚兩鬢秋。',64,'全唐诗/poet.song.91000.json','["先生詩興浩難收，苦思俄驚兩鬢秋。", "變格競傳吳富體，懷沙擬續畔牢愁。", "會令後學輕焚藳，消得詩名號倚樓。", "我老恨無青玉案，錦囊分示若爲酬。"]'),
('d6571955-5ee3-4ccb-9c39-44b626fed5ae','應文監視刈穫有詩輒和一篇恐以一飽廢學因而勉之','張綱','宋','宋诗','song-poetry','','[]','杖藜何日下西疇，想見欣逢歲有秋。',64,'全唐诗/poet.song.91000.json','["杖藜何日下西疇，想見欣逢歲有秋。", "可但聚糧供腹飽，還應釀秫散眉愁。", "决科佇看標金榜，得路終期侍玉樓。", "莫把光陰等閑棄，一朝清問要人酬。"]'),
('08c1b98a-756c-4ea3-8d5a-8f46889baac3','九日用前韻','張綱','宋','宋诗','song-poetry','','[]','閑裏光陰逐水流，重陽忽復故園秋。',64,'全唐诗/poet.song.91000.json','["閑裏光陰逐水流，重陽忽復故園秋。", "休言白髪從教老，試插黄花也解愁。", "感舊有時曾落帽，憑髙無力更登樓。", "昏昏病懶惟堪睡，詩債休催未暇酬。"]'),
('1301713c-7c96-4a40-916f-c90e90a1ec2c','走筆戲呈世叔伯達二親友','張綱','宋','宋诗','song-poetry','','[]','老來無計了殘年，只有歡情寄酒邊。',32,'全唐诗/poet.song.91000.json','["老來無計了殘年，只有歡情寄酒邊。", "歌舞借看真達士，忍將朱戶鎖嬋娟。"]'),
('2e43ea37-f129-466d-88a1-8ac726b05726','次韻周伯見贈','張綱','宋','宋诗','song-poetry','','[]','幼子童孫乏寸長，遷官同日被榮光。',64,'全唐诗/poet.song.91000.json','["幼子童孫乏寸長，遷官同日被榮光。", "芝蘭瑞色來空翠，雨露恩言滿詔黄。", "莫訝飛騰循九品，會看毫末聳千章。", "即今天子收羣策，廊廟訏謨要主張。"]'),
('ff108d10-a323-4d78-92ea-4b4290e6cc06','用前韻','張綱','宋','宋诗','song-poetry','','[]','百歲休誇日月長，十分逾八歎流光。',64,'全唐诗/poet.song.91000.json','["百歲休誇日月長，十分逾八歎流光。", "精忠許國心猶赤，老病催人髪已黄。", "扶杖每聞宣鳯詔，望雲無路仰龍章。", "恢圖幸有皋夔在，坐看朝綱萬目張。"]'),
('1f793a14-8a3f-44e4-9df3-c94976fb90cd','次韻方守送進士','張綱','宋','宋诗','song-poetry','','[]','下詔徴多士，彈冠動四溟。',48,'全唐诗/poet.song.91000.json','["下詔徴多士，彈冠動四溟。", "三埸遵舊典，八韻見明經。", "勸駕勤州牧，吟牋詫地靈。", "春風歸路近，衫色照山青。"]'),
('8d921544-251d-465d-a555-213724b28da3','次韻周伯謝綿襖長篇','張綱','宋','宋诗','song-poetry','','[]','最宜爲誥唐仲舒，上林子虚漢相如。',176,'全唐诗/poet.song.91000.json','["最宜爲誥唐仲舒，上林子虚漢相如。", "喜君萬事懶着眼，獨向文章情未疏。", "家貧肯戀儋石儲，船漏則已那復袽。", "素志蹉跎雪侵鬢，青衫匍匐塵滿裾。", "可憐虞翻屯骨相，相逢呼我丈人行。", "夜聞抵掌論開邊，怒髪衝冠亦何壯。", "鸘裘典盡終諱寒，忍寒悲歌行路難。", "綈袍恐貽范叔怒，長篇忽拜烏絲闌。", "辭章典要古所尚，餘子碌碌何足仰。", "願君回筆頌皇猷，偃武修文答靈貺。", "天子亟欲聞盡言，前席還應虚黈纊。"]'),
('070a5b13-4014-4f3f-85e2-04aa17f5e493','老夫辭榮里居行年八十酒間漫成拙句二首述意而已不以示外也  其一','張綱','宋','宋诗','song-poetry','','[]','莫笑樽前白髪翁，曾騎竹馬戲元豐。',64,'全唐诗/poet.song.91000.json','["莫笑樽前白髪翁，曾騎竹馬戲元豐。", "年彌八帙癡頑在，身荷三朝寵眷隆。", "綠野敢將前哲比，香山幸有老人同。", "興來尚欲尋幽去，收拾殘春杖屨中。"]'),
('f50b2009-2ba1-4cc7-8bd5-c043842b89b5','老夫辭榮里居行年八十酒間漫成拙句二首述意而已不以示外也  其二','張綱','宋','宋诗','song-poetry','','[]','老病辭榮日月邊，歸來擬作地行仙。',64,'全唐诗/poet.song.91000.json','["老病辭榮日月邊，歸來擬作地行仙。", "飛霜滿鬢三千丈，止水觀心八十年。", "松菊尚存堪寄傲，干戈未定敢安眠。", "君王宵旰圖恢復，洗眼神兵策萬全。"]'),
('75375418-9cd9-45d0-8073-5a117fa329f2','親舊以老夫年及中壽既辱臨况又多以詩詞相慶祝顧衰謝何以得之輒成鄙句叙述感悰','張綱','宋','宋诗','song-poetry','','[]','老來光景去駸駸，親舊應多惜老心。',64,'全唐诗/poet.song.91000.json','["老來光景去駸駸，親舊應多惜老心。", "傾盖義髙雙白璧，開函詩敵萬黄金。", "催年生怕玲瓏唱，醉夜寧辭鑿落深。", "多謝慇懃祝强健，寄言衰病莫相侵。"]'),
('862eec82-0a37-4535-b300-85c388ca3e7f','老病','張綱','宋','宋诗','song-poetry','','[]','蕭然華髪映蒼顔，九帙開來第一年。',64,'全唐诗/poet.song.91000.json','["蕭然華髪映蒼顔，九帙開來第一年。", "鍊盡交游難諱老，養成衰病却安禪。", "新春已負登山屐，舊賞空慚載酒船。", "張緒風流那復少，坐看飛雪弄晴烟。"]'),
('e883782d-f227-4902-bfa4-20457f1ca5d7','送釡孫省試','張綱','宋','宋诗','song-poetry','','[]','英髦雲集幾千人，羣試争看藝絕倫。',64,'全唐诗/poet.song.91000.json','["英髦雲集幾千人，羣試争看藝絕倫。", "一鼓搴旗先作氣，三塲下筆要如神。", "决科無失青氈舊，拜賜重添綠綬新。", "秀發孫枝吾欲見，夢魂已到上林眷。"]'),
('66f596dd-c9a7-4b54-80d3-bf0f4463b4b4','次韻洪總領題花信亭得江樓二首  其一','張綱','宋','宋诗','song-poetry','','[]','誰爲傳花信，新亭破睡風。',48,'全唐诗/poet.song.91000.json','["誰爲傳花信，新亭破睡風。", "春回芳意早，客到賞心同。", "酒盞搖江綠，詩牋照坐紅。", "無由接歡宴，危坐正書空。"]'),
('4b11fb98-3d58-46e7-9217-077bdd1b167d','次韻洪總領題花信亭得江樓二首  其二','張綱','宋','宋诗','song-poetry','','[]','地勝宜樓觀，臨江勢屹然。',48,'全唐诗/poet.song.91000.json','["地勝宜樓觀，臨江勢屹然。", "横波吞翠壁，倒影插雕椽。", "老子難收興，雲安未足憐。", "由來詞翰手，五鳯獨居前。"]'),
('f43b1cfc-c8be-4d8c-aef6-1710fb061087','見華陽舊題刻石有感','張綱','宋','宋诗','song-poetry','','[]','舊句入貞珉，新題亦已陳。',24,'全唐诗/poet.song.91000.json','["舊句入貞珉，新題亦已陳。", "光陰如許速，誰是百年人。"]'),
('12000648-6c66-45fb-8dd4-52d1e31d97b8','某上章辭免召命蒙恩矜許仍賜羊酒存問自念衰殘辱此異數不勝感天荷聖之情謹課成拙詩一首','張綱','宋','宋诗','song-poetry','','[]','昧死飛章上九天，懇辭嚴召卒餘年。',64,'全唐诗/poet.song.91000.json','["昧死飛章上九天，懇辭嚴召卒餘年。", "綸言寵念桑榆迫，臺餽恩垂雨露偏。", "異數一時真創見，窮鄉萬口徧誇傳。", "吾衰忝冒知難報，結草他年敢避先。"]'),
('fe20f90e-7564-4cf9-b590-6919657926fa','用前韻','張綱','宋','宋诗','song-poetry','','[]','召節煌煌下帝關，君王圖舊起髙年。',64,'全唐诗/poet.song.91000.json','["召節煌煌下帝關，君王圖舊起髙年。", "露章懇避回天速，拜命歡呼壓地偏。", "錫饌宰官侵夜到，問安州牧置郵傳。", "辭榮有耀人皆說，誰解清時獨占先。"]'),
('13b044ac-7ea4-4fa8-b117-2302fcea7db2','考妣贈官一時榮耀老懷易感輒敬書長句','張綱','宋','宋诗','song-poetry','','[]','絲綸五色錦爲囊，寵贈雙親廟室光。',64,'全唐诗/poet.song.91000.json','["絲綸五色錦爲囊，寵贈雙親廟室光。", "位列三孤升極品，名加大國啟新疆。", "劬勞仰荷湛恩報，精爽應知積慶長。", "燕及子孫宜勉力，忠勤他日繼遺芳。"]'),
('60fd775a-42c1-4610-bd75-6adc1cc3fd8a','送彦禮弟赴歙尉四首  其一','張綱','宋','宋诗','song-poetry','','[]','莫辭官小路間關，趁取春風稳着鞭。',32,'全唐诗/poet.song.91000.json','["莫辭官小路間關，趁取春風稳着鞭。", "無限清時推轂手，冲天何必待三年。"]'),
('06d872bc-1b13-44d7-84c3-6a5205191604','送彦禮弟赴歙尉四首  其二','張綱','宋','宋诗','song-poetry','','[]','池塘春草促君詩，阿緒風流絮欲飛。',32,'全唐诗/poet.song.91000.json','["池塘春草促君詩，阿緒風流絮欲飛。", "滿眼吾家好風景，正須相賞忽相違。"]'),
('66ce0111-25e7-47b7-b9ec-d6649890ded2','送彦禮弟赴歙尉四首  其三','張綱','宋','宋诗','song-poetry','','[]','高才自是古梅仙，綵棒何須向壁懸。',32,'全唐诗/poet.song.91000.json','["高才自是古梅仙，綵棒何須向壁懸。", "晉盜奔秦無一事，爐薫深炷好安禪。"]'),
('83ccfb12-10f1-4db2-8024-ddb5f921231e','送彦禮弟赴歙尉四首  其四','張綱','宋','宋诗','song-poetry','','[]','空詩羞澀送君行，老病難堪叙别情。',32,'全唐诗/poet.song.91000.json','["空詩羞澀送君行，老病難堪叙别情。", "天假吾年未填壑，它時猶及問歸程。"]'),
('8535e57b-0ffe-4623-8546-20ab6efb01b3','舊所乘馬老且瘠見之感懷','張綱','宋','宋诗','song-poetry','','[]','人衰馬亦老，不踏長安道。',48,'全唐诗/poet.song.91000.json','["人衰馬亦老，不踏長安道。", "筋力漸疲羸，鞍韉謾華好。", "見我勿嘶鳴，爲爾動懷抱。", "無復矍鑠時，去去飽豐草。"]'),
('ae50cbf0-e1eb-47c0-a3c5-84f63217eade','夜思出處因作戲言','張綱','宋','宋诗','song-poetry','','[]','仕路定風波，人生能幾何。',24,'全唐诗/poet.song.91000.json','["仕路定風波，人生能幾何。", "時來聊試手，爲瑞不宜多。"]'),
('4b2507ad-3a8a-4f04-924e-f439cbc04d77','老來交朋淪謝雖婢僕亦無在者感舊忽覺凄然','張綱','宋','宋诗','song-poetry','','[]','故交淪没水東流，歲晚無人話昔遊。',32,'全唐诗/poet.song.91000.json','["故交淪没水東流，歲晚無人話昔遊。", "飛絮落花何足道，忽經風雨亦添愁。"]'),
('9e8eac3d-17c2-47f5-917c-f4ec45fa05c5','顯仁皇后挽詞三首  其一','張綱','宋','宋诗','song-poetry','','[]','輔漢陰功大，生商寶運開。',48,'全唐诗/poet.song.91000.json','["輔漢陰功大，生商寶運開。", "俸從湯邑省，恩向外家裁。", "奄忽乘仙馭，劬勞動聖哀。", "園陵奉遺誥，終不費邦財。"]'),
('a952ce36-6b39-421b-a30a-4770c0320d59','顯仁皇后挽詞三首  其二','張綱','宋','宋诗','song-poetry','','[]','長樂坤儀肅，思齊母道全。',48,'全唐诗/poet.song.91000.json','["長樂坤儀肅，思齊母道全。", "九州供大養，八帙茂遐年。", "仗簇江山外，哀纒日月邊。", "遺芳歸史筆，萬古照青編。"]'),
('800f8906-18f5-4075-83db-8fabe8a1e88a','顯仁皇后挽詞三首  其三','張綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','仗去慈寧殿，神歸永祐宫。',48,'全唐诗/poet.song.91000.json','["仗去慈寧殿，神歸永祐宫。", "問安迷輦道，灑泣慟宸衷。", "水逝長江月，天號宰木風。", "平生尚慈儉，流澤到無窮。"]'),
('228c7445-3a6f-411f-9c28-57fe1b045829','鄭國太挽詞四首  其一','張綱','宋','宋诗','song-poetry','','[]','五福兼全舉世稀，庭闈早日見清規。',64,'全唐诗/poet.song.91000.json','["五福兼全舉世稀，庭闈早日見清規。", "應期千載生公輔，掩迹三遷號母師。", "漢魏疏封華國史，蘋蘩遺德繼周詩。", "年年只說重陽近，無復黄花酒一巵。"]'),
('44ea5a05-a376-49c2-97d4-8d9856388cd0','鄭國太挽詞四首  其二','張綱','宋','宋诗','song-poetry','','[]','一夕萱堂事已非，百年遺範在豐碑。',64,'全唐诗/poet.song.91000.json','["一夕萱堂事已非，百年遺範在豐碑。", "頒花玉殿春風暖，奉詔登樓夜漏移。", "罷宴已聞修故事，回班那復見新儀。", "音容寂寞應仙去，香火因緣只自知。"]'),
('557d1973-0b86-400f-ab7f-5fc508f6651b','鄭國太挽詞四首  其三','張綱','宋','宋诗','song-poetry','','[]','蘭桂秋風一夜催，袞衣何處望南陔。',64,'全唐诗/poet.song.91000.json','["蘭桂秋風一夜催，袞衣何處望南陔。", "堂垂斗帳銷香篆，鑑掩飛鸞下玉臺。", "漢使從天虚鹵簿，胡笳和月助悲哀。", "東門咫尺佳城在，雙鶴飛空日幾回。"]'),
('b478c9df-a454-4df7-9e8b-aec94cba89bc','鄭國太挽詞四首  其四','張綱','宋','宋诗','song-poetry','','[]','銘旌冉冉去飛揚，蕭瑟西風泣畫堂。',64,'全唐诗/poet.song.91000.json','["銘旌冉冉去飛揚，蕭瑟西風泣畫堂。", "不見魚軒辭繡轂，空餘鸞誥冷綃囊。", "姓名自是標仙籍，環珮應知返帝鄉。", "盡把遺芳歸史筆，會令千古獨輝煌。"]'),
('841e428f-5e83-435d-a2b9-515804757397','何丞相挽詞三首  其一','張綱','宋','宋诗','song-poetry','','[]','一德乘亨運，三公冠宰司。',48,'全唐诗/poet.song.91000.json','["一德乘亨運，三公冠宰司。", "秉鈞回直道，解組向明時。", "人去空圖畫，名存粲鼎彛。", "懸知千古後，貪懦激清規。"]'),
('d2eb6edb-c6cf-4815-a136-585d7ea3533a','何丞相挽詞三首  其二','張綱','宋','宋诗','song-poetry','','[]','帝念虧三鑑，天臨動八鑾。',48,'全唐诗/poet.song.91000.json','["帝念虧三鑑，天臨動八鑾。", "飛星瞻傅說，舊學記甘盤。", "治定身先退，名全德不刊。", "于何驗符策，有子嗣鴛鸞。"]'),
('6d3ef69e-8d0e-4796-8b22-e6cb5007444a','何丞相挽詞三首  其三','張綱','宋','宋诗','song-poetry','','[]','不憖遺元老，巖巖失具瞻。',48,'全唐诗/poet.song.91000.json','["不憖遺元老，巖巖失具瞻。", "勳庸扶廟社，名字到閭閻。", "王國開封大，師垣寵數兼。", "夢雞初莫省，今日竟成占。"]'),
('85b21422-889a-4291-97cc-c6c1f7887ee2','譚勝仲挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','詞伯風騷舊，公朝宿望存。',48,'全唐诗/poet.song.91000.json','["詞伯風騷舊，公朝宿望存。", "郎官寧出宰，廷尉亟平反。", "夢斷天衢遠，愁連野樹昏。", "祗應陰德茂，蘭玉照于門。"]'),
('49eb28d8-8560-45cf-bf5b-de200391feff','譚勝仲挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','時論歸清德，耽書到白頭。',48,'全唐诗/poet.song.91000.json','["時論歸清德，耽書到白頭。", "士應知己用，人豈法家流。", "骨瘦凌孤鶴，詩豪壓萬牛。", "悲看耆舊傳，誰復繼前修。"]'),
('c054d9a5-6003-4f30-b110-78c180aec23c','湯德廣挽詞三首  其一','張綱','宋','宋诗','song-poetry','','[]','四海知名士，三朝老從臣。',48,'全唐诗/poet.song.91000.json','["四海知名士，三朝老從臣。", "勤王安反側，分閫試經綸。", "天闊鴛行斷，山空馬鬛新。", "豐碑滿忠義，千古詔簪紳。"]'),
('8dee91af-d995-458f-b6f2-01df57364ca6','湯德廣挽詞三首  其二','張綱','宋','宋诗','song-poetry','','[]','忠憤憂時切，風雲得路先。',48,'全唐诗/poet.song.91000.json','["忠憤憂時切，風雲得路先。", "官箴循吏傳，家法棣華篇。", "滅虜兵方急，優賢席屢前。", "如何天不憖，髙冢臥蒼烟。"]'),
('8e9ccdcc-82e6-4779-8c10-7f826ee280a0','湯德廣挽詞三首  其三','張綱','宋','宋诗','song-poetry','','[]','束髪師前輩，忘年得此翁。',48,'全唐诗/poet.song.91000.json','["束髪師前輩，忘年得此翁。", "雞豚同里社，詩禮共家風。", "别去十年久，書無三月空。", "歸來人不見，銘旐舞斜紅。"]'),
('a46cfd94-66a1-4d59-a850-b3724989139b','張彦度挽詩二首  其一','張綱','宋','宋诗','song-poetry','','[]','京兆吾宗不乏人，煌煌朱紱照簪紳。',64,'全唐诗/poet.song.91000.json','["京兆吾宗不乏人，煌煌朱紱照簪紳。", "棠陰訟簡絃歌樂，蓮幕才髙畫諾新。", "北海但知樽有酒，莱蕪誰念甑生塵。", "哀笳忽送秋風急，忍看遺踪萬古陳。"]'),
('6b16da5d-ff55-458f-b5ed-83b724c31814','張彦度挽詩二首  其二','張綱','宋','宋诗','song-poetry','','[]','滿目溪山舊賞心，杖藜那復共登臨。',64,'全唐诗/poet.song.91000.json','["滿目溪山舊賞心，杖藜那復共登臨。", "平生友誼情無間，累世宗盟分更深。", "顧我老懷誰告語，思君遙夜獨悲吟。", "流風賴有諸郎在，他日相親倘嗣音。"]'),
('3ff4fbac-039d-400c-a4af-5ce5d2bea262','莊弱翁挽詩二首  其一','張綱','宋','宋诗','song-poetry','','[]','厚德鄉評最，知名國士同。',48,'全唐诗/poet.song.91000.json','["厚德鄉評最，知名國士同。", "郎曹參列宿，宰屬輔宗工。", "紫詔恩垂下，黄梁夢已空。", "九原那可作，流涕濕西風。"]'),
('374a8723-5082-496d-b8c7-7589d2d928f4','莊弱翁挽詩二首  其二','張綱','宋','宋诗','song-poetry','','[]','仕路青霄逼，還家白髪生。',48,'全唐诗/poet.song.91000.json','["仕路青霄逼，還家白髪生。", "一麾驚作夢，三徑適幽情。", "孰謂如蘭契，先隨逝水傾。", "送君悽斷處，烟雨暗銘旌。"]'),
('6eb034d2-c578-494e-b1ba-e988317703bd','胡氏碩人挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','吾舅當朝傑，幽芳配德同。',48,'全唐诗/poet.song.91000.json','["吾舅當朝傑，幽芳配德同。", "典刑家法整，湯沐上恩隆。", "鸞影悲塵鑑，蘭芬泣露叢。", "音容不知處，宰木夜號風。"]'),
('2ed567c5-501f-46eb-b654-9d7af3b0e6f7','胡氏碩人挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','我有劬勞念，多從外氏遊。',48,'全唐诗/poet.song.91000.json','["我有劬勞念，多從外氏遊。", "母儀頻接侍，賓饋每淹留。", "應惜年垂老，相親禮特優。", "一朝千古别，衰淚不能收。"]'),
('65c68754-06a8-4f74-8344-839155cf853a','舅李侍郎挽詞三首  其一','張綱','宋','宋诗','song-poetry','','[]','射策飛騰早，推賢望實兼。',48,'全唐诗/poet.song.91000.json','["射策飛騰早，推賢望實兼。", "直心常自負，大器果難淹。", "持橐丹墀稳，分符畫戟嚴。", "平生莫追憶，淚盡轉愁添。"]'),
('ab78fbeb-e92a-48f3-9abb-87675ed1234f','舅李侍郎挽詞三首  其二','張綱','宋','宋诗','song-poetry','','[]','諸舅唯公在，承顔念母存。',48,'全唐诗/poet.song.91000.json','["諸舅唯公在，承顔念母存。", "笑看身已老，情話意彌温。", "不作求田計，方期報主恩。", "髙堂忽蕭瑟，誰爲賦招魂。"]'),
('3e10a1d4-59a6-460d-8666-0b72972665c0','舅李侍郎挽詞三首  其三','張綱','宋','宋诗','song-poetry','','[]','彊健公先去，零丁我曷從。',48,'全唐诗/poet.song.91000.json','["彊健公先去，零丁我曷從。", "同盟空白水，酷似有衰容。", "休說鵷行夢，看成馬鬛封。", "淚流南望眼，愁絕暮雲重。"]'),
('f94b3ed1-f439-4e69-a3dd-c2a99837c9ab','洪慶善挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','畫省真郎選，朱幡老郡侯。',48,'全唐诗/poet.song.91000.json','["畫省真郎選，朱幡老郡侯。", "名歸時論重，行向古人求。", "嗜學千雞跖，修文五鳯樓。", "秋風忽驚夢，懷舊涕交流。"]'),
('d76eca99-eb79-4fed-bb66-d613d9c5f3c0','洪慶善挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','忝戚鄉閭舊，論交道義深。',48,'全唐诗/poet.song.91000.json','["忝戚鄉閭舊，論交道義深。", "窮搜千古意，樂易一生心。", "遭謗身雖貶，全名死不沉。", "君恩爲昭雪，歸窆得家林。"]'),
('0b5c7268-6637-42ab-9942-2591aad78aa8','吳氏太淑人挽詞','張綱','宋','宋诗','song-poetry','','[]','生兒要路早飛騰，玉瑱金花寵屢膺。',64,'全唐诗/poet.song.91000.json','["生兒要路早飛騰，玉瑱金花寵屢膺。", "天壽康寧逾九帙，佛心明了契三乘。", "葭莩永歎音容阻，閭里空存孝義稱。", "追想潘輿從游處，青青烟草正愁凝。"]'),
('aa906d00-437a-4bea-a034-09082c2a1cf6','陳叔美挽詞','張綱','宋','宋诗','song-poetry','','[]','坦腹東牀衆莫奇，堂堂吾弟獨君知。',64,'全唐诗/poet.song.91000.json','["坦腹東牀衆莫奇，堂堂吾弟獨君知。", "交親未及親三歲，淪喪俄驚共一時。", "琴在我方悲子敬，禮存誰爲哭言思。", "山阿幽室千年閟，挽語空吟靖節詩。"]'),
('290981bb-3137-44af-8259-2188a1feb24b','外祖李承事挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','總角承顔賴擊蒙，後生因識古人風。',64,'全唐诗/poet.song.91000.json','["總角承顔賴擊蒙，後生因識古人風。", "忘情自到羲皇上，盛事多談慶曆中。", "雙壽兒孫青若若，一門慈孝鬱葱葱。", "吁嗟耆舊今何在，古木斜陽瀨水空。"]'),
('3334da5d-0678-438d-882b-57a202395a43','外祖李承事挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','西山忽與老人期，未報深恩忍復思。',64,'全唐诗/poet.song.91000.json','["西山忽與老人期，未報深恩忍復思。", "燕及祖風從少小，與聞家訓識操持。", "聊從諸舅紀遺行，深愧外孫無好辭。", "懸想追封在他日，附書名傳有佳兒。"]'),
('e5dc1fe5-558d-43a9-8ded-cbb278cf6fb0','舅李義卿挽詞','張綱','宋','宋诗','song-poetry','','[]','由來甥舅兩相依，存没誰知半路虧。',64,'全唐诗/poet.song.91000.json','["由來甥舅兩相依，存没誰知半路虧。", "在側每蒙誇叔寶，不才那得似牢之。", "臨風酌酒酬春處，對月凴軒語夜時。", "回首凄凉已陳迹，壯心無哭奈愁思。"]'),
('d409b0d0-5be3-4cb1-a94e-96205549cc54','沈洞元挽詞','張綱','宋','宋诗','song-poetry','','[]','天闕辭嚴召，雲棲得坐忘。',48,'全唐诗/poet.song.91000.json','["天闕辭嚴召，雲棲得坐忘。", "尊生三洞籙，起死上池方。", "神託飛魚化，丹餘舊竈香。", "從今紀甲子，華表佇還鄉。"]'),
('77def840-9ff7-4f14-ae0f-cb5ee3b7cc92','徐獻仲挽詞','張綱','宋','宋诗','song-poetry','','[]','一尊相别未經時，情話如今忍復思。',64,'全唐诗/poet.song.91000.json','["一尊相别未經時，情話如今忍復思。", "老去交親能有幾，年來懷抱更誰知。", "谿橋路斷秋風急，香火庭空曉日遲。", "三尺孤墳閉千古，傷心東望涕交頤。"]'),
('084b843d-de07-4daa-8e74-b07d9d606748','丁宣仲挽詞','張綱','宋','宋诗','song-poetry','','[]','回首三年别，追懷一笑歡。',48,'全唐诗/poet.song.91000.json','["回首三年别，追懷一笑歡。", "坐移香砌暖，飲散燭花殘。", "蒿里歸何速，桃蹊忍更看。", "秋原愁絕處，爲想鶺鴒寒。"]'),
('5e68ef8e-5977-4507-89be-20df1da258da','李居正挽詞','張綱','宋','宋诗','song-poetry','','[]','白首論交舊，黄冠獨此人。',48,'全唐诗/poet.song.91000.json','["白首論交舊，黄冠獨此人。", "誠全知俗薄，語直見情親。", "上館鍾魚在，空壇月露新。", "如今入山去，行處是悲辛。"]'),
('156bec25-ab56-497e-96b9-3d2d91564d34','丁明仲挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','世德知名早，鄉評第一流。',48,'全唐诗/poet.song.91000.json','["世德知名早，鄉評第一流。", "折腰官易厭，拄頰興難收。", "博物千尋海，髙情百尺樓。", "平生松菊徑，蕭瑟晚雲秋。"]'),
('923b45f9-bf92-480f-a3ab-f3de2d80ea34','丁明仲挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','里社欣相接，葭莩晚益親。',48,'全唐诗/poet.song.91000.json','["里社欣相接，葭莩晚益親。", "過從忘客禮，簡易見天真。", "把酒微風夜，歸舟細雨春。", "如今每追憶，悽慟欲傷神。"]'),
('bbc2fc7e-25b0-41b0-876f-06d3dac7f89d','陳美成挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','望族推平輿，清芬嗣太邱。',48,'全唐诗/poet.song.91000.json','["望族推平輿，清芬嗣太邱。", "鄉評嚴禮法，家學邃源流。", "幸託葭莩契，方期仗履遊。", "西風忽悲惨，忍復看眠牛。"]'),
('b3219017-ebd1-4325-b7ef-9bd19d67b4d0','陳美成挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','德潤洮湖闊，心平福地安。',48,'全唐诗/poet.song.91000.json','["德潤洮湖闊，心平福地安。", "流風前輩似，雅量鄙夫寛。", "松菊開三徑，芝蘭秀二難。", "百年如轉燭，蕭瑟夜堂寒。"]'),
('b1a5527a-403c-4272-87dc-ea2834278ef8','丁宋卿挽詞','張綱','宋','宋诗','song-poetry','','[]','舊約頻相過，交情忍獨違。',48,'全唐诗/poet.song.91000.json','["舊約頻相過，交情忍獨違。", "四時閑杖履，一榻冷烟霏。", "易感龍祠别，難期鶴馭歸。", "老懷誰共語，東望益霑衣。"]'),
('381e2f2b-bdec-4e23-8d8b-800739381f28','彦飾弟挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','吾家奕奕茂芝蘭，士論尤推季孟間。',64,'全唐诗/poet.song.91000.json','["吾家奕奕茂芝蘭，士論尤推季孟間。", "挾策可憐埸屋老，杜門空對水雲間。", "嗟余屏跡常多病，幸爾論心數解顔。", "乘興過從無復日，忍將愁眼望西山。"]'),
('1c5e7913-dc3c-42b0-866a-f78c9affde61','彦飾弟挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','解組歸來會面初，杖藜朝暮過吾廬。',64,'全唐诗/poet.song.91000.json','["解組歸來會面初，杖藜朝暮過吾廬。", "相親樽酒情無間，共話田園樂有餘。", "樗散年頹方倚託，棣華風急頓蕭疏。", "堂堂人物無髙壽，不那哀傷淚滿裾。"]'),
('968ddebb-957c-477a-99f5-aad29b1c4c96','彦深弟挽詞','張綱','宋','宋诗','song-poetry','','[]','憶弟懸弧日，當余弱冠年。',48,'全唐诗/poet.song.91000.json','["憶弟懸弧日，當余弱冠年。", "艱勤同素志，衰病各華顛。", "辭禄歸相倚，驚魂去忽先。", "一樽風雨夜，那復共蟬聯。"]'),
('6c8234ef-6856-4715-ba3b-8b3d47511f3a','陳子張挽詞二首  其一','張綱','宋','宋诗','song-poetry','','[]','地發湖光秀，神鍾鶴骨清。',48,'全唐诗/poet.song.91000.json','["地發湖光秀，神鍾鶴骨清。", "髙談排俗子，執友遍時英。", "枳棘鸞棲在，松楸馬鬛成。", "欲收東望眼，流涕若爲情。"]'),
('255e59c2-f6e2-47b9-8afb-88052d5f0f12','陳子張挽詞二首  其二','張綱','宋','宋诗','song-poetry','','[]','交契先朝露，凄凉對夕暉。',48,'全唐诗/poet.song.91000.json','["交契先朝露，凄凉對夕暉。", "箕裘三世遠，簿領一官微。", "翠柏開新隧，青編冷舊幃。", "元方未慚長，萬里看横飛。"]'),
('796d8223-9eb4-4b3c-acd0-dc1f589cf100','堅所生母李氏安人挽詞五首  其一','張綱','宋','宋诗','song-poetry','','[]','仙李移根遠，夭桃表慶長。',48,'全唐诗/poet.song.91000.json','["仙李移根遠，夭桃表慶長。", "九重頒象服，三世奉萱堂。", "尚想慈祥性，難追淡靚粧。", "眼酸生怕哭，雙淚忽淋浪。"]'),
('630a3e96-90d0-4fda-b675-ace117257197','堅所生母李氏安人挽詞五首  其二','張綱','宋','宋诗','song-poetry','','[]','四德騰芳早，三乘悟性空。',48,'全唐诗/poet.song.91000.json','["四德騰芳早，三乘悟性空。", "清修忘俗累，勤儉肅家風。", "舞鏡鸞悲影，飛花雨泣叢。", "愁情無處著，半入夢魂中。"]'),
('c766e648-8257-4969-8f2d-013122291ae2','堅所生母李氏安人挽詞五首  其三','張綱','宋','宋诗','song-poetry','','[]','舊約余偕老，分違汝忽先。',48,'全唐诗/poet.song.91000.json','["舊約余偕老，分違汝忽先。", "有懷中饋闕，無憾母儀全。", "望斷送歸路，衷纒垂盡年。", "何當卜同穴，相與伴愁烟。"]'),
('76cc4dcf-fef5-4304-a4c4-7705eb672812','堅所生母李氏安人挽詞五首  其四','張綱','宋','宋诗','song-poetry','','[]','七帙開逾半，孤芳散若飄。',48,'全唐诗/poet.song.91000.json','["七帙開逾半，孤芳散若飄。", "可憐頻舉案，那復記吹簫。", "翠幌浮埃積，熏爐舊炷消。", "如何寄懷抱，細雨夜蕭蕭。"]'),
('d28697a9-62a4-45e0-8316-75667fc2f43c','道士王如晦真贊  其一','張綱','宋','宋诗','song-poetry','','[]','色如春溫，若可與言。',48,'全唐诗/poet.song.91000.json','["色如春溫，若可與言。", "神如水清，不可以煩。", "子喬仙去遠矣，乃今識其裔孫。", "任造化之日逝，獨湛然而常存。"]'),
('ea1a52fb-e11d-4305-8fe4-530274155bc0','道士王如晦真贊  其二','張綱','宋','宋诗','song-poetry','','[]','道風仙骨照青春，誰寫生綃卻亂真。',32,'全唐诗/poet.song.91000.json','["道風仙骨照青春，誰寫生綃卻亂真。", "莫訝三毛不加頰，齊公端解視全人。"]'),
('978106b2-6ee0-4166-abe7-3f1bbc075fb4','道士李沖妙真贊  其一','張綱','宋','宋诗','song-poetry','','[]','蟠根仙李萬葉敷，遺芳豈直黄冠徒。',80,'全唐诗/poet.song.91000.json','["蟠根仙李萬葉敷，遺芳豈直黄冠徒。", "吐氣硉矹古丈夫，味道之腴貌何癯。", "誰令畏壘俎豆予，龍吟虎嘯人爭趨。", "故棲猿鶴情未疏，翻然脫屣吾歸歟。", "舍者爭席不關渠，向來形諜誠區區。"]'),
('7b848967-d3c6-4112-99a0-0b3d7c6c253f','道士李沖妙真贊  其二','張綱','宋','宋诗','song-poetry','','[]','領袖名山，龍吟虎嘯。',51,'全唐诗/poet.song.91000.json','["領袖名山，龍吟虎嘯。", "忽辭屨於戶外，信光矣而不耀。", "是將沖而用之，深入乎衆妙之門。", "吾不知其人，曰伯陽之孫。"]'),
('a90cb02f-0200-4e3a-b975-b1a6b75f6de0','自贊寫真  其一','張綱','宋','宋诗','song-poetry','','[]','堂堂莫作公侯想，是身如幻無定相。',32,'全唐诗/poet.song.91000.json','["堂堂莫作公侯想，是身如幻無定相。", "衣冠掛卻神武門，便是維摩坐方丈。"]'),
('2a68a3ce-2071-4ed9-9ec2-efd512e986e8','自贊寫真  其二','張綱','宋','宋诗','song-poetry','','[]','投閑歲久，聖恩圖舊。',40,'全唐诗/poet.song.91000.json','["投閑歲久，聖恩圖舊。", "載錫身章，在帝左右。", "骨相多屯，何以瘉人。", "陳力就列，勿爲具臣。"]'),
('d2d716da-367a-48e5-b956-c13660d325e4','南洞即事','張綱','宋','宋诗','song-poetry','','[]','紫綬金章八十三，衰殘不稱舊官銜。',32,'全唐诗/poet.song.91000.json','["紫綬金章八十三，衰殘不稱舊官銜。", "煩君寫作歸田老，野野翛然坐碧巖。"]'),
('2184bbd4-546e-4809-a79f-7a0dec3ada56','偈','釋文觀','宋','宋诗','song-poetry','','[]','過去諸如來，斯門已成就，好事不如無。',54,'全唐诗/poet.song.91000.json','["過去諸如來，斯門已成就，好事不如無。", "現在諸菩薩，今各入圓明，好事不如無。", "未來修學人，當依如是住，好事不如無。"]'),
('9234dbae-7cd0-4db0-ade2-a05f25f14e1d','頌古三首  其一','釋文觀','宋','宋诗','song-poetry','','[]','冬瓜蘸雪未爲淡，匠者三文淡最幽。',32,'全唐诗/poet.song.91000.json','["冬瓜蘸雪未爲淡，匠者三文淡最幽。", "淡最幽，天共白雲曉，水和明月流。"]'),
('6a96b75e-fdd7-41a4-8826-234afc2befc0','頌古三首  其二','釋文觀','宋','宋诗','song-poetry','','[]','趙州勘破老婆時，恰似青春三月裏。',32,'全唐诗/poet.song.91000.json','["趙州勘破老婆時，恰似青春三月裏。", "陌上遊人爭看花，鷓鴣啼處誰相委。"]'),
('259842eb-7e5f-4dd6-b670-e8836113722f','頌古三首  其三','釋文觀','宋','宋诗','song-poetry','','[]','冰雪肌膚西舍女，梳粧巧巧畫雙眉。',32,'全唐诗/poet.song.91000.json','["冰雪肌膚西舍女，梳粧巧巧畫雙眉。", "傍人筆力強傳寫，戶外如何見得伊。"]'),
('8da65d4a-7964-46ad-b557-70909eea2870','頌古','釋可觀','宋','宋诗','song-poetry','','[]','夾山不在一橈上，明月蘆花夜夜寒。',32,'全唐诗/poet.song.91000.json','["夾山不在一橈上，明月蘆花夜夜寒。", "誰謂華亭消息斷，儼然秋色在江山。"]'),
('30b6f4df-b1cf-4962-83a3-cfa38ae72b31','重九','釋可觀','宋','宋诗','song-poetry','','[]','胸中一寸灰已冷，頭上千莖雪未消。',32,'全唐诗/poet.song.91000.json','["胸中一寸灰已冷，頭上千莖雪未消。", "老步只宜平地去，不知何事又登高。"]'),
('3ed10b66-4148-4a7b-a071-bb6aeeb1794d','自題像','釋可觀','宋','宋诗','song-poetry','','[]','維摩詰不壞於身，而隨一相老竹庵。',40,'全唐诗/poet.song.91000.json','["維摩詰不壞於身，而隨一相老竹庵。", "壞與不壞，初無欠長。", "到處江山風月，不是這個伎倆。"]'),
('19cafd5b-a89b-4edd-97d2-5e4eca375427','五峰巖','劉濤','宋','宋诗','song-poetry','','[]','五峰巖在白雲間，巖下千山與萬山。',32,'全唐诗/poet.song.91000.json','["五峰巖在白雲間，巖下千山與萬山。", "莫向公卿容易道，恐伊來此一生閑。"]'),
('167cb607-40c3-4dbe-9423-f59fc481fa8c','延福寺','劉濤','宋','宋诗','song-poetry','','[]','唐時賢士今何在，晉代青松獨此存。',32,'全唐诗/poet.song.91000.json','["唐時賢士今何在，晉代青松獨此存。", "往事悠悠何處問，金雞山色又黄昏。"]'),
('2981264c-ea29-46ac-83d3-05ca51070ab7','思古堂','劉濤','宋','宋诗','song-poetry','','[]','今人思古不如古，後代思今亦似今。',32,'全唐诗/poet.song.91000.json','["今人思古不如古，後代思今亦似今。", "古往今來祇如此，溪山傷盡幾人心。"]'),
('98cd89da-cf63-4589-98e7-212abb36d2d6','處士林知墓','劉濤','宋','宋诗','song-poetry','','[]','處士墳三尺，吳山松萬株。',48,'全唐诗/poet.song.91000.json','["處士墳三尺，吳山松萬株。", "空餘著書業，不見煉丹爐。", "道古言難合，年高勢最孤。", "盛朝禮樂備，無處用真儒。"]'),
('69838010-1ee6-4b46-9ae4-71bfba171eb1','建炎丞相成國呂忠穆公退老堂  其一','張澂','宋','宋诗','song-poetry','','[]','均佚歸來一品崇，赤城新野煥仙風。',64,'全唐诗/poet.song.91000.json','["均佚歸來一品崇，赤城新野煥仙風。", "功存社稷今全德，身佩安危本至公。", "寧似樂天丹竈破，不令北海酒樽空。", "中原未靖戎氛惡，會有訏謨沃舜聰。"]'),
('703b9784-a2c9-4138-b8fd-28786e6359ab','建炎丞相成國呂忠穆公退老堂  其二','張澂','宋','宋诗','song-poetry','','[]','背郭堂成樂趣真，碧油幢下海山春。',64,'全唐诗/poet.song.91000.json','["背郭堂成樂趣真，碧油幢下海山春。", "誰知種木十年手，元是擎天一柱人。", "久矣威名彰草木，行須談笑靜風塵。", "寧容巾屨長閑逸，即看金甌寵數新。"]'),
('832b1f2f-9553-4aa8-bd49-80725be60e90','青雲亭','張澂','宋','宋诗','song-poetry','','[]','昔者青雲亭，位置直巽隅。',72,'全唐诗/poet.song.91000.json','["昔者青雲亭，位置直巽隅。", "旴江入懷抱，靈谷當襟裾。", "百年但草茀，兔葵雜榛蕪。", "我登問安堂，凝睇爽氣俱。", "相將還絕賞，翬飛接雲鳬。", "卻望州郭盛，五峰畫不如。"]'),
('33037412-d97e-4876-ae6c-080384e225db','雷公山','張澂','宋','宋诗','song-poetry','','[]','年大嗜煙壑，心鄙城郭近。',192,'全唐诗/poet.song.91000.json','["年大嗜煙壑，心鄙城郭近。", "籃輿踐晨霜，峭蒨入雲畛。", "病衰風見乘，放浪顧難忍。", "駕言小玩愒，微尚希遯隱。", "隱淪著扁舟，欲濟江無流。", "岧嶤雷公山，信美慚薄遊。", "夕煙散林谷，暮鐘鳴寺樓。", "撫事百感集，聊茲兼夕留。", "留情不復懽，惻惻抱悲嘆。", "何以紓拂鬰，曳策青雲端。", "雷祠蔽深莽，靈宮俯層巒。", "下視萬壑趨，遙見千峰攢。", "攢峰娛余心，領略悟山陰。", "平生一丘壑，何須故山岑。", "放懷白鳥盟，斯焉得重尋。", "題詩謝靈山，勿閟金玉音。"]'),
('4e1884e0-0af0-4af7-929a-a680c5cb5e2c','嵯峨嶺','張澂','宋','宋诗','song-poetry','','[]','晨登嵯峨嶺，危欲搏春冥。',24,'全唐诗/poet.song.91000.json','["晨登嵯峨嶺，危欲搏春冥。", "安得秦六甲，鎚鑿使之平。"]'),
('506b447c-525c-4db1-b953-1e1f68bd2c58','蝦蟆石','張澂','宋','宋诗','song-poetry','','[]','千峰來南兮萬馬奔，翠麓卻立兮如飲江之黿。',100,'全唐诗/poet.song.91000.json','["千峰來南兮萬馬奔，翠麓卻立兮如飲江之黿。", "湫靈沸黑兮神物生，雲霧晝晦兮風憀慄而凄清。", "我愛灘瀧㶁㶁兮寒瀨齒齒，浮我江䑳兮歲不知其幾。", "石中之人兮喜我不屑，華我以春花兮食我以秋實。", "我棄而不即兮獨不清冷弄明月。"]'),
('8334cafb-019d-4591-aa8d-686677abc1e3','鑿石潭','張澂','宋','宋诗','song-poetry','','[]','船去臨川郭，江深鑿石潭。',48,'全唐诗/poet.song.91000.json','["船去臨川郭，江深鑿石潭。", "梅花如庾嶺，客路厭江南。", "晚日明深谷，長煙繚翠嵐。", "極知江路近，終約艤浮驂。"]'),
('f9346936-e347-44ad-9eb4-a15c1d2f90e5','源潭','張澂','宋','宋诗','song-poetry','','[]','露槳依灘急，霜飚入鬢清。',48,'全唐诗/poet.song.91000.json','["露槳依灘急，霜飚入鬢清。", "秋痕到晴樹，江勢擁孤城。", "野鶴疑仙分，檣烏伴水程。", "故園千嶂外，白首不勝情。"]'),
('971004bc-4b17-4333-974b-b293a5154bdf','述陂橘','張澂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','述陂元是一滄州，四繞澄江璧水流。',128,'全唐诗/poet.song.91000.json','["述陂元是一滄州，四繞澄江璧水流。", "肥腴不但便黍麥，清瘦尤宜橘柚秋。", "秋風籬落青間黄，王孫金彈天雨霜。", "甘寒入齒冰漿冷，氣馥吳姬翠袖香。", "我衰不辦作李衡，木奴千戶供我耕。", "但愛洞庭春色好，細釀只許幽人傾。", "傳柑酷憶風光裏，懷橘真成淚如洗。", "陂傍儻種三百栽，商山之樂吾得矣。"]'),
('23d2b711-ed4f-4d12-bcc1-49d62837a9f7','椑侯柿','張澂','宋','宋诗','song-poetry','','[]','家山謬說冷糖霜，未若椑侯遠擅場。',64,'全唐诗/poet.song.91000.json','["家山謬說冷糖霜，未若椑侯遠擅場。", "甘似醍醐成蜜汁，寒於瑪瑙貯冰漿。", "學書博士空題葉，病渴文園卻屢嘗。", "不識梁侯底處所，虎賁要是似中郎。"]'),
('10526da8-c010-4c07-ab9c-1c83cf94470c','文昌軒','張澂','宋','宋诗','song-poetry','','[]','峭蒨雲煙曉騎迷，地偏心遠愛林扉。',64,'全唐诗/poet.song.91000.json','["峭蒨雲煙曉騎迷，地偏心遠愛林扉。", "人家歲晏川坻靜，場圃功成鴈鶩肥。", "雷嶺泉深方澤潤，井山丹就已空飛。", "經行不爲山林約，結臆煙霞自翠微。"]'),
('770e7678-7f74-41d1-8c68-2fcbc4976723','孝義寺','張澂','宋','宋诗','song-poetry','','[]','城東孝義寺，仍說臥冰池。',48,'全唐诗/poet.song.91000.json','["城東孝義寺，仍說臥冰池。", "雖贋猶堪訓，前賢況可師。", "香銷春殿冷，樓壓暮鐘嘶。", "末俗逾偷薄，哀懷欲涕洟。"]'),
('95f041b8-0fd6-4a90-8fca-f24c6c1b1523','清沼寺','張澂','宋','宋诗','song-poetry','','[]','野山縈小樹，翠麓訪禪家。',48,'全唐诗/poet.song.91000.json','["野山縈小樹，翠麓訪禪家。", "殿古燈無焰，霜濃菊自花。", "寒煙深橘柚，雜樹矯龍蛇。", "歸路綿岡隴，寒風舞凍鴉。"]'),
('761e7aa2-89cd-4abf-a0dd-0168707315ae','詩銘','張澂','宋','宋诗','song-poetry','','[]','桂嶺摩天灘波經地兩磅礴，盡石之變窮神之祕禹所鑿。',288,'全唐诗/poet.song.91000.json','["桂嶺摩天灘波經地兩磅礴，盡石之變窮神之祕禹所鑿。", "故其高者峭拔排空礪矛槊，而其下者宏曠洞達侔觀閣。", "瞻彼龍巖穹窿巃嵷跨寥廓，發地百尺蜿蜒躨跜勢拏攫。", "騎風乘雲去爲膏澤起焦涸，或爲至人老子孔明世程彠。", "結融肖像綵介朱鬣宛如昨，風醒雨澀森然向人恐遂躍。", "豢龍不官孔甲劉累失其學，亦復舞湫號蚓生物困陵轢。", "我昔笠澤覽觀湖海天一握，正見神物下飲濤波釃瀺灂。", "蒼鱗修尾其大環臂煙霧薄，須臾上征疾雷迅雨間飛雹。", "自喜壯觀光絕後前邈霄堮，豈知白首炎陬水石窮脈絡。", "雄姿偉態摩挲沈嘆窘揚搉，潭湫涵泹尚其來游醉牷犦。", "山空月寒風露凄然誰與樂，卻視陳跡感郗陵谷眙以愕。", "我作銘詩贅牙嚄唶嫓灝噩，琢之嵌巖日月齊光萬古託。"]'),
('99e53304-0959-468e-bc90-9900736aacc9','仰山','張澂','宋','宋诗','song-poetry','','[]','蕭寺藏幽谷，溪流燕尾分。',48,'全唐诗/poet.song.91000.json','["蕭寺藏幽谷，溪流燕尾分。", "松蘿諸洞合，鐘鼓上方聞。", "寶塔開晴日，空潭隔暮雲。", "躋攀窮勝境，猿鶴自爲羣。"]'),
('0007debe-03b1-401d-8139-10be6453ce8c','句  其一','張澂','宋','宋诗','song-poetry','','[]','鑄金像出開元末，檢玉書藏景祐間。',16,'全唐诗/poet.song.91000.json','["鑄金像出開元末，檢玉書藏景祐間。"]'),
('6f6d3502-76eb-4b2d-ab99-7decbc5f2cf0','句  其二','張澂','宋','宋诗','song-poetry','','[]','漳南周匡物，競秀元和年。',24,'全唐诗/poet.song.91000.json','["漳南周匡物，競秀元和年。", "作句詫親友，進爲鄉黨先。"]'),
('57bfae3e-7243-41b6-bfb0-0d036c75bf6b','句  其三','張澂','宋','宋诗','song-poetry','','[]','述陂蹲鴟瘦如鶴，味美渾疑齊酥酪。',16,'全唐诗/poet.song.91000.json','["述陂蹲鴟瘦如鶴，味美渾疑齊酥酪。"]'),
('4f90994d-c75f-4184-b013-7047b9316ea3','句  其四','張澂','宋','宋诗','song-poetry','','[]','汝水秋橙大如盃。',8,'全唐诗/poet.song.91000.json','["汝水秋橙大如盃。"]'),
('413a42f0-56ca-407d-bcb5-f302b3726cb8','題詞山','李健','宋','宋诗','song-poetry','','[]','午庭官事了，心與白動閑。',48,'全唐诗/poet.song.91000.json','["午庭官事了，心與白動閑。", "泉脈瀉崖谷，天風吹珮環。", "花開煙靄外，人語翠微間。", "山色看來好，相留不放還。"]'),
('b7360c88-7784-41e9-8eb1-fa9a6f2e35a9','真凈禪師舉石霜虔侍者話問之契悟偈','釋普鑑','宋','宋诗','song-poetry','','[]','枯木無華幾度秋，斷雲猶掛樹梢頭。',32,'全唐诗/poet.song.91000.json','["枯木無華幾度秋，斷雲猶掛樹梢頭。", "自從鬭折泥牛角，直至如今水倒流。"]'),
('0524cf43-de35-4848-a146-6ad620a8bd03','偈','釋普鑑','宋','宋诗','song-poetry','','[]','月圓，伏惟三世諸佛。',98,'全唐诗/poet.song.91000.json','["月圓，伏惟三世諸佛。", "貍奴白牯，各各起居萬福。", "時中淡薄，無可相延，切希寬抱。", "老水牯牛，近日亦自多病多惱，不甘水草。", "遇著暖日和風，當下和身便倒。", "教渠拽杷牽犁，直是搖頭擺腦。", "可憐萬頃良田，一時變爲荒草。"]'),
('16da88cc-d4b5-43cb-b22d-16d8709a192c','五派 臨濟','釋普鑑','宋','宋诗','song-poetry','','[]','銅頭鐵觜百家冤，一喝雙分照用全。',32,'全唐诗/poet.song.91000.json','["銅頭鐵觜百家冤，一喝雙分照用全。", "三尺吹毛定寰宇，臨行拋向瞎驢邊。"]'),
('d3b4de9c-493c-46f2-a5d7-5bc08e1be99d','五派 雲門','釋普鑑','宋','宋诗','song-poetry','','[]','三句都將一串穿，等閑掛向御樓前。',32,'全唐诗/poet.song.91000.json','["三句都將一串穿，等閑掛向御樓前。", "幾多行客眼定動，東海鯉魚飛上天。"]'),
('3d8c6473-9a3d-4f73-9ad2-a64767fb8ffc','五派 曹洞','釋普鑑','宋','宋诗','song-poetry','','[]','紫庭黄閣带春溫，寢殿何人侍至尊。',32,'全唐诗/poet.song.91000.json','["紫庭黄閣带春溫，寢殿何人侍至尊。", "長愛百司分職處，玉鞭敲鐙出金門。"]'),
('16a3ac70-75af-459d-8bb5-22f6a72a2c0e','五派 溈仰','釋普鑑','宋','宋诗','song-poetry','','[]','一個撒開千萬個，簸箕解說無生話。',32,'全唐诗/poet.song.91000.json','["一個撒開千萬個，簸箕解說無生話。", "草堂睡起觜盧都，寂子要須原夢破。"]'),
('9c5f8f01-5a24-4077-b0c5-df555c2cf570','五派 法眼','釋普鑑','宋','宋诗','song-poetry','','[]','溪光野色浸樓臺，一笛遙聞奏落梅。',32,'全唐诗/poet.song.91000.json','["溪光野色浸樓臺，一笛遙聞奏落梅。", "風送斷雲歸嶺去，月和流水過橋來。"]'),
('e317dde7-ac3f-4541-9a15-1885870bc4b2','頌古二首  其一','釋普鑑','宋','宋诗','song-poetry','','[]','拈花親付老頭陀，平地俄興一丈波。',32,'全唐诗/poet.song.91000.json','["拈花親付老頭陀，平地俄興一丈波。", "後代釘椿搖櫓者，竹篙量水轉譊訛。"]'),
('ca72a562-dc5c-497a-b8cd-0cf05b01dc15','頌古二首  其二','釋普鑑','宋','宋诗','song-poetry','','[]','你若無心我也休，鴛鴦帳裏懶擡頭。',32,'全唐诗/poet.song.91000.json','["你若無心我也休，鴛鴦帳裏懶擡頭。", "家童爲問深深意，笑指紗窗月正秋。"]'),
('c134b4ce-c76f-4e9d-9f44-37fee3d99a38','沙邊','張斛','宋','宋诗','song-poetry','','[]','晚雨漲平堤，沙邊獨杖藜。',48,'全唐诗/poet.song.91000.json','["晚雨漲平堤，沙邊獨杖藜。", "長風催雁北，衆水避潮西。", "楚客相逢少，吳天入望低。", "故園無路到，春草自萋萋。"]'),
('36927e55-9e19-4066-bc4c-4f8113f77d43','東川春日','張斛','宋','宋诗','song-poetry','','[]','巴蜀三年客，江湖萬里情。',48,'全唐诗/poet.song.91000.json','["巴蜀三年客，江湖萬里情。", "滄波何處盡，歸棹幾時行。", "世態浮雲變，春愁細草生。", "羣山遮望眼，片月上高城。"]'),
('02502d9c-ea6c-47b0-aeed-1050a8e2865b','巫山對月懷湖外親友','張斛','宋','宋诗','song-poetry','','[]','衆壑斂新雨，孤舟增暮寒。',48,'全唐诗/poet.song.91000.json','["衆壑斂新雨，孤舟增暮寒。", "巫山今夜月，湘水幾人看。", "不得臨湖醉，惟愁下峽難。", "雙魚憑寄遠，尺素勸加餐。"]'),
('9d7f88cb-67b1-41b1-a076-06a3b041e44a','武陵春雪','張斛','宋','宋诗','song-poetry','','[]','天風吹雪滿千山，不見桃花汎碧瀾。',32,'全唐诗/poet.song.91000.json','["天風吹雪滿千山，不見桃花汎碧瀾。", "洞裏仙人貪種玉，豈知人世有春寒。"]'),
('2ae6a8da-fcac-46d9-a457-3bb304eec4d7','盧臺峭帆亭','張斛','宋','宋诗','song-poetry','','[]','高秋客未還，何處望鄉關。',48,'全唐诗/poet.song.91000.json','["高秋客未還，何處望鄉關。", "喬木蒼烟外，孤亭落照間。", "雨晴山覺近，潮滿水如閑。", "目斷峒陽路，歸雲不可攀。"]'),
('46530406-f1bb-4aa4-aec0-4256d92f851b','高寺','張斛','宋','宋诗','song-poetry','','[]','高寺鳴鐘後，孤舟落雁邊。',48,'全唐诗/poet.song.91000.json','["高寺鳴鐘後，孤舟落雁邊。", "已知歸徑晚，故就上方眠。", "石峻溜聲急，月高松影圓。", "明朝下烟靄，迴首阻清川。"]'),
('b6789143-292b-43e3-b46c-4b1fd98f2a89','寓中江縣樓','張斛','宋','宋诗','song-poetry','','[]','武江斜轉石，文岫獨參天。',48,'全唐诗/poet.song.91000.json','["武江斜轉石，文岫獨參天。", "綠漲他山雨，青浮近市烟。", "松薪炊白粲，水蔓繫紅鮮。", "自喜飄蓬跡，安居過兩年。"]'),
('11637040-2aa8-4746-b548-37b5f6fa240d','迴文二首  其一','張斛','宋','宋诗','song-poetry','','[]','野曠悲行客，湍驚礙去船。',24,'全唐诗/poet.song.91000.json','["野曠悲行客，湍驚礙去船。", "夜江清汎月，秋草碧連天。"]'),
('e1b36f88-25da-4b6c-8454-4fdd3418b3a9','迴文二首  其二','張斛','宋','宋诗','song-poetry','','[]','綠逕斜縈草，紅梢半落花。',24,'全唐诗/poet.song.91000.json','["綠逕斜縈草，紅梢半落花。", "曲池風碎月，欹岸雨摧沙。"]'),
('3f868627-1518-4753-a7c3-4be780a8a2bf','仙門驛聽泉','張斛','宋','宋诗','song-poetry','','[]','一亭圍古木，雙磵瀉清流。',48,'全唐诗/poet.song.91000.json','["一亭圍古木，雙磵瀉清流。", "行到雲山暮，卧聞風雨秋。", "客塵何日浣，病渴此時瘳。", "歸去南溪上，輕舟細浪浮。"]'),
('9ac5d54a-dfaf-4d29-907c-aebb9c28b942','夜雨南山','張斛','宋','宋诗','song-poetry','','[]','雨夜宿山齋，夜深雨聲息。',24,'全唐诗/poet.song.91000.json','["雨夜宿山齋，夜深雨聲息。", "石室含餘清，風枝堕殘滴。"]'),
('ab58a5a2-05d1-40d4-b9a6-07da834eb9ef','平安關道中二首  其一','張斛','宋','宋诗','song-poetry','','[]','高林俯青冥，柯葉森若織。',72,'全唐诗/poet.song.91000.json','["高林俯青冥，柯葉森若織。", "陽光已轉午，陰嶺仍半黑。", "峥嶸亂石間，行子有苦色。", "臨深地勢入，涉險天宇塞。", "四顧無所投，迹蠒去未息。", "悵然增百憂，冥冥羨歸翼。"]'),
('4b0c104f-35b9-46bf-8f9e-f8f0790cc707','平安關道中二首  其二','張斛','宋','宋诗','song-poetry','','[]','窮冬十日陰，積雪千山路。',72,'全唐诗/poet.song.91000.json','["窮冬十日陰，積雪千山路。", "晴雲開半嶺，落日猶在樹。", "悠悠客心速，慘慘天色暮。", "寒鳥各有依，解鞍尚無處。", "游魚誤銜鈎，玄豹終隱霧。", "行行謝冠冕，復我林壑趣。"]'),
('c8bd73eb-ff4a-42e1-a310-c58527bc10c8','將渡江','張斛','宋','宋诗','song-poetry','','[]','無數飛花委路塵，不堪重醉楚城春。',32,'全唐诗/poet.song.91000.json','["無數飛花委路塵，不堪重醉楚城春。", "明朝回首江南岸，烟雨昏昏不見人。"]'),
('488d25d0-55db-44fe-a615-82aefc4b7313','還家','張斛','宋','宋诗','song-poetry','','[]','雲林無俗姿，相對可終老。',24,'全唐诗/poet.song.91000.json','["雲林無俗姿，相對可終老。", "如何塵中人，不見青山好。"]'),
('7d348488-d862-4f70-928d-0c3a939337bf','訪香林老','張斛','宋','宋诗','song-poetry','','[]','風雨無時浪蹴天，南浮舟楫信多艱。',64,'全唐诗/poet.song.91000.json','["風雨無時浪蹴天，南浮舟楫信多艱。", "半生夢破寒江月，萬里春回故國山。", "歸客自傷青鬢改，高僧長共白雲閑。", "誅茅借我溪西地，未厭相從水石間。"]'),
('1028e83a-3f78-4b34-a2ec-97e558c7e956','海邊亭爲浩然賦','張斛','宋','宋诗','song-poetry','','[]','夙有滄洲趣，雲扃夢幾回。',48,'全唐诗/poet.song.91000.json','["夙有滄洲趣，雲扃夢幾回。", "臨深疑地盡，望遠覺天開。", "月湧冰輪出，濤飜雪陣來。", "無機同海客，鷗鳥莫相猜。"]'),
('bfe9bbc5-9c46-4240-a1b7-37c6d7a745a8','南京遇馬丈朝美','張斛','宋','宋诗','song-poetry','','[]','浮雲久與故山違，茅棟如存尚可依。',64,'全唐诗/poet.song.91000.json','["浮雲久與故山違，茅棟如存尚可依。", "行路相逢初似夢，舊游重到復疑非。", "滄江萬里悲南渡，白髪幾人能北歸。", "二十年前河上月，尊前還共惜清輝。"]'),
('656cca57-f5fb-4082-93e1-2035143efab6','小孤山','張斛','宋','宋诗','song-poetry','','[]','天圍秋漲闊，山背夕陽孤。',24,'全唐诗/poet.song.91000.json','["天圍秋漲闊，山背夕陽孤。", "岸樹晴猶濕，汀煙近卻無。"]'),
('fa86bcab-7739-4200-bc7b-7957db962849','句  其一','張斛','宋','宋诗','song-poetry','','[]','雲開千里月，風動一天星。',12,'全唐诗/poet.song.91000.json','["雲開千里月，風動一天星。"]'),
('4d3c46f1-3b7d-4f89-8119-816a35146a0e','句  其二','張斛','宋','宋诗','song-poetry','','[]','細草沙邊樹，疏煙嶺外村。',12,'全唐诗/poet.song.91000.json','["細草沙邊樹，疏煙嶺外村。"]'),
('060d1069-9332-4e9c-89e3-17681011f177','句  其三','張斛','宋','宋诗','song-poetry','','[]','綠漲他山雨，青浮近市煙。',12,'全唐诗/poet.song.91000.json','["綠漲他山雨，青浮近市煙。"]'),
('1a861a90-eaa4-48e3-bd26-3b203e20e766','句  其四','張斛','宋','宋诗','song-poetry','','[]','月色四時好，人心此夜偏。',12,'全唐诗/poet.song.91000.json','["月色四時好，人心此夜偏。"]'),
('9c6ff3f8-36f4-4d57-a20a-4a82b4544d2f','句  其五','張斛','宋','宋诗','song-poetry','','[]','春水有秀色，野雲無俗姿。',12,'全唐诗/poet.song.91000.json','["春水有秀色，野雲無俗姿。"]'),
('2659008d-f6c0-4d8f-bfa2-165940dfa611','句  其六','張斛','宋','宋诗','song-poetry','','[]','晴光搖碧海，遠色带滄洲。',12,'全唐诗/poet.song.91000.json','["晴光搖碧海，遠色带滄洲。"]'),
('46b841c1-c44c-4e40-bc29-9238d49265af','句  其七','張斛','宋','宋诗','song-poetry','','[]','雨聲喧莫島，水色借秋空。',12,'全唐诗/poet.song.91000.json','["雨聲喧莫島，水色借秋空。"]'),
('844cd85f-495a-4035-9560-294ca7b47eaf','句  其八','張斛','宋','宋诗','song-poetry','','[]','碣石晚風催雁急，昭祁寒漲與雲平。',16,'全唐诗/poet.song.91000.json','["碣石晚風催雁急，昭祁寒漲與雲平。"]'),
('e688f277-3746-4441-91c0-6e5cc02121ec','和吳顧道暑雪軒','王澧','宋','宋诗','song-poetry','','[]','望處疑蓬島，天長碧海閑。',48,'全唐诗/poet.song.91000.json','["望處疑蓬島，天長碧海閑。", "雲霞收玉宇，煙浪湧銀山。", "茶人清談裏，風生兩腋間。", "詩成似西嶺，高嶮不容攀。"]'),
('ab83390a-f1ee-4c92-b294-6081d9f26fdc','和田望再賦暑雪軒','王澧','宋','宋诗','song-poetry','','[]','層軒高棟與雲侵，照眼嵯峨雪滿岑。',64,'全唐诗/poet.song.91000.json','["層軒高棟與雲侵，照眼嵯峨雪滿岑。", "寒人欄干欺畏日，煙橫圖畫失遙杯。", "雍容樽俎開金地，模寫風光要玉音。", "萬里岷峨今更重，太平藩翰作喉襟。"]'),
('0766a1e3-3ba6-46bd-b461-298143bb8826','和周通老合江亭','王澧','宋','宋诗','song-poetry','','[]','膚使中心若飲冰，合江宴集更思清。',64,'全唐诗/poet.song.91000.json','["膚使中心若飲冰，合江宴集更思清。", "涼風輕拂來幽戶，暑雨乍收新霽晴。", "蕭灑虛亭迎野色，玲瓏遠水漱溪聲。", "公餘自得高吟賞，還轡雍容带月行。"]'),
('2d9171dc-bf5e-4e39-b7c6-44e6d97c7b99','碧沼寺','王析','宋','宋诗','song-poetry','','[]','精藍結處足清虛，泉遶庭階樹遶廬。',64,'全唐诗/poet.song.91000.json','["精藍結處足清虛，泉遶庭階樹遶廬。", "鬰密青巒垂薜荔，渟澄碧沼映芙蕖。", "客來差喜風塵隔，僧住應知世網疏。", "爲感湯休暮雲句，使人煩慮頓然除。"]'),
('29676dd8-a9e7-4429-ad94-5361a187f7ad','碧沼寺','劉庠','宋','宋诗','song-poetry','','[]','萬疊羣山裏，招提獨屹然。',144,'全唐诗/poet.song.91000.json','["萬疊羣山裏，招提獨屹然。", "遠依花嶺構，高與上方連。", "鐘磬雲霄外，簷楹杳靄邊。", "佛宮皆古像，詩版盡唐賢。", "乘興公餘日，間來首夏天。", "池清初過雨，沼碧乍生蓮。", "薜荔垂青幄，芭蕉展翠牋。", "谿聲寒漱玉，嵐氣冷堆煙。", "信步宜松徑，烹茶喜石泉。", "虛堂不知暑，凈境合通仙。", "自得幽棲趣，翻嗟俗事牽。", "紅塵懶回首，落日尚遷延。"]'),
('31a7d2c7-71b3-4d35-b771-87b1e5a2bdd5','留題三洲洞','蕭淵言','宋','宋诗','song-poetry','','[]','山勢凌空下鬰迂，前森秀島應台符。',64,'全唐诗/poet.song.91000.json','["山勢凌空下鬰迂，前森秀島應台符。", "洞中古老傳仙迹，望外風光接海隅。", "屹若臣心彊諫剖，嵌如龜腹效靈刳。", "清幽景致仁人樂，誰爲名標勝地圖。"]'),
('bd321cb4-1c84-47c0-8ae4-731fe2cb6545','邑宰同遊峴峰','張志行','宋','宋诗','song-poetry','','[]','勝境追遊豈易尋，公餘喜得共登臨。',64,'全唐诗/poet.song.91000.json','["勝境追遊豈易尋，公餘喜得共登臨。", "攀蘿縹緲雲霄興，夾道琮琤玉石音。", "置酒但教呼我輩，題名何必刻碑陰。", "籃輿歸去敲明月，盛集應堪繼竹林。"]'),
('74148cfc-52e8-4fa6-863a-eace3e7f0798','涵碧亭','張志行','宋','宋诗','song-poetry','','[]','夢遊還解洗塵勞，一日堪來一百遭。',64,'全唐诗/poet.song.91000.json','["夢遊還解洗塵勞，一日堪來一百遭。", "有眼石泉聲更細，無心亭竹節猶高。", "洞中意寂含千古，世上名輕等一毫。", "此藥要知天付與，未宜輕話與兒曹。"]'),
('316c3106-e475-4e03-a68c-eb5e36d72196','送喻迪孺郎中知遂寧府','張廣','宋','宋诗','song-poetry','','[]','平時場屋漫聲名，晚下瞿唐信此生。',64,'全唐诗/poet.song.91000.json','["平時場屋漫聲名，晚下瞿唐信此生。", "萬里不應頻去國，一麾聊復爲專城。", "送春杯酒侵行色，上峽家山慰客情。", "坐遣官曹頓牢落，說詩誰復似康衡。"]'),
('a656c9a7-da44-48d7-bd05-de7b315a4b74','句','陳括','宋','宋诗','song-poetry','','[]','古來唯有杜陵翁。',8,'全唐诗/poet.song.91000.json','["古來唯有杜陵翁。"]'),
('e5a4f2f1-ba29-4a6c-95a6-67e0243291fb','武陵溪','楊川','宋','宋诗','song-poetry','','[]','武溪控扼五溪傜，路入京城萬國朝。',48,'全唐诗/poet.song.91000.json','["武溪控扼五溪傜，路入京城萬國朝。", "石櫃雄排沅水勢，浮國高聳接雲霄。", "丹砂井湧三泉脈，玉带河橫六畫橋。"]'),
('9aa1732a-726d-4f22-9fa0-cba86cde2cfa','題豐溪清風堂','呂鏜','宋','宋诗','song-poetry','','[]','瘦竹長松萬仞山，白雲深處小禪關。',32,'全唐诗/poet.song.91000.json','["瘦竹長松萬仞山，白雲深處小禪關。", "忘機人到忘機處，一縷春風盡日閑。"]'),
('7061f96e-3a96-4882-a39a-adb2ba65cc84','歌','呂鏜','宋','宋诗','song-poetry','','[]','數千里兮客王畿，忘甘旨兮親庭幃。',32,'全唐诗/poet.song.91000.json','["數千里兮客王畿，忘甘旨兮親庭幃。", "歲云莫兮音書稀，魂欲斷兮白雲飛。"]'),
('497554f6-b9c6-45c3-99c1-2aa8012da6c3','過東坡墓','朱廣漢','宋','宋诗','song-poetry','','[]','文星落處天地泣，此老已亡吾道窮。',64,'全唐诗/poet.song.91000.json','["文星落處天地泣，此老已亡吾道窮。", "才力謾趨生仲達，功名猶忌死姚崇。", "人間便覺無清氣，海外何人識古風。", "平日萬篇誰愛惜，六丁收拾在瑤宮。"]'),
('fb735167-dcad-46c4-978f-52ff141d4027','自咏','朱廣漢','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','百萬人中隱一身，深如勺水在滄溟。',64,'全唐诗/poet.song.91000.json','["百萬人中隱一身，深如勺水在滄溟。", "獨醒自負賢人酒，天闊難尋處士星。", "照影自憐湖水碧，高吟贏得蜀山青。", "城南老樹如相問，不枉翻空過洞庭。"]'),
('942ce668-c71d-4bdd-baa9-cdaa40f86d6b','遊龍華寺','徐若渾','宋','宋诗','song-poetry','','[]','杖履曾爲勝地遊，朅來驚嘆歲華週。',64,'全唐诗/poet.song.91000.json','["杖履曾爲勝地遊，朅來驚嘆歲華週。", "上方重閣人如舊，修竹茂林山自秋。", "尚想縱談方外去，空餘妙墨壁間留。", "回頭彭蠡湖邊路，準擬東歸一釣舟。"]'),
('a1b477c3-0df8-40d2-8471-30a9ab785db8','和遊章法寺','徐若渾','宋','宋诗','song-poetry','','[]','嘉君步屐招提寺，應與白雲相對閑。',64,'全唐诗/poet.song.91000.json','["嘉君步屐招提寺，應與白雲相對閑。", "盡見地輿藏勝境，始知天柱是名山。", "疏疏葉脫長林表，瀝瀝泉鳴亂石間。", "又入郡城聲利窟，定嫌輕自寶坊還。"]'),
('a9fe2db9-956f-4f83-a7e0-81f76152462a','經綸堂','徐若渾','宋','宋诗','song-poetry','','[]','我公大志在經綸，初向山房寄此身。',64,'全唐诗/poet.song.91000.json','["我公大志在經綸，初向山房寄此身。", "到老自全千丈節，調元曾轉萬家春。", "青編勳業光終爛，翠琰文章久更新。", "今古斯人常想慕，不應上墊雨中巾。"]'),
('ecd4e735-179b-4ea6-8c28-67929752df54','藍田喻言詩二首  其一','徐若渾','宋','宋诗','song-poetry','','[]','南有樹居叟，翛然一徑開。',48,'全唐诗/poet.song.91000.json','["南有樹居叟，翛然一徑開。", "經年野戶外，不見俗人來。", "冰炭知難合，溪山覺易陪。", "竹間逢片石，一坐便忘回。"]'),
('66e0f9fe-6579-4958-b91b-460cd1b76b3b','藍田喻言詩二首  其二','徐若渾','宋','宋诗','song-poetry','','[]','處世覺還早，終無陸地波。',48,'全唐诗/poet.song.91000.json','["處世覺還早，終無陸地波。", "事從安分少，憂爲過求多。", "慮廣神偏昧，心平氣自和。", "萬般惟好勝，勝得又如何。"]'),
('f333f2d3-f414-493c-b9eb-44e464962d61','睿謀殿賜宴和御製','李資諒','宋','宋诗','song-poetry','','[]','鹿鳴嘉會宴賢良，仙樂洋洋出洞房。',64,'全唐诗/poet.song.91000.json','["鹿鳴嘉會宴賢良，仙樂洋洋出洞房。", "天上賜花頭上艷，盤中宣橘袖中香。", "黄河再報千年瑞，綠醑輕浮萬壽觴。", "今日陪臣參盛際，願歌天保永無忘。"]'),
('1f780ac4-42d0-4409-b8ae-a4eb31fd7948','祈澤寺','梵仙','宋','宋诗','song-poetry','','[]','萬里區區學宦游，江南江北幾時休。',32,'全唐诗/poet.song.91000.json','["萬里區區學宦游，江南江北幾時休。", "朝來作別殷勤語，爲謝多情黄栗留。"]'),
('0070b6af-6354-4c35-9098-864efb8b26ed','蒼龍巖潭','董天慶','宋','宋诗','song-poetry','','[]','潭深凈如練，宛然魚自見。',24,'全唐诗/poet.song.91000.json','["潭深凈如練，宛然魚自見。", "獨憐簑笠翁，錯下銀鈎線。"]'),
('977f5586-9ee3-451a-b7bb-e0ebe3e9738c','題大隱堂','侯綬','宋','宋诗','song-poetry','','[]','千峰美景真堪戀，一點靈源我自閑。',32,'全唐诗/poet.song.91000.json','["千峰美景真堪戀，一點靈源我自閑。", "居士不緣能解此，豈知深隱在松間。"]'),
('2f33ebc2-b22c-449b-8034-466f4c9db192','僕公山思杏丹仙','郝以中','宋','宋诗','song-poetry','','[]','風雷龍虎驚州牧，一去朝天更不還。',64,'全唐诗/poet.song.91000.json','["風雷龍虎驚州牧，一去朝天更不還。", "巖拆杏花空爛熳，泉盈丹井尚潺湲。", "嶺頭猿起凄涼嘆，洞口雲歸寂寞閑。", "登覽幾回餘悵望，只聞人道僕公山。"]'),
('e114e1a0-845d-443c-8996-2f6b78438eea','續徽宗詩','徽宗朝太學生','宋','宋诗','song-poetry','','[]','選飯朝來不喜餐，御廚空費八珍盤。',32,'全唐诗/poet.song.91000.json','["選飯朝來不喜餐，御廚空費八珍盤。", "人間有味俱嘗徧，只許江梅一點酸。"]'),
('a8e3d61b-ab90-4e9e-8a29-3621b36d9eb3','立春前一日','朱淑真','宋','宋诗','song-poetry','','[]','梅花枝上雪初融，一夜高風激轉東。',32,'全唐诗/poet.song.91000.json','["梅花枝上雪初融，一夜高風激轉東。", "芳草池塘冰未薄，柳條如線著春工。"]'),
('0fa81283-52d6-4fbb-8213-306b9e285400','立春古律','朱淑真','宋','宋诗','song-poetry','','[]','停杯不飲待春來，和氣先春動六街。',64,'全唐诗/poet.song.91000.json','["停杯不飲待春來，和氣先春動六街。", "生菜乍挑宜卷餅，羅幡旋剪稱聯釵。", "休論殘臘千重恨，管入新年百事諧。", "從此對花幷對景，盡拘風月入詩懷。"]');
